-- Poems batch 371
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e39b93db-15d0-4f29-8ab7-12d9ea5247b1','次韻韓宰上元二絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','傷時此夜憶神京，月照鼇山輦道平。',32,'全唐诗/poet.song.85000.json','["傷時此夜憶神京，月照鼇山輦道平。", "朱雀街門舊行路，星毬飛上鳳凰城。"]'),
('3fdc7b83-7a2d-433a-8860-4d42a03890cc','和劉英臣見寄二絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','諸葛奇才當十倍，謫仙詞句滿三千。',32,'全唐诗/poet.song.85000.json','["諸葛奇才當十倍，謫仙詞句滿三千。", "我惟閉閣捫書册，掃地燒香亦靜便。"]'),
('43fbd0e5-17fc-45d2-9f1a-7d389f394f30','和劉英臣見寄二絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','胸吞雲夢欲八九，日誦古書常數千。',32,'全唐诗/poet.song.85000.json','["胸吞雲夢欲八九，日誦古書常數千。", "撐拄枯腸只堪睡，從君嘲我腹便便。"]'),
('a1e72dc2-09e6-4a82-9894-e3f679a8d5dc','幽蘭寄向文剛二絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','西風黄葉深林下，忽有新蘭動地香。',32,'全唐诗/poet.song.85000.json','["西風黄葉深林下，忽有新蘭動地香。", "公子夜寒誰對語，應容幽客到書房。"]'),
('36b917bb-de9a-417b-bf2f-bb8178621292','幽蘭寄向文剛二絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','連夜風吹碧玉枝，山深寒重得香遲。',32,'全唐诗/poet.song.85000.json','["連夜風吹碧玉枝，山深寒重得香遲。", "窮秋故出邁往韻，要就高人覓好詩。"]'),
('509e1a4f-1374-4014-806c-4c48e368d9cb','次韻黄超然','王庭珪','宋','宋诗','song-poetry','','[]','楚詞賦物取香草，衆草猶須避國香。',32,'全唐诗/poet.song.85000.json','["楚詞賦物取香草，衆草猶須避國香。", "一辱雕章重題品，何慚清廟薦芝房。"]'),
('796b6047-ea69-496a-ad56-d5ee6b932b73','雪中遇胡烈臣歸自郴陽戲成一絕','王庭珪','宋','宋诗','song-poetry','','[]','路傍有客騎牛過，乞與蓑衣作蓆眠。',32,'全唐诗/poet.song.85000.json','["路傍有客騎牛過，乞與蓑衣作蓆眠。", "邂逅若能相顧問，和公畫上釣魚船。"]'),
('9fd1bcd1-474d-4112-aeeb-ffcb2382f27c','衡嶽銓德觀作  其一','王庭珪','宋','宋诗','song-poetry','','[]','峰頭烏帽翠雲裘，三百年來無此流。',32,'全唐诗/poet.song.85000.json','["峰頭烏帽翠雲裘，三百年來無此流。", "餘論更容平子否，猶勝湛輩峴山遊。"]'),
('c77322c6-077a-464a-bbdb-31d8da3f31b7','衡嶽銓德觀作  其二','王庭珪','宋','宋诗','song-poetry','','[]','碧玉峰前雲滿徑，赤欄橋畔柳參天。',32,'全唐诗/poet.song.85000.json','["碧玉峰前雲滿徑，赤欄橋畔柳參天。", "長廊静夜松風起，寫得餘聲入響泉。"]'),
('6701c395-f33e-4865-8115-548fdbaa9e50','清江張氏活人堂二絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','遠系長沙太守孫，家傳太守活人言。',32,'全唐诗/poet.song.85000.json','["遠系長沙太守孫，家傳太守活人言。", "刀圭一粒起人死，安得聲名不出門。"]'),
('498a3713-4d44-4bf3-a27f-e9ccba229d7f','清江張氏活人堂二絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','海底龍宮失護防，老龍偷得返魂方。',32,'全唐诗/poet.song.85000.json','["海底龍宮失護防，老龍偷得返魂方。", "聞君夜壓春槽響，攜扣柴門乞酒漿。"]'),
('ff4da68a-e5ff-4905-81c5-596585226206','次韻謝昌國','王庭珪','宋','宋诗','song-poetry','','[]','今人不識古人心，誰識羲皇太古音。',32,'全唐诗/poet.song.85000.json','["今人不識古人心，誰識羲皇太古音。", "如望銀河九天上，聊分一勺濯塵襟。"]'),
('dfffc81f-e357-4d61-bc25-60ec45f02420','雙田逢蕭國器話别','王庭珪','宋','宋诗','song-poetry','','[]','黄葉西風何處村，茅簷立馬問寒温。',32,'全唐诗/poet.song.85000.json','["黄葉西風何處村，茅簷立馬問寒温。", "江東渭北情無限，罇酒他時得細論。"]'),
('843a1923-b36a-4b9e-bdcd-bfe9882150d0','和康晉侯見贈','王庭珪','宋','宋诗','song-poetry','','[]','儒生無力荷干戈，亂後篇章感慨多。',32,'全唐诗/poet.song.85000.json','["儒生無力荷干戈，亂後篇章感慨多。", "但拏筆頭吟白雪，莫挑馬箠渡黄河。"]'),
('fb863a52-4566-47bb-8b61-2a60f16d3ed2','雪中以酒送歐陽廣明袁叔明','王庭珪','宋','宋诗','song-poetry','','[]','小槽新壓甕頭春，盛欲招呼雪閉門。',32,'全唐诗/poet.song.85000.json','["小槽新壓甕頭春，盛欲招呼雪閉門。", "卧對袁郎說周易，不妨伸頸飲清罇。"]'),
('8287168c-373a-49d9-b5ec-bf6700066fa0','鄱陽周師禹求清軒霧齋詩二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','月入柴門夜色新，坐堅談壘足佳賓。',32,'全唐诗/poet.song.85000.json','["月入柴門夜色新，坐堅談壘足佳賓。", "誰云老子興不淺，政恐元規塵污人。"]'),
('30ac09ce-409b-4db0-8be2-b387a055bebf','鄱陽周師禹求清軒霧齋詩二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','細雨如烟下九垓，始聞巖谷隱奇才。',32,'全唐诗/poet.song.85000.json','["細雨如烟下九垓，始聞巖谷隱奇才。", "一朝文彩驚人眼，知自南山霧裏來。"]'),
('8cd4b395-b837-4793-84ba-bd2c0dbc92c1','送彭士貴  其一','王庭珪','宋','宋诗','song-poetry','','[]','詔謂將軍急擊戎，連營已列漢旗紅。',32,'全唐诗/poet.song.85000.json','["詔謂將軍急擊戎，連營已列漢旗紅。", "須君磨盾作露布，破陣誰先第一功。"]'),
('138dbd56-4b82-4cb4-939b-7c3a2c9d4d40','送彭士貴  其二','王庭珪','宋','宋诗','song-poetry','','[]','大將威名震九州，毛錐何補劍鎗頭。',32,'全唐诗/poet.song.85000.json','["大將威名震九州，毛錐何補劍鎗頭。", "但歌出塞從軍樂，莫笑居鄉馬少遊。"]'),
('6973df52-c8ee-4438-bd9b-e6becb5d5add','劉天錫之子八歳能作大字今年十三矣筆畫愈進有雄徤之氣作二絕句贈之  其一','王庭珪','宋','宋诗','song-poetry','','[]','羣兒墨汁翻老鴉，爾獨落紙生龍蛇。',32,'全唐诗/poet.song.85000.json','["羣兒墨汁翻老鴉，爾獨落紙生龍蛇。", "郎罷不須頻掣筆，渠今自會畫江沙。"]'),
('e41abc02-e4d8-4478-a5ba-af00c9c509f9','劉天錫之子八歳能作大字今年十三矣筆畫愈進有雄徤之氣作二絕句贈之  其二','王庭珪','宋','宋诗','song-poetry','','[]','作戈如挽百鈞弩，腕力想能回萬牛。',32,'全唐诗/poet.song.85000.json','["作戈如挽百鈞弩，腕力想能回萬牛。", "江夏當年有童子，未聞落筆寫銀鈎。"]'),
('835ded7e-5311-4f00-9456-4c865f84bf75','郊外留别友人','王庭珪','宋','宋诗','song-poetry','','[]','不及匆匆把一巵，丹楓黄葉助題詩。',32,'全唐诗/poet.song.85000.json','["不及匆匆把一巵，丹楓黄葉助題詩。", "天教遠謫非無意，更上沅湘看九疑。"]'),
('c73fef0f-b1e0-43c7-a84f-4fe39baa05a0','寄劉世臣仲美','王庭珪','宋','宋诗','song-poetry','','[]','此道陵遲久已亡，後生無復立門牆。',32,'全唐诗/poet.song.85000.json','["此道陵遲久已亡，後生無復立門牆。", "遙知二子心如鐵，端爲盧溪一瓣香。"]'),
('6c5de96a-41d8-4e6e-a270-c46a1a58266a','贈無識道人','王庭珪','宋','宋诗','song-poetry','','[]','古廟香爐冷似冰，向來土木弄精靈。',32,'全唐诗/poet.song.85000.json','["古廟香爐冷似冰，向來土木弄精靈。", "如今萬事都不會，却笑金剛努眼睛。"]'),
('5f576c04-090d-4156-a1e2-e62ab6dd973f','謝張東言','王庭珪','宋','宋诗','song-poetry','','[]','忽見蛟蛇遶壁蟠，歸時星斗已闌干。',32,'全唐诗/poet.song.85000.json','["忽見蛟蛇遶壁蟠，歸時星斗已闌干。", "山童不識回鸞字，誤認題門作鳳看。"]'),
('433f80f6-6370-4fef-912f-1b13da1f2e88','惜春亭觀酴醿','王庭珪','宋','宋诗','song-poetry','','[]','東皇收拾春歸去，獨遣酴醿殿後塵。',32,'全唐诗/poet.song.85000.json','["東皇收拾春歸去，獨遣酴醿殿後塵。", "憐我寒窗賦愁寂，時看玉面送殘春。"]'),
('3162c7d0-5eb6-43a1-a272-acbee12243cc','彭青老好談禪喜作詩西寧詩有謀身之語借其語激之三首  其一','王庭珪','宋','宋诗','song-poetry','','[]','未省前身是道人，莫嗟求仕困無津。',32,'全唐诗/poet.song.85000.json','["未省前身是道人，莫嗟求仕困無津。", "東風動地泥牛吼，簷蔔花開别是春。"]'),
('bec2d1e9-c8a6-445b-a168-847ca7a4b532','彭青老好談禪喜作詩西寧詩有謀身之語借其語激之三首  其二','王庭珪','宋','宋诗','song-poetry','','[]','未能投筆取封侯，一食聊須爲口謀。',32,'全唐诗/poet.song.85000.json','["未能投筆取封侯，一食聊須爲口謀。", "日向晴窗研破硯，讀書當讀億那由。"]'),
('1a8468a4-04b7-4677-a73f-58d5c28de29a','彭青老好談禪喜作詩西寧詩有謀身之語借其語激之三首  其三','王庭珪','宋','宋诗','song-poetry','','[]','好詩渾厚如金玉，妙質勿令斤斧侵。',32,'全唐诗/poet.song.85000.json','["好詩渾厚如金玉，妙質勿令斤斧侵。", "要識筆端三昧力，夜深山水自成音。"]'),
('4109b7bd-5efc-4c08-adc2-a55b840b863c','漁父詞','王庭珪','宋','宋诗','song-poetry','','[]','冥冥江雨濕蓑衣，夜上高巖宿翠微。',32,'全唐诗/poet.song.85000.json','["冥冥江雨濕蓑衣，夜上高巖宿翠微。", "夢斷一聲烟草綠，遙聞款乃扣舷歸。"]'),
('253321fd-f75a-4002-bde2-397e76686355','曦上人頃脫塵網可謂俊哉衲僧也絕句贈之','王庭珪','宋','宋诗','song-poetry','','[]','震林獅子非凡獸，脫網鯉魚真衲僧。',32,'全唐诗/poet.song.85000.json','["震林獅子非凡獸，脫網鯉魚真衲僧。", "宿垢消磨應已盡，竿頭海底任横行。"]'),
('aecc0043-6105-4776-85be-e52e88e898fa','遊沅陵劉道人菴中唯一禪椅不置卧榻云不睡四十年矣戲作二絕  其一','王庭珪','宋','宋诗','song-poetry','','[]','一菴茅屋白雲深，坐待丹砂欲變金。',32,'全唐诗/poet.song.85000.json','["一菴茅屋白雲深，坐待丹砂欲變金。", "誰信菴中人不睡，滿池春水聽龍吟。"]'),
('e65e0d8e-a916-470e-9d8e-cbff872bd00b','遊沅陵劉道人菴中唯一禪椅不置卧榻云不睡四十年矣戲作二絕  其二','王庭珪','宋','宋诗','song-poetry','','[]','九曲江邊雲欲凈，三更海上月華孤。',32,'全唐诗/poet.song.85000.json','["九曲江邊雲欲凈，三更海上月華孤。", "金刀直入滄溟底，奪得驪龍頷下珠。"]'),
('6dc32361-6cd3-49ce-8148-b6eb70da67b7','次韻陳君授暮春感懷','王庭珪','宋','宋诗','song-poetry','','[]','雨餘山鳥百般啼，烟隔桃蹊一線微。',32,'全唐诗/poet.song.85000.json','["雨餘山鳥百般啼，烟隔桃蹊一線微。", "南北東西春總好，杜鵑何苦勸人歸。"]'),
('05d253f3-77c8-48e5-a014-35b79f91211e','辰州馬觀察送酒二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','壺頭直下開邊郡，勳業誰如馬伏波。',32,'全唐诗/poet.song.85000.json','["壺頭直下開邊郡，勳業誰如馬伏波。", "還見遠孫持漢節，坐令千騎擁雕戈。"]'),
('eeca87de-4b66-4738-91bf-d8159c27c7fa','辰州馬觀察送酒二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','倒盡鄰翁老瓦缸，使君忽送玉爲漿。',32,'全唐诗/poet.song.85000.json','["倒盡鄰翁老瓦缸，使君忽送玉爲漿。", "昌黎對月無詩酒，絕句聊酬馬侍郎。"]'),
('694794f3-eb9b-4f5e-8699-08374d4ae12e','董仲儀來夜郎訪死生二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','雪霾鬼葬山頭路，霧失鬼門關外村。',32,'全唐诗/poet.song.85000.json','["雪霾鬼葬山頭路，霧失鬼門關外村。", "不謂故人千萬里，忽攜書册夜敲門。"]'),
('08b2da4c-3856-4939-910a-d41206a49195','董仲儀來夜郎訪死生二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','我識君家董狀元，草萊崛起跳天門。',32,'全唐诗/poet.song.85000.json','["我識君家董狀元，草萊崛起跳天門。", "揮毫玉陛摩星斗，持槖明光奉至尊。"]'),
('7e4bb680-672c-4a46-b9a0-fd5a2fb40598','次韻酬國子生趙秀才四絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','淵明五柳非無宅，子美西枝自有村。',32,'全唐诗/poet.song.85000.json','["淵明五柳非無宅，子美西枝自有村。", "堪笑長安近時客，紛紛騎馬傍誰門。"]'),
('66f71a11-d823-45e5-98e5-60a255f469b1','次韻酬國子生趙秀才四絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','入關莫戀銅駝陌，待詔行趨金馬門。',32,'全唐诗/poet.song.85000.json','["入關莫戀銅駝陌，待詔行趨金馬門。", "場屋若歸丞相府，可無公道得推尊。"]'),
('4d3f9b20-c250-4801-b68d-c3118305022a','次韻酬國子生趙秀才四絕句  其三','王庭珪','宋','宋诗','song-poetry','','[]','羡君將入銀蟾窟，容我歸耕谷口村。',32,'全唐诗/poet.song.85000.json','["羡君將入銀蟾窟，容我歸耕谷口村。", "遙想明年春殿下，臚傳先出九重門。"]'),
