('d0e61f7d-b378-457a-99b0-95dab090e66a','贈清首座','王庭珪','宋','宋诗','song-poetry','','[]','上堂何事更論量，還我珠來本自光。',32,'全唐诗/poet.song.85000.json','["上堂何事更論量，還我珠來本自光。", "未識飛猿嶺頭峻，兩回掀倒夾山牀。"]'),
('aa03f3fe-4a79-476d-9914-23b4fe49e795','和裴主簿桃花','王庭珪','宋','宋诗','song-poetry','','[]','近水淺桃不忍看，似臨清鏡惜紅顔。',32,'全唐诗/poet.song.85000.json','["近水淺桃不忍看，似臨清鏡惜紅顔。", "騎驢主簿吟詩瘦，應秃千毫筆管斑。"]'),
('35e91606-8e3e-46c3-b3eb-05562a5ced74','秋蘭寄知縣陳邦直','王庭珪','宋','宋诗','song-poetry','','[]','昨夜西風茁紫芽，不應獨著野人家。',32,'全唐诗/poet.song.85000.json','["昨夜西風茁紫芽，不應獨著野人家。", "安仁未倦栽桃李，添此清香一種花。"]'),
('981870c3-dda3-48a6-b684-08de11e24d04','和答邦直二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','惠愛如蘭正吐芽，芳風吹落幾千家。',32,'全唐诗/poet.song.85000.json','["惠愛如蘭正吐芽，芳風吹落幾千家。", "明年催直金鑾殿，龍口飄香看百花。"]'),
('afdd7f37-16d8-4345-bb89-f6574a2bcf09','和答邦直二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','系出拾遺揚馬後，清詞麗句復名家。',32,'全唐诗/poet.song.85000.json','["系出拾遺揚馬後，清詞麗句復名家。", "豈惟草木遭題品，大筆行當判五花。"]'),
('9861dbf6-cd92-486f-a7d2-b096810e14ba','美胡烈臣晚年生子','王庭珪','宋','宋诗','song-poetry','','[]','老蚌生珠喜可涯，窮閻得寶亦堪誇。',32,'全唐诗/poet.song.85000.json','["老蚌生珠喜可涯，窮閻得寶亦堪誇。", "如今七歳誦千字，他日端能讀五車。"]'),
('b2df802e-2960-4155-bb82-3e91bb8896d3','和彭養正陳令尹','王庭珪','宋','宋诗','song-poetry','','[]','氣壓秋園百草芽，風流宜在令君家。',32,'全唐诗/poet.song.85000.json','["氣壓秋園百草芽，風流宜在令君家。", "但傾綠蟻伴清客，莫羡黄金刻蘚花。"]'),
('d62e675e-b8fe-4b0e-8575-0536bc5615fd','和劉元弼見招','王庭珪','宋','宋诗','song-poetry','','[]','玉壺沽酒挈青絲，及取春風花發時。',32,'全唐诗/poet.song.85000.json','["玉壺沽酒挈青絲，及取春風花發時。", "便把一罇留客醉，莫教紅雨洗殘枝。"]'),
('07bfce76-d70c-4cdb-bf43-7c999489e9e1','贈相士','王庭珪','宋','宋诗','song-poetry','','[]','富貴本非吾輩事，老來寧復問窮通。',32,'全唐诗/poet.song.85000.json','["富貴本非吾輩事，老來寧復問窮通。", "餘齡幾許君知否，願作昇平一老翁。"]'),
('6e11045b-c46c-4654-b00e-09689efad908','問訊王道之病','王庭珪','宋','宋诗','song-poetry','','[]','居士病從何處起，我今往問與誰俱。',32,'全唐诗/poet.song.85000.json','["居士病從何處起，我今往問與誰俱。", "室中三萬二千座，更許盧溪下語無。"]'),
('cff93d2c-d882-4566-b52b-4939ba1dd9d2','贈宜春筆工','王庭珪','宋','宋诗','song-poetry','','[]','宜城一變宣城様，入手便如錐畫沙。',32,'全唐诗/poet.song.85000.json','["宜城一變宣城様，入手便如錐畫沙。", "但喜中書頭未秃，不妨詩老夢生花。"]'),
('8c8091ee-3d8c-419d-b4dd-8a1cd1413412','步芳園','王庭珪','宋','宋诗','song-poetry','','[]','密栽桃李礙車輪，柳下風微不動塵。',32,'全唐诗/poet.song.85000.json','["密栽桃李礙車輪，柳下風微不動塵。", "已辦尋春蠟雙屐，飛花滿地草如茵。"]'),
('d70072ae-b2bb-4554-bfa7-12ea55a0f7b4','湖頭觀桃李四絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','路轉烟村萬木春，村深疑有避秦人。',32,'全唐诗/poet.song.85000.json','["路轉烟村萬木春，村深疑有避秦人。", "山農出谷驚相問，不信邊頭有戰塵。"]'),
('b2fcbc6d-e4e1-4c13-be5d-3494524ea098','湖頭觀桃李四絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','朝騎一馬暮還歸，盡日花間覓句遲。',32,'全唐诗/poet.song.85000.json','["朝騎一馬暮還歸，盡日花間覓句遲。", "黄四娘家誰敢道，古來惟有少陵詩。"]'),
('799ec6b2-27fd-4464-8712-c0177cc014ba','湖頭觀桃李四絕句  其三','王庭珪','宋','宋诗','song-poetry','','[]','城裏池臺俗儉窮，却來城外探東風。',32,'全唐诗/poet.song.85000.json','["城裏池臺俗儉窮，却來城外探東風。", "曲欄幽檻趣不遠，春在郊原浩蕩中。"]'),
('846816b7-6013-4195-b5a6-cac056d5618d','湖頭觀桃李四絕句  其四','王庭珪','宋','宋诗','song-poetry','','[]','春入千林烟雨中，桃花李花能白紅。',32,'全唐诗/poet.song.85000.json','["春入千林烟雨中，桃花李花能白紅。", "一時草木披錦繡，十里吹香墜晚風。"]'),
('9013b3db-b3cf-45d1-af28-8765071b16b5','茉莉花三絕句  其一','王庭珪','宋','宋诗','song-poetry','','[]','纖雲捲盡日西流，人在瑤池宴未休。',32,'全唐诗/poet.song.85000.json','["纖雲捲盡日西流，人在瑤池宴未休。", "王母欲歸香滿路，曉風吹下玉搔頭。"]'),
('94ddc3bd-8a71-45c3-9350-82b49d5253c2','茉莉花三絕句  其二','王庭珪','宋','宋诗','song-poetry','','[]','火雲燒野葉聲乾，歷眼誰知玉蕊寒。',32,'全唐诗/poet.song.85000.json','["火雲燒野葉聲乾，歷眼誰知玉蕊寒。", "疑是羣仙來下降，夜深時聽珮珊珊。"]'),
('87356a7b-9bbb-4df5-9573-958dfa0e02b6','茉莉花三絕句  其三','王庭珪','宋','宋诗','song-poetry','','[]','逆鼻清香小不分，冰肌一洗瘴江昏。',32,'全唐诗/poet.song.85000.json','["逆鼻清香小不分，冰肌一洗瘴江昏。", "嶺頭未負春消息，恐是梅花欲返魂。"]'),
('89fcaf36-9925-4ff6-9343-7d82d8aa3b43','挽劉美中尚書','王庭珪','宋','宋诗','song-poetry','','[]','公方持槖我休官，握手平生出肺肝。',64,'全唐诗/poet.song.85000.json','["公方持槖我休官，握手平生出肺肝。", "豈是尚書先著履，須知處士不彈冠。", "文章進直金鑾殿，槽櫪空餘寶馬鞍。", "忍看銘旌下螺浦，再攜斗酒餞江干。"]'),
('5c35b53c-4ffd-462f-b04a-7ef52bfff955','挽彭子從郎中','王庭珪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嶺北嶺南持使節，湖西兼總大農錢。',64,'全唐诗/poet.song.85000.json','["嶺北嶺南持使節，湖西兼總大農錢。", "廟堂正賴持國計，蓬島祗爲蜕骨仙。", "郎省尚虚丹禁地，銘旌忽上洞庭船。", "衣冠不許掛神武，端謂猶堪濟巨川。"]'),
('e533654f-2e3b-4b1f-9f93-2dc462502d0e','挽王自然二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','耆舊風流絕後塵，尚容晚歳接冠巾。',64,'全唐诗/poet.song.85000.json','["耆舊風流絕後塵，尚容晚歳接冠巾。", "英豪取友半天下，論議常傾一座人。", "横槊陣前工草檄，結廬江上老垂綸。", "只今遺像髯如棘，猶足堂堂聳縉紳。"]'),
('c077213c-9aa5-434b-85e7-0786145b6f29','挽王自然二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','衣冠南渡塞螺川，始識蓬萊王自然。',64,'全唐诗/poet.song.85000.json','["衣冠南渡塞螺川，始識蓬萊王自然。", "舌捲風雷翻海岳，學窮精祲出人天。", "歸來元亮荒三徑，老去揚雄有一廛。", "斗酒隻雞思欲致，無因下馬拜新阡。"]'),
('d3b062cf-6252-494a-b1ab-09127034510a','挽王夫人','王庭珪','宋','宋诗','song-poetry','','[]','憶昔諸郎從板輿，當時人物渡江初。',64,'全唐诗/poet.song.85000.json','["憶昔諸郎從板輿，當時人物渡江初。", "蓬萊闕外雙飛鶴，葬會漳南數郡車。", "魄已成仙歸閬苑，兒方着足上雲衢。", "紫微即日趨嚴召，八座無因問起居。"]'),
('5d61a4a4-9dec-4b64-9e6f-2c2b9ac9a258','挽盧宜人二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','崔盧唐舊族，譜系自名門。',48,'全唐诗/poet.song.85000.json','["崔盧唐舊族，譜系自名門。", "子舍三珠樹，思劉七耳孫。", "是行將貴顯，不及問平反。", "坐脫無凡語，人傳有至言。"]'),
('cb8bc5f9-c3ef-45c6-8799-b88960f86f4a','挽盧宜人二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','高風林下閨門裏，幾歲長齋繡佛前。',64,'全唐诗/poet.song.85000.json','["高風林下閨門裏，幾歲長齋繡佛前。", "夫子雄才尹天邑，清魂獨樂上蓬仙。", "化爲雙鶴何方客，來置束芻南郡賢。", "會致送車填廣陌，他時彤史亦須編。"]'),
('8670372f-1d00-41c8-8e63-eb3a75c433e9','挽黄忠臣二首  其一','王庭珪','宋','宋诗','song-poetry','','[]','憶昔相逢子少年，詩書從我日磨研。',64,'全唐诗/poet.song.85000.json','["憶昔相逢子少年，詩書從我日磨研。", "平生極力欲推挽，世事驚人忽變遷。", "未辯嘘枯送天上，忍收遺骨葬江邊。", "雙親白髪終身恨，不見青衫落眼前。"]'),
('be48aaa2-2e8b-40bd-8ae4-4b27572c45f5','挽黄忠臣二首  其二','王庭珪','宋','宋诗','song-poetry','','[]','書報登科墨未乾，已聞弔客在門闌。',64,'全唐诗/poet.song.85000.json','["書報登科墨未乾，已聞弔客在門闌。", "只傳金榜升華省，不得丹梯上廣寒。", "賦就兩番隨計吏，花開一日遍長安。", "誰知鬼錄南宮籍，却作修文地下官。"]'),
('52b6b6b5-0ddc-4d27-a323-3e24a172c709','挽戴彦成通判','王庭珪','宋','宋诗','song-poetry','','[]','早歲同充上國賓，與君先占廣寒春。',64,'全唐诗/poet.song.85000.json','["早歲同充上國賓，與君先占廣寒春。", "青雲尚記當時事，黄土今埋如此人。", "别駕朱幡泥飾屏，縈紆茜綬带銅銀。", "生前富貴無餘恨，痛念堂遺白髪親。"]'),
('a66ded48-d129-4af6-a82a-ce6d14e4dcbb','挽劉公弼','王庭珪','宋','宋诗','song-poetry','','[]','弟兄詞賦喧場屋，晚歲鄉閭譽益譁。',64,'全唐诗/poet.song.85000.json','["弟兄詞賦喧場屋，晚歲鄉閭譽益譁。", "窗下殘編雕草木，壁間遺翰走龍蛇。", "蠟餘幾緉遊山屐，書滿千篇載鹿車。", "痛惜蒲輪迎未果，寢門來哭淚横斜。"]'),
('5e6836a3-ae24-4c69-8544-719ff504cb18','挽王修華','王庭珪','宋','宋诗','song-poetry','','[]','督賦寧居中上科，治身從此得名多。',64,'全唐诗/poet.song.85000.json','["督賦寧居中上科，治身從此得名多。", "不聞老父踰垣走，且聽兒童載道歌。", "吏不捉人真快樂，庭無留事足中和。", "邦民盡作嬰兒泣，忍送輀車返爛柯。"]'),
('67365310-4f2d-4623-89af-1d8dcbb32715','挽劉英臣','王庭珪','宋','宋诗','song-poetry','','[]','累世以貲雄里閭，惟公挾策似寒儒。',64,'全唐诗/poet.song.85000.json','["累世以貲雄里閭，惟公挾策似寒儒。", "欲將那律九經庫，定勝江陵千木奴。", "玉樹諸郎新命貴，錦囊丹誥寵光殊。", "當時籍甚吳丞相，恩澤今歸兩鳳雛。"]'),
('acf6cf96-e5d6-4158-85d8-afc85d943a82','挽徐子平  其一','王庭珪','宋','宋诗','song-poetry','','[]','數椽破屋臨溪水，日日讀書喧四鄰。',64,'全唐诗/poet.song.85000.json','["數椽破屋臨溪水，日日讀書喧四鄰。", "白首傳經窮到骨，清風入座静無塵。", "堆窗史傳千張紙，過隙光陰一轉輪。", "富貴掀天亦埃滅，今時何必歎斯人。"]'),
('336d32d6-f40f-4846-8951-75f9b43e5f18','挽徐子平  其二','王庭珪','宋','宋诗','song-poetry','','[]','季子過徐因掛劍，吾詩似劍敢欺徐。',64,'全唐诗/poet.song.85000.json','["季子過徐因掛劍，吾詩似劍敢欺徐。", "才華本自輕場屋，詁訓猶堪授里閭。", "踏雪打門人問字，載殽從學酒盈車。", "兒童誦得平生賦，不是兔園遺下書。"]'),
('37625702-d34b-412a-b6b6-1177ea494ab6','挽羅荆老','王庭珪','宋','宋诗','song-poetry','','[]','初挾儒書戰舉場，弟兄旗鼓亦相當。',64,'全唐诗/poet.song.85000.json','["初挾儒書戰舉場，弟兄旗鼓亦相當。", "探囊聊復起人死，繫肘空餘濟世方。", "漢苑舊嘗知姓字，壺天今别有仙鄉。", "老龍猶抱玉函訣，夜扣柴門乞酒漿。"]'),
('5678eb8d-5657-4db2-9d19-73c3d47ec2d8','挽鄭教授','王庭珪','宋','宋诗','song-poetry','','[]','仰高雖未接華裾，清論時容著野夫。',64,'全唐诗/poet.song.85000.json','["仰高雖未接華裾，清論時容著野夫。", "掛劍未能臨死穴，隔江何處奠生芻。", "淒涼陶令松三徑，寂寞揚雄宅一區。", "插架尚餘三萬軸，傳家宜有鳳凰雛。"]'),
('b980bfd9-473b-4bda-a34b-63a34ac8e89d','挽曾氏安人','王庭珪','宋','宋诗','song-poetry','','[]','令儀早出閨中秀，少日來歸丞相家。',64,'全唐诗/poet.song.85000.json','["令儀早出閨中秀，少日來歸丞相家。", "能以功名勉夫子，忍看旌旐起悲笳。", "錦囊篆字金裝出，玉珮鳴裾帔有霞。", "贈典有加兒亦貴，誥黄新墨字如鴉。"]'),
('0a0e43e3-cbfb-4bc6-acac-0be3af08393a','挽范孺人','王庭珪','宋','宋诗','song-poetry','','[]','少日來歸奉藻蘋，一門冠蓋擁朱輪。',64,'全唐诗/poet.song.85000.json','["少日來歸奉藻蘋，一門冠蓋擁朱輪。", "平生未識德公嫂，比歲纔依孟母鄰。", "魂返蓬萊三萬里，鶴歸華表幾千春。", "南州高士應匍匐，忍看靈車下北津。"]'),
('b1b586fe-b8ae-4ac5-a173-9f84c85f7045','挽瞿氏','王庭珪','宋','宋诗','song-poetry','','[]','徒身諸福壽尤豐，魄返仙曹第幾宮。',64,'全唐诗/poet.song.85000.json','["徒身諸福壽尤豐，魄返仙曹第幾宮。", "西土夢星生太白，東牀選壻得梁鴻。", "豈無名士當時論，自有夫人林下風。", "來弔不知何處客，化爲雙鶴却飛空。"]'),
('4ce56eac-5cae-489c-82aa-bba8c14a2224','挽易氏','王庭珪','宋','宋诗','song-poetry','','[]','媪有才子鄰我居，父老欲起高門閭。',64,'全唐诗/poet.song.85000.json','["媪有才子鄰我居，父老欲起高門閭。", "此媪不知家有無，但典髻鬟供買書。", "今朝慟哭城南道，忍送喪車入秋草。", "預愁來歲寒食時，不見襄陽德公嫂。"]'),
('65f24c86-0244-475e-9419-700022eeec4a','挽劉子儀','王庭珪','宋','宋诗','song-poetry','','[]','鬼伯歌朝露，歸魂掩夜泉。',48,'全唐诗/poet.song.85000.json','["鬼伯歌朝露，歸魂掩夜泉。", "起家詩禮盛，折桂弟兄賢。", "箭落雙鵰日，君當化鶴年。", "阿鴻今已貴，飛去欲摩天。"]'),
('0ed2126f-3653-48c2-9ace-19e266482fe5','挽歐陽仁叟','王庭珪','宋','宋诗','song-poetry','','[]','郡從簪纓貴，騶僮意氣華。',48,'全唐诗/poet.song.85000.json','["郡從簪纓貴，騶僮意氣華。", "呼盧晉公子，大俠魯朱家。", "錦臂誇豪放，銀鞍走狹斜。", "忍尋桃徑裏，無主亦開花。"]'),
('52806c1e-6922-4d88-80b2-4cc75d97ca8e','挽張氏安人','王庭珪','宋','宋诗','song-poetry','','[]','母子未相識，哀號徹九穹。',48,'全唐诗/poet.song.85000.json','["母子未相識，哀號徹九穹。", "一生何敢望，萬里忽相逢。", "綵服舊兒戲，錦囊新誥封。", "悲歌滿行路，千載想遺風。"]'),
('df953253-9139-4a59-95b5-b204f9b51e3a','挽歐陽宜人','王庭珪','宋','宋诗','song-poetry','','[]','渤海家聲赫，先朝御史孫。',48,'全唐诗/poet.song.85000.json','["渤海家聲赫，先朝御史孫。", "霞冠宜象服，腰笏擁魚軒。", "五福壽尤貴，兩兒名更喧。", "惟嗟漢陽遠，不及問平反。"]'),
('90f38d9d-5fe4-4023-b964-85dd03e47344','挽王氏夫人','王庭珪','宋','宋诗','song-poetry','','[]','歲歉傾禾粟，賓來剪髪鬟。',48,'全唐诗/poet.song.85000.json','["歲歉傾禾粟，賓來剪髪鬟。", "其人今已朽，此事古尤難。", "斜日銜峰頂，秋風想珮環。", "出門驚弔客，雙鶴下雲間。"]'),
('5ff92b10-881f-49cf-b7c5-3fdecb22ea4e','挽王氏孺人','王庭珪','宋','宋诗','song-poetry','','[]','賜爵逢千載，皇恩下九關。',48,'全唐诗/poet.song.85000.json','["賜爵逢千載，皇恩下九關。", "誥詞金篆字，珩珮玉連環。", "陶母今有後，萊衣不復斑。", "哀歌堪挽紼，徒有涙澘澘。"]'),
('f8bab052-eb7d-4610-a98f-78beb005ce38','挽郭氏孺人','王庭珪','宋','宋诗','song-poetry','','[]','擇對真佳壻，傳家好弟兄。',48,'全唐诗/poet.song.85000.json','["擇對真佳壻，傳家好弟兄。", "魂飛瑤海岸，風斷玉簫聲。", "舉案人何在，埋文誰作銘。", "潘郎今未老，他日看襃榮。"]'),
('ea75591f-62fb-49f4-a395-a76b9e178e8e','挽聶氏孺人','王庭珪','宋','宋诗','song-poetry','','[]','隴上龐公女，相家裴十娘。',48,'全唐诗/poet.song.85000.json','["隴上龐公女，相家裴十娘。", "空門參白足，佳壻得黄香。", "木馬風前響，蓮花火裏芳。", "彌陀真樂土，環珮響鏘鏘。"]'),
('b9e72866-fd9c-4867-b62f-d622e8a0f1ce','挽露氏恭人','王庭珪','宋','宋诗','song-poetry','','[]','華胄東京舊，青樓大道邊。',48,'全唐诗/poet.song.85000.json','["華胄東京舊，青樓大道邊。", "渡江離險阻，舉族得安全。", "追賞榮身後，褒封及眼前。", "清魂在蓬島，彷彿綴羣仙。"]'),
('1a31ec71-93a0-4807-a311-34f211bf07bb','挽丁陶明縣尉','王庭珪','宋','宋诗','song-poetry','','[]','東南作尉本神仙，化鶴家聲亦宛然。',64,'全唐诗/poet.song.85000.json','["東南作尉本神仙，化鶴家聲亦宛然。", "臨欲騎魚歸海島，猶能躍馬拓弓絃。", "花間載酒經旬日，陌上悲歌隔九泉。", "尚有讀書臺下月，夜深還照碧池邊。"]'),
('b1ee614c-c224-40fe-8362-c99102263b3d','挽劉宗望','王庭珪','宋','宋诗','song-poetry','','[]','何年來卧北山霞，猶指海邊團練家。',64,'全唐诗/poet.song.85000.json','["何年來卧北山霞，猶指海邊團練家。", "手把方書妙耕種，門高閭巷獨清華。", "兩兒駒齒日千里，萬卷牙籖架五車。", "風動松篁起蕭瑟，不堪回首聽悲笳。"]'),
('3cfe3e1b-2a30-41c4-9092-c59cf365fa1e','蕭瀧廟迎神詩','王庭珪','宋','宋诗','song-poetry','','[]','瀧神何年此列宮，神之來兮雨溟濛。',96,'全唐诗/poet.song.85000.json','["瀧神何年此列宮，神之來兮雨溟濛。", "雷公擊鼓驅羣龍，神之靈兮與天通。", "十日五日一雨風，物無疵癘年穀豐。", "瀧民事神甚嚴恭，牲羞薦酒羅鼓鐘。", "湍雖洶涌長年工，不聞船石相撞舂。", "孰知此者神之功，宜歌此曲傳無窮。"]'),
('2c9050ce-339f-447d-809d-2ee14caaeb39','乾龍節致語口號','王庭珪','宋','宋诗','song-poetry','','[]','紅日初生碧海邊，蓬萊金殿起晴烟。',64,'全唐诗/poet.song.85000.json','["紅日初生碧海邊，蓬萊金殿起晴烟。", "幾重瑞氣籠雙闕，萬室歡聲動九天。", "百二山河扶寶祚，兩階干羽舞文甎。", "遙聞葱嶺新都護，願舉霞觴祝萬年。"]'),
('bc5e6426-a2f7-4aa5-8599-fed89aa3f9a4','天申節致語','王庭珪','宋','宋诗','song-poetry','','[]','樂事初從天上傳，慈寧宮在曰華邊。',64,'全唐诗/poet.song.85000.json','["樂事初從天上傳，慈寧宮在曰華邊。", "慶逢誕節張鈞樂，奏舉遐方錫御筵。", "滿殿薰風旗彩動，一墀鳴玉佩聲喧。", "遙聞儀鳯隨韶奏，報道君王壽萬年。"]'),
('fc195148-8dc5-4ed9-a7c1-629a11948183','閱軍致語口號','王庭珪','宋','宋诗','song-poetry','','[]','秀嶺東邊今日晴，千兵繞出陣雲平。',64,'全唐诗/poet.song.85000.json','["秀嶺東邊今日晴，千兵繞出陣雲平。", "長槍大劍遮行路，後虎前貔擁使旌。", "看拓弓弦聲霹靂，願回甲馬掃欃槍。", "山農野叟何曾識，來聽秋風鼓角聲。"]'),
('1e88e34e-b7c7-480a-877d-ace6131ddf20','高峰禪寺修殿疏偈','王庭珪','宋','宋诗','song-poetry','','[]','紺殿傾頹幾十秋，佛應不語阿難愁。',32,'全唐诗/poet.song.85000.json','["紺殿傾頹幾十秋，佛應不語阿難愁。", "諸方檀越宜興念，共出把茅來蓋頭。"]'),
('b2068af2-81e6-45b8-8b2b-bfdbe2f83db0','遷善齋銘','王庭珪','宋','宋诗','song-poetry','','[]','擊石出火，鼓鐘得聲。',120,'全唐诗/poet.song.85000.json','["擊石出火，鼓鐘得聲。", "不鼓不擊，寂無聲形。", "人之有善，物中最靈。", "揉以學問，其識乃明。", "跛鼈千里，六驥不行。", "玉不加琢，器何由成。", "吾觀成叔，挺挺有立。", "學有淵源，家聲爀熠。", "深山大澤，龍蛇蟠蟄。", "實無所遷，假遷而入。", "猶天之升，不落階級。", "參辰殊途，追莫能及。"]'),
('b548f5fb-df5c-4529-937f-391bdaacb27b','惠端琴銘','王庭珪','宋','宋诗','song-poetry','','[]','大江之西，盧水之陰。',75,'全唐诗/poet.song.85000.json','["大江之西，盧水之陰。", "有三昧手，斲無量音。", "震動法窟，是爲老端之琴。", "蓋嘗求師於海中，登蓬萊閬風之岑，聽海水林木之蕭森。", "採枯桐以寄其妙絕，信哉點瓦礫而成金。"]'),
('10524c41-5f94-49df-83c0-c65c95eefd6e','琴銘','王庭珪','宋','宋诗','song-poetry','','[]','桐生高岡，斧出月窟。',45,'全唐诗/poet.song.85000.json','["桐生高岡，斧出月窟。", "斵而成器，神藏鬼没。", "此一物也，與寶劍相攜於盧溪之上，三者皆天下之英物。"]'),
('bd1d4f0d-3b89-47f7-85b7-b35b24d0f8aa','惠門寺鐘銘','王庭珪','宋','宋诗','song-poetry','','[]','萬動俱寂，如大虚空。',60,'全唐诗/poet.song.85000.json','["萬動俱寂，如大虚空。", "虚空無椎，何物爲鐘。", "傍震萬壑，高聞九穹。", "聲緣何起，吾知所從。", "鐘邪椎耶，莫尸其功。", "隱如雷霆，在大千中。"]'),
('ba4c9707-1ad7-4933-951b-f29bd68e4585','寶珠寺鐘銘','王庭珪','宋','宋诗','song-poetry','','[]','蠢然冥頑孰與覺，空中雷電忽磅礴。',64,'全唐诗/poet.song.85000.json','["蠢然冥頑孰與覺，空中雷電忽磅礴。", "大音希聲本無作，回祿奮怒飛廉惡。", "一鼓成鐘神所託，劍蟠蛟螭怒牙角。", "六種震動天雨雹，鑄此銘詩呵不若。"]'),
('17a66127-7123-4663-9e94-f0c2aff64a76','仁山五百羅漢贊','王庭珪','宋','宋诗','song-poetry','','[]','迦葉天中五百尊，目連羅睺皆駿奔。',80,'全唐诗/poet.song.85000.json','["迦葉天中五百尊，目連羅睺皆駿奔。", "阿難啼哭佛日昏，誰爲設法沙林園。", "帝釋擁護六鑿根，習氣脫盡婆羅門。", "仁山金碧耀人天，瞻禮願見前世緣。", "法螺一吹天上聞，還報十方羅漢恩。"]'),
('a79c2f09-62fc-44be-93ad-fd7a695af1b5','圓通贊','王庭珪','宋','宋诗','song-poetry','','[]','太山秋毫兩微塵，巨細本無不二門。',64,'全唐诗/poet.song.85000.json','["太山秋毫兩微塵，巨細本無不二門。", "四方八面開戶牖，是中元有不動尊。", "如大圓鏡萬象入，如大海水百谷奔。", "維摩倒用那羅印，用證初心豈或淪。"]'),
('2f84c784-f55e-47cc-b946-a24f16deda39','洪覺範畫贊','王庭珪','宋','宋诗','song-poetry','','[]','謂公爲佛，乃工文章。',60,'全唐诗/poet.song.85000.json','["謂公爲佛，乃工文章。", "謂公爲儒，乃是和尚。", "非佛非儒，是虚空藏。", "畫雖逼真，實非真相。", "作如是見，亦未離妄。", "水在瓶中，月在天上。"]'),
('5ad9ac5b-874e-4d1f-9eda-e8084db6057e','李伯時畫像贊','王庭珪','宋','宋诗','song-poetry','','[]','非佛非仙，亦非儒者。',40,'全唐诗/poet.song.85000.json','["非佛非仙，亦非儒者。", "硉硉矹矹，名滿天下。", "孰貌其真，非真非假。", "讀東坡詩，乃識此畫。"]'),
('8b8a6aa8-110f-4bcf-bd95-ab57d14b9b56','歐陽公制贊','王庭珪','宋','宋诗','song-poetry','','[]','如馬放逸兮不覊，如松磥砢兮多節。',56,'全唐诗/poet.song.85000.json','["如馬放逸兮不覊，如松磥砢兮多節。", "偉幹如謝康樂之眉鬚，雄辯如樓君卿之唇舌。", "其高處可以上可以下，其妙處不可畫不可說。"]'),
('0ba27baa-2d7f-4751-8823-8ec8a8f896c0','杲和尚畫贊','王庭珪','宋','宋诗','song-poetry','','[]','硉硉矹矹，如祝融太華，高不知其幾千丈。',105,'全唐诗/poet.song.85000.json','["硉硉矹矹，如祝融太華，高不知其幾千丈。", "軒軒轟轟，如驚雷唳鶴，聲徹乎九天之上。", "道在真空，空即無相。", "以相求之，如盲摸象。", "乘機應物，河岳震響。", "眼如掣電，舌如奔浪。", "轉大法輪，說無盡藏。", "當恁麽時有識之者，箇是徑山杲和尚。"]'),
('5f1eaefe-1e89-441f-82e5-38e78311b2a1','鑑達觀畫像贊','王庭珪','宋','宋诗','song-poetry','','[]','寂然其容，萬法不起。',80,'全唐诗/poet.song.85000.json','["寂然其容，萬法不起。", "色固無求，不怒不喜。", "人自即之，其門如市。", "忽然探囊，輒起人死。", "本自無生，死亦何理。", "公能起之，如月在水。", "應物現形，本無作止。", "我復贊之，亦遊戲耳。"]'),
('a9e51ab0-316b-4a77-9ea4-34afce0aecbd','路正卿畫像贊','王庭珪','宋','宋诗','song-poetry','','[]','森然如千丈之長松，勢若摩穹。',58,'全唐诗/poet.song.85000.json','["森然如千丈之長松，勢若摩穹。", "昂然如野鶴之出籠，雞羣遂空。", "使之崛起，接翼鵷鴻。", "高冠大劍，立于庭中。", "七尺之軀，萬夫之雄。"]'),
('73d68684-f6f0-4bee-adac-1c6fea3e2964','王修華畫像贊','王庭珪','宋','宋诗','song-poetry','','[]','不冠不束，真被褐而懷玉。',78,'全唐诗/poet.song.85000.json','["不冠不束，真被褐而懷玉。", "眼如曳電，光掣巖谷。", "不爲燕頷虎頭，萬里飛而食肉。", "幅巾飄然，如五柳先生。", "寧終身爲縣令，而無求於世俗。", "揮麈塵埃之外，遺物離人，而立於獨。"]'),
('f2cd4757-3dcc-4bdf-a542-665752853689','劉大虚喜神贊','王庭珪','宋','宋诗','song-poetry','','[]','畫無老幼，形全神守。',79,'全唐诗/poet.song.85000.json','["畫無老幼，形全神守。", "頰上三毛，端逢妙手。", "少年角立，試輙不偶。", "不復掉鞅，名聞谷口。", "量陂千頃，才不論斗。", "今踰八十，年其逮耉。", "古人云用之則爲公爲卿，不用則山谷一叟。"]'),
('029e8479-ed88-487d-894e-8ba0b3aba087','英和尚贊','王庭珪','宋','宋诗','song-poetry','','[]','吉州英，鐵作觜。',16,'全唐诗/poet.song.85000.json','["吉州英，鐵作觜。", "莫貶眼，只這是。"]'),
('8c6b03fd-8b37-42cb-8986-04b71d16f1a0','戲調義高','王庭珪','宋','宋诗','song-poetry','','[]','横擔拄杖入山，坐斷高峰境界。',56,'全唐诗/poet.song.85000.json','["横擔拄杖入山，坐斷高峰境界。", "一吼震動林木，忽然草賊大敗。", "了則萬法俱空，未了應須還債。", "本是兩重公案，如今一道俱解。"]'),
('114d96b8-3afe-43a1-8b28-7b5b6d4d7823','答王道之','王庭珪','宋','宋诗','song-poetry','','[]','雲門至死不惺惺，居士仍蹉半月程。',32,'全唐诗/poet.song.85000.json','["雲門至死不惺惺，居士仍蹉半月程。", "未省夢中重說夢，醉來添酒幾時醒。"]'),
('7ffb226c-f082-4d3e-8c47-bebef13a5abb','贈姪孫行深','王庭珪','宋','宋诗','song-poetry','','[]','頭陀未具山僧像，只欠鉢囊挑錫杖。',32,'全唐诗/poet.song.85000.json','["頭陀未具山僧像，只欠鉢囊挑錫杖。", "我今自是在家僧，汝好將錢買和尚。"]'),
