('8af23167-903f-4b07-be6f-e0142cda9132','菖蒲寺','季陵','宋','宋诗','song-poetry','','[]','飛泉一派木千章，九節蒲根澗裏香。',32,'全唐诗/poet.song.85000.json','["飛泉一派木千章，九節蒲根澗裏香。", "拔宅不留雞與犬，至今無處問仙方。"]'),
('cd19b973-c48d-456b-a9ca-52981ab6ee7f','小盡行','朱敦儒','宋','宋诗','song-poetry','','[]','藤州三月作小盡，梧州三月作大盡。',64,'全唐诗/poet.song.85000.json','["藤州三月作小盡，梧州三月作大盡。", "哀哉官曆今不頒，憶昔昇平淚成陣。", "我今何異桃源人，落葉爲秋花作春。", "但恨未能與世隔，時聞喪亂空傷神。"]'),
('bc0b57f0-68aa-4b81-9501-0b14e130a2bf','種蕪菁作羹','朱敦儒','宋','宋诗','song-poetry','','[]','且喜蕪菁種得成，苔心散出碧縱橫。',64,'全唐诗/poet.song.85000.json','["且喜蕪菁種得成，苔心散出碧縱橫。", "脆甜肭子無反惡，肥嫩恙兒不殺生。", "樂羊豈斷兒孫念，劉季寧無父子情。", "爭似野人茅屋下，日高澹煮一杯羹。"]'),
('423b34f9-df14-4955-921d-84f91fc3d83b','歷世','朱敦儒','宋','宋诗','song-poetry','','[]','面冊面友風雨散，山鳥山花澹薄交。',32,'全唐诗/poet.song.85000.json','["面冊面友風雨散，山鳥山花澹薄交。", "一榻氍毹容獨臥，滿盤杞菊是兼肴。"]'),
('3f54431f-6bf1-44c0-946d-7bbb15438134','五言','朱敦儒','宋','宋诗','song-poetry','','[]','天寒猶著絮，雨濕欲蒸書。',36,'全唐诗/poet.song.85000.json','["天寒猶著絮，雨濕欲蒸書。", "吳地人情薄，西人客計疏。", "無書堪著眼，有法可安心。"]'),
('0e22fe5b-a0ef-497c-81ec-162f531f1d03','絕句二首  其一','朱敦儒','宋','宋诗','song-poetry','','[]','誰倚黄旗喚阿瞞，令君終作可憐人。',32,'全唐诗/poet.song.85000.json','["誰倚黄旗喚阿瞞，令君終作可憐人。", "蕭然惟有鹿門老，不带孫劉一點塵。"]'),
