('efdf784e-c661-49f4-88df-a1d06d08583c','臨別誡弟子偈','釋凈昭','宋','宋诗','song-poetry','','[]','物外翛然獲自由，殷勤諸子送他州。',64,'全唐诗/poet.song.85000.json','["物外翛然獲自由，殷勤諸子送他州。", "白雲暫駐無方所，明月相隨到處優。", "巖谷乍拖終勿思，林泉幽景豈迴眸。", "吾今此去聊相別，汝且和光混衆流。"]'),
('e77ba328-a473-4b96-ac91-2f1655691b4c','夢中作','江端本','宋','宋诗','song-poetry','','[]','晚風殘日下危樓，斜倚欄幹滿眼愁。',32,'全唐诗/poet.song.85000.json','["晚風殘日下危樓，斜倚欄幹滿眼愁。", "休唱陽關催別酒，春情離恨總悠悠。"]'),
('d783f2d1-3ccf-4211-9941-01df13d84c1c','次韻子我兄和沈侍御史吳興酬唱詩三首  其一','江端本','宋','宋诗','song-poetry','','[]','苕霅憶初泛，星霜今幾周。',48,'全唐诗/poet.song.85000.json','["苕霅憶初泛，星霜今幾周。", "芳蓮霞比色，晚水月同游。", "未盡煙波賞，先驚歲月遒。", "風塵今滿眼，遙想芰荷秋。"]'),
('a5c5fa9d-146b-4746-8a66-9a64de971a0f','次韻子我兄和沈侍御史吳興酬唱詩三首  其二','江端本','宋','宋诗','song-poetry','','[]','宇宙煙塵日，誰何風馬牛。',48,'全唐诗/poet.song.85000.json','["宇宙煙塵日，誰何風馬牛。", "掀天怒翼倦，卷地駭奔流。", "黷武非天意，窮凶與鬼謀。", "風波方治渺，何處可維舟。"]'),
('ef18ff2e-b929-4de6-90dc-94dc716b6c26','次韻子我兄和沈侍御史吳興酬唱詩三首  其三','江端本','宋','宋诗','song-poetry','','[]','四野傳烽急，中原殺氣浮。',48,'全唐诗/poet.song.85000.json','["四野傳烽急，中原殺氣浮。", "游魚驚過艇，風葉亂鳴鶖。", "宿霧藏文豹，寒浮露遠洲。", "無心謀出處，知命復何憂。"]'),
('b5d7ac5b-d851-46b3-84d0-160ae96abb12','送人','江端本','宋','宋诗','song-poetry','','[]','年衰歲晚有誰從，井臼無人伴敬通。',64,'全唐诗/poet.song.85000.json','["年衰歲晚有誰從，井臼無人伴敬通。", "當戶秋山橫積翠，擁階霜葉委殘紅。", "倦遊自笑裘先敝，赴敵誰知甲已衷。", "看取功名垂竹帛，不須咄咄更書空。"]'),
('ac820cdf-51b3-4da6-99d2-e525e30a604f','閑居即事','鄭測','宋','宋诗','song-poetry','','[]','小園風景暮春初，隨分優游亦足娛。',64,'全唐诗/poet.song.85000.json','["小園風景暮春初，隨分優游亦足娛。", "柳似王恭殊濯濯，蝶疑莊叟自蘧蘧。", "澆腸漫進三蕉酒，引睡聊翻數葉書。", "今日始知閑有味，悔從塵土曳長裾。"]'),
('a05d1800-717e-43ac-9ba8-dab84e26fe0a','賞心亭','姜仲謙','宋','宋诗','song-poetry','','[]','樓外青山刮眼明，軒窗當暑更風清。',64,'全唐诗/poet.song.85000.json','["樓外青山刮眼明，軒窗當暑更風清。", "地分南北開天險，江泛東西幾客程。", "四者難並同醆斝，一之已甚厭戈兵。", "最憐夜夜秦淮月，相伴依然似友生。"]'),
('7453dba1-9fa2-4b3e-b53b-626fa384c2b0','己酉中秋任才仲陳去非會飲岳陽樓上酒半酣高談大笑行草間出誠一時俊遊也爲賦之','姜仲謙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','岳陽樓高幾千尺，俯視洞庭方酒酣。',64,'全唐诗/poet.song.85000.json','["岳陽樓高幾千尺，俯視洞庭方酒酣。", "萬頃波光天上下，兩山秋色月東南。", "興來鸞鵠隨行草，夜永魚龍駭笑談。", "我欲煩公釣鰲手，盡移雲水到松庵。"]'),
('ba367a17-580c-4748-9aff-78d55ccedd8b','思杜亭','姜仲謙','宋','宋诗','song-poetry','','[]','十里松陰古道場，一亭還復枕瀟湘。',64,'全唐诗/poet.song.85000.json','["十里松陰古道場，一亭還復枕瀟湘。", "詩翁至死憂唐室，野客於今吊耒陽。", "窻戶雲生山雨集，巖溪花發曉風香。", "不唯臨眺添惆悵，自是年來鬢已霜。"]'),
('255136ac-3bd2-4116-9e5b-6f1499bd713e','長蘆寺','姜仲謙','宋','宋诗','song-poetry','','[]','長蘆禪剎昔經過，十載重遊素髪多。',64,'全唐诗/poet.song.85000.json','["長蘆禪剎昔經過，十載重遊素髪多。", "南去宦情聊爾耳，西來師意竟如何。", "千燈不絕開堂盛，一葦常存濟世多。", "我久途窮仗佛力，剩書內葉弭風波。"]'),
('3b0bfa42-51db-4dcd-8b3d-b4270d2bdfcd','句','姜仲謙','宋','宋诗','song-poetry','','[]','銅鼓舊俗存，瘴江春色早。',12,'全唐诗/poet.song.85000.json','["銅鼓舊俗存，瘴江春色早。"]'),
('9437d081-e1e4-4a84-91a0-b90be7397459','游百巖（原注：石在河南修武）','劉師忠','宋','宋诗','song-poetry','','[]','當年匹馬度荒村，青眼相逢是此君。',32,'全唐诗/poet.song.85000.json','["當年匹馬度荒村，青眼相逢是此君。", "重到故鄉歸興動，一竿風月對何人。"]'),
('73332906-8c65-4a7d-83dd-dc21e08503c0','和李處勱題萃清閣','江緯','宋','宋诗','song-poetry','','[]','于嗟道力淺，日恐世緣熟。',132,'全唐诗/poet.song.85000.json','["于嗟道力淺，日恐世緣熟。", "身雖走朝市，夢輒在巖麓。", "歸來濯塵纓，築室淺流瀑。", "簷宿謫仙雲，徑荒陶令菊。", "吟哦格調古，衛養神氣肅。", "遐觀狹宇宙，幽討遍山谷。", "林泉無俗韻，松檜有清馥。", "悠然夢幻身，忍把利名束。", "吾人藴長才，未肯策高足。", "朅來金溪上，共奏紫芝曲。", "永結忘形交，何須醉醽醁。"]'),
('27b1c23f-96f2-4ede-8ea7-4c77aaf3573d','書中貴人扇','王彥和','宋','宋诗','song-poetry','','[]','天邊一線征鴻沒，山色淺深墨未勻。',32,'全唐诗/poet.song.85000.json','["天邊一線征鴻沒，山色淺深墨未勻。", "別浦漁舟待歸去，夕陽渡口兩三人。"]'),
