('af54b532-6f76-4db0-b364-c28687075508','題張文潛畫帖  其一','陳克','宋','宋诗','song-poetry','','[]','此老從來馬如狗，却笑蹇驢難朝天。',32,'全唐诗/poet.song.85000.json','["此老從來馬如狗，却笑蹇驢難朝天。", "聊爾據鞍猶覓句，想知行處似乘船。"]'),
('625d60af-d58a-4c99-92d4-7317d320960f','題張文潛畫帖  其二','陳克','宋','宋诗','song-poetry','','[]','官曹文書堆滿牀，憒憒度日孤晝長。',32,'全唐诗/poet.song.85000.json','["官曹文書堆滿牀，憒憒度日孤晝長。", "安得如彼二三子，抱琴挟策置我旁。"]'),
('1da58ac2-fee7-4175-9431-8db808ed676e','何伯言畫','陳克','宋','宋诗','song-poetry','','[]','何子畫山心極苦，不畫山林畫其趣。',96,'全唐诗/poet.song.85000.json','["何子畫山心極苦，不畫山林畫其趣。", "不知此絹厚幾許，隱隱深入疑有路。", "去年持此干貴權，數幅得官仍得錢。", "平民常産賣有盡，筆端有産無窮年。", "而今東絹知何數，不爲水墨爲襦袴。", "我憐何子老更癡，平民皆飽汝獨饑。"]'),
('3bdb2cb6-e6fb-419c-9c80-68399e888d76','三品石','陳克','宋','宋诗','song-poetry','','[]','臨春結綺今何在，屹立巉巉終不改。',32,'全唐诗/poet.song.85000.json','["臨春結綺今何在，屹立巉巉終不改。", "可憐江總負君恩，白頭仍作北朝臣。"]'),
('382a6280-1546-4659-9b0e-44e8908f64d9','瑞香','陳克','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','佳人在空谷，雙星思銀河。',120,'全唐诗/poet.song.85000.json','["佳人在空谷，雙星思銀河。", "契闊不有命，盛時豈蹉跎。", "娟娟匡廬秀，如此粲者何。", "香蜜綴紅糝，寶薰罩宮羅。", "幽窗下團欒，微風自婆娑。", "寂寥千年初，戢戢逢艾多。", "何階託方便，百金聘猗儺。", "赤欄青篾舫，丁寧護根窼。", "泥沙亦天幸，扳聯入宣和。", "誰令蘭蕙徒，憔悴守巖阿。"]'),
('2c762cbb-e78b-493e-afeb-7bee4f13befa','九月瑞香盛開','陳克','宋','宋诗','song-poetry','','[]','宣和殿裏春風早，紅錦薰籠二月時。',32,'全唐诗/poet.song.85000.json','["宣和殿裏春風早，紅錦薰籠二月時。", "流落人間真善事，九秋霜露卻相宜。"]'),
('a5b240db-ac42-47d5-9f64-c62636894615','代王正平從諫掾乞畫憑肩美人扇子二首  其一','陳克','宋','宋诗','song-poetry','','[]','道人已悟孩提事，棄擲泥兒壞紙鳶。',32,'全唐诗/poet.song.85000.json','["道人已悟孩提事，棄擲泥兒壞紙鳶。", "聞道近來都識破，丹青便面亦輕捐。"]'),
('f980b5b5-3665-4c38-b807-7df6cdb4eea8','代王正平從諫掾乞畫憑肩美人扇子二首  其二','陳克','宋','宋诗','song-poetry','','[]','難陀已幻登伽女，童子猶參蘇密多。',32,'全唐诗/poet.song.85000.json','["難陀已幻登伽女，童子猶參蘇密多。", "正士逡巡不應受，可能分供病維摩。"]'),
('158f6908-3ae0-4293-80d1-122f18da3f22','遊謝鄉','陳克','宋','宋诗','song-poetry','','[]','雨裏落帆遊謝鄉，寒聲古木共荒涼。',32,'全唐诗/poet.song.85000.json','["雨裏落帆遊謝鄉，寒聲古木共荒涼。", "四山爲我洗蒼玉，況有故人歸上方。"]'),
('8f5f02fc-c0bb-4b3c-a80b-5e1133e71a4a','閨情','陳克','宋','宋诗','song-poetry','','[]','壁間衛玠眉目是，膝下枚皋言語真。',32,'全唐诗/poet.song.85000.json','["壁間衛玠眉目是，膝下枚皋言語真。", "縱使無情似郎主，那能對此不沾巾。"]'),
('5cfc5bee-d1e2-40f8-802a-9c77a873f5ef','五月菊','陳克','宋','宋诗','song-poetry','','[]','黄菊有本性，霜餘見幽茂。',24,'全唐诗/poet.song.85000.json','["黄菊有本性，霜餘見幽茂。", "名緇喻般若，太史謹占候。"]'),
('312a7324-e658-435d-b0ce-fcdd2a5fb345','送僧歸天甯萬年禪院','陳克','宋','宋诗','song-poetry','','[]','朝天來詣觚稜闕，傍海歸尋瀑布峰。',64,'全唐诗/poet.song.85000.json','["朝天來詣觚稜闕，傍海歸尋瀑布峰。", "才大不慚師號美，道高翻訝帝恩重。", "問程行冒江村雨，寄宿吟聽水寺鐘。", "到日依依賞清景，石橋雲月滿杉松。"]'),
('cfc944a4-5ee2-4bb1-a7bc-9e2bd365e85d','舍弟書來索近詩','陳克','宋','宋诗','song-poetry','','[]','溪上秋風濁酒杯，白頭羞見菊花開。',64,'全唐诗/poet.song.85000.json','["溪上秋風濁酒杯，白頭羞見菊花開。", "夫耕婦饁吾將老，弟勸兄酬子不來。", "霜露終身思建業，雲山何處是天台。", "百年懷抱今如此，縱有詩成似七哀。"]'),
('4c18ed3d-2f2b-41ce-bb55-bf8cd600ffec','謝瘧鬼','陳克','宋','宋诗','song-poetry','','[]','皇天分四時，寒暑代翕張。',288,'全唐诗/poet.song.85000.json','["皇天分四時，寒暑代翕張。", "折膠與流金，民生以爲常。", "伊坎離何神，爲帝司一方。", "如何縱孽鬼，乘時盜陰陽。", "睢盱四五輩，欻東西跳踉。", "詭祕各有名，爲人作炎涼。", "或燔以炬火，或吹以鞴囊。", "初噤如立雪，俄赫如探湯。", "炎洲抵陰壑，那得在一床。", "閼伯追實沈，左右分寇攘。", "須臾異冬春，裘扇安可當。", "番休數汗粟，冰炭沸我腸。", "怫鬰不自聊，災疢未渠央。", "非針艾所及，區區事祈禳。", "犧牲一物無，祝祠甚荒唐。", "殷勤謝衆鬼，汝計誠未良。", "汝利在嘔泄，藜莧焉足嘗。", "我貧乏錢財，調汝徒披猖。", "來汝豈不聞，儒生類強梁。", "子美雖老瘦，靦顔事新粧。", "退之稍奸黠，百藥更臭香。", "身病易語言，咄咄多謗傷。", "吾將援此例，勉作新詩章。", "詩以榮汝歸，自可捐糗糧。"]'),
('7b08666f-cad5-4a51-a656-73cf6d86e266','陽羨春歌','陳克','宋','宋诗','song-poetry','','[]','石亭梅花落如積，吐鮫斕斑竹茹赤。',128,'全唐诗/poet.song.85000.json','["石亭梅花落如積，吐鮫斕斑竹茹赤。", "祝陵有酒清若空，煮糯蒸魚作寒食。", "長橋新晴好天氣，兩市兒郎櫂船戲。", "溪頭饒鼓狂殺儂，青蓋紅裙偶相值。", "風光何處最可憐，邵家高樓白日邊。", "樓下遊人顔色喜，溪南黄帽應羞死。", "三月未有二月殘，靈龜可信渰水乾。", "葑草青青促歸去，短蕭橫笛說明年。"]'),
('6285d80a-aba6-4d30-9394-fb8915cfb0eb','壽張教授','陳克','宋','宋诗','song-poetry','','[]','玉府多應惜謫仙，紫皇留戀到殘年。',64,'全唐诗/poet.song.85000.json','["玉府多應惜謫仙，紫皇留戀到殘年。", "畫眉京溜風流在，借箸先生節概全。", "祿比書辭增百萬，壽如門弟及三千。", "互鄉不解華祝封，只誦天長地久篇。"]'),
('81dee17c-f8b0-4a4f-b8fa-2ce2b6215b20','遊善權山留題三首 乾洞','陳克','宋','宋诗','song-poetry','','[]','神仙何時開，中虛仰縈盤。',120,'全唐诗/poet.song.85000.json','["神仙何時開，中虛仰縈盤。", "呀然九地低，怪此天壤寬。", "窈窅闢瓊戶，璁瓏綴珠鬘。", "陰道差險絕，真形謝雕剜。", "閬風安在哉，突兀浮雲端。", "天高鬼神惡，欲往良獨難。", "空飛遽未暇，穴處如何安。", "相將三重茅，勢面玄都壇。", "仙田滿嘉植，玉彩長闌干。", "心空腹自實，寧計米鹽殘。"]'),
('6720826b-8307-4e85-bba4-9341016a413a','遊善權山留題三首 水洞','陳克','宋','宋诗','song-poetry','','[]','逶迤步哀壑，跼蹐生微瀾。',120,'全唐诗/poet.song.85000.json','["逶迤步哀壑，跼蹐生微瀾。", "慘慘白日暮，蕭蕭朱夏寒。", "崖傾勢方壯，石出水益湍。", "淙流響磬瑟，突起橫鏌干。", "微蹤乍渺茫，妙想忺盤桓。", "我今人世間，所向行路難。", "如何洞宮脚，危磴仍屈蟠。", "神傷阻獨往，髪竪兩股酸。", "了知仙凡隔，坐惜歲月殘。", "心違淚交墮，已去猶長嘆。"]'),
('12ad8c95-f758-4f54-b954-13ce8644a5a1','遊善權山留題三首 寺後湫水','陳克','宋','宋诗','song-poetry','','[]','岡巒誰穿空，脈液互吞吐。',120,'全唐诗/poet.song.85000.json','["岡巒誰穿空，脈液互吞吐。", "憑虛倚翠巖，發地涵潼乳。", "哀絃響崖寺，清鏡照林塢。", "縈坻驟曲折，嚙石猶飛舞。", "津涯浩無窮，神怪傳自古。", "參差見坤軸，晃蕩連水府。", "微生寄荒絕，多病厭鹹苦。", "永懷宅清泠，戮力事農圃。", "青秧漸出水，紫筍新過雨。", "無慚種秫陶，更似煎茶羽。"]'),
('c74d8264-6f99-4d7b-8530-ff09b5c77a93','返魂梅次蘇藉韻  其一','陳克','宋','宋诗','song-poetry','','[]','誰道春歸無覓處，眠齋香霧作春昏。',32,'全唐诗/poet.song.85000.json','["誰道春歸無覓處，眠齋香霧作春昏。", "君詩似說江南信，試與梅花招斷魂。"]'),
('18fd88ce-932f-42ff-93ac-b7c4298df553','返魂梅次蘇藉韻  其二','陳克','宋','宋诗','song-poetry','','[]','花開莫奏傷心曲，花落休矜稱面妝。',32,'全唐诗/poet.song.85000.json','["花開莫奏傷心曲，花落休矜稱面妝。", "只憶夢爲蝴蝶去，香雲密處有春光。"]'),
('355f034f-13bb-4ecc-afc3-7043c45a0108','返魂梅次蘇藉韻  其三','陳克','宋','宋诗','song-poetry','','[]','老夫粥後惟耽睡，灰暖香濃百念消。',32,'全唐诗/poet.song.85000.json','["老夫粥後惟耽睡，灰暖香濃百念消。", "不學朱門貴公子，鴨爐煙裏逞風標。"]'),
('3abc4224-54e9-4ed2-be88-8e23e1c899dc','返魂梅次蘇藉韻  其四','陳克','宋','宋诗','song-poetry','','[]','鼻根無奈重煙繞，偏處春隨夜色勻。',32,'全唐诗/poet.song.85000.json','["鼻根無奈重煙繞，偏處春隨夜色勻。", "眼裏狂花開底事，依然看作一枝春。"]'),
('33fda902-1fcd-4fb8-bf41-a47a02273489','返魂梅次蘇藉韻  其五','陳克','宋','宋诗','song-poetry','','[]','漫道君家四壁空，衣篝沈水晚朦朧。',32,'全唐诗/poet.song.85000.json','["漫道君家四壁空，衣篝沈水晚朦朧。", "詩情似被花相惱，入我香奩境界中。"]'),
('7c8940c7-c1b5-48b1-ad5b-d3f0b92c96b5','句  其一','陳克','宋','宋诗','song-poetry','','[]','鳥聲妨客夢，花片攪春心。',12,'全唐诗/poet.song.85000.json','["鳥聲妨客夢，花片攪春心。"]'),
('38fcdcc0-241b-47e6-933b-12abff76fdab','句  其二','陳克','宋','宋诗','song-poetry','','[]','易照水姿容，非復我登樓。',12,'全唐诗/poet.song.85000.json','["易照水姿容，非復我登樓。"]'),
('0ea42b85-1097-4bed-b731-c4df001389a0','句  其三','陳克','宋','宋诗','song-poetry','','[]','徘徊臨北顧，慷慨俯東流。',12,'全唐诗/poet.song.85000.json','["徘徊臨北顧，慷慨俯東流。"]'),
('7fa76ba5-d4c4-42f2-9fb0-5dec2738e469','句  其四','陳克','宋','宋诗','song-poetry','','[]','淚眼生憎好天色，離觴偏觸病心情。',16,'全唐诗/poet.song.85000.json','["淚眼生憎好天色，離觴偏觸病心情。"]'),
('c3360d62-4614-4108-9435-76a978a37b8e','句  其五','陳克','宋','宋诗','song-poetry','','[]','莫向邊鴻問消息，斷腸書信不如無。',16,'全唐诗/poet.song.85000.json','["莫向邊鴻問消息，斷腸書信不如無。"]'),
('c53f226c-efe4-44f7-96dc-49875d8a442c','句  其六','陳克','宋','宋诗','song-poetry','','[]','小楫登魚蟹，平原聚鳥烏。',12,'全唐诗/poet.song.85000.json','["小楫登魚蟹，平原聚鳥烏。"]'),
('d32f206d-fe05-4d20-a043-bb568d99e75b','句  其七','陳克','宋','宋诗','song-poetry','','[]','俯臨鐵甕重城迥，遠接金陵勝氣來。',16,'全唐诗/poet.song.85000.json','["俯臨鐵甕重城迥，遠接金陵勝氣來。"]'),
('a382ee0e-ca8b-470b-a866-9edeb1f88168','句  其八','陳克','宋','宋诗','song-poetry','','[]','北固天下奇，憑虛倚樓堞。',24,'全唐诗/poet.song.85000.json','["北固天下奇，憑虛倚樓堞。", "大江走天去，控以高崨嶪。"]'),
('6ca0ae5c-eb0e-44d0-a4ec-aaa094277a3a','句  其九','陳克','宋','宋诗','song-poetry','','[]','君今向姑孰，山好江漫漫。',24,'全唐诗/poet.song.85000.json','["君今向姑孰，山好江漫漫。", "炯如謫仙人，千載欣復還。"]'),
('0e5581fe-6dd1-4047-93f8-c689ecc50752','句  其一○','陳克','宋','宋诗','song-poetry','','[]','渺渺大江流。',6,'全唐诗/poet.song.85000.json','["渺渺大江流。"]'),
