('a79085e6-04db-481e-afef-b8da911cb35e','句  其二五','陳克','宋','宋诗','song-poetry','','[]','莫嘆勞生三十九。',8,'全唐诗/poet.song.85000.json','["莫嘆勞生三十九。"]'),
('0f175a49-9112-44cd-a9ba-b8a3d339994a','句  其二六','陳克','宋','宋诗','song-poetry','','[]','老去光陰非我春。',8,'全唐诗/poet.song.85000.json','["老去光陰非我春。"]'),
('96591372-ab94-46a4-b56d-b5efeae97113','句  其二七','陳克','宋','宋诗','song-poetry','','[]','角中飄去凄於骨，笛裏吹來妙入神。',16,'全唐诗/poet.song.85000.json','["角中飄去凄於骨，笛裏吹來妙入神。"]'),
('729bd7c6-db31-4554-96a2-c001937ff78a','句  其二八','陳克','宋','宋诗','song-poetry','','[]','愁眼不供千樹雪，醉頭猶奈一枝春。',16,'全唐诗/poet.song.85000.json','["愁眼不供千樹雪，醉頭猶奈一枝春。"]'),
('a130641c-d781-4892-8f6b-3e5c15f22520','句  其二九','陳克','宋','宋诗','song-poetry','','[]','濛濛清露濯幽葩，醉質斕斑襯曉霞。',16,'全唐诗/poet.song.85000.json','["濛濛清露濯幽葩，醉質斕斑襯曉霞。"]'),
('4d488fb7-9a4a-4ace-94bf-9384dee1470d','句  其三○','陳克','宋','宋诗','song-poetry','','[]','顧我從來貧到骨，經營藜藿亦艱辛。',16,'全唐诗/poet.song.85000.json','["顧我從來貧到骨，經營藜藿亦艱辛。"]'),
('0552a009-c2fd-4f4c-8f53-7fbf126f7ff9','句  其三一','陳克','宋','宋诗','song-poetry','','[]','樓下旌旗五丈餘，府中賢尹計魁梧。',16,'全唐诗/poet.song.85000.json','["樓下旌旗五丈餘，府中賢尹計魁梧。"]'),
('573a8d26-63a8-45a6-8729-bcdb6455356e','德清龜谿亭遇大雨','孫覿','宋','宋诗','song-poetry','','[]','崩雲四合千嶂重，奔電一掣十里紅。',160,'全唐诗/poet.song.85000.json','["崩雲四合千嶂重，奔電一掣十里紅。", "土囊叱吸萬竅風，江翻石走昏相蒙。", "疾雷破柱鞭老龍，百賈顛沛市井空。", "銀河倒傾千丈谼，魚鼈欲取山爲宫。", "洪濤舂天怒相攻，大舸吹簸如飛蓬。", "醉臥掀舞一葉中，洗我雲夢芥蒂胸。", "忽然變滅何匆匆，雷公收聲電改容。", "霞舒霧卷縈長虹，紺碧萬頃磨青銅。", "溪邊結網南巷翁，白髮黄馘射兩瞳。", "赤鱗騰出無留蹤，刻舟求劍何時逢。"]'),
('98bc67b0-b34f-46a5-818d-5c747f114a8c','湖州天寧寺飲王生二首  其一','孫覿','宋','宋诗','song-poetry','','[]','莫鬬蝸兩角，且共貉一邱。',48,'全唐诗/poet.song.85000.json','["莫鬬蝸兩角，且共貉一邱。", "夷踞坐我旁，汝豈河南騶。", "割肉一噉之，徐以大白浮。", "噲伍君勿譙，笑談起封侯。"]'),
('70f186a2-c662-4c96-a5cd-76d0df271d9c','湖州天寧寺飲王生二首  其二','孫覿','宋','宋诗','song-poetry','','[]','諸家迹便掃，得此一老兵。',48,'全唐诗/poet.song.85000.json','["諸家迹便掃，得此一老兵。", "江東醉司馬，酒中尚求名。", "哀哉南山萁，不平自號鳴。", "慎勿歌烏烏，作此老婢聲。"]'),
('1c502d45-6ca1-45cf-b3a1-1419e07aebf4','宿太湖口二首  其一','孫覿','宋','宋诗','song-poetry','','["\u592a\u6e56"]','誰令醉尉怒，端是丞相嗔。',48,'全唐诗/poet.song.85000.json','["誰令醉尉怒，端是丞相嗔。", "交疏白眼見，愁絕翠眉顰。", "遲暮仍三黜，驚窺有四鄰。", "還將萬里眼，笑索嶺梅春。"]'),
('58884d8e-2625-4c95-a5f6-7c50a16c07bf','宿太湖口二首  其二','孫覿','宋','宋诗','song-poetry','','["\u592a\u6e56"]','白首對瀧吏，騂汗愧逐臣。',48,'全唐诗/poet.song.85000.json','["白首對瀧吏，騂汗愧逐臣。", "溪山不改色，風雨解留人。", "坎壈知天意，漂浮任此身。", "紛紛小兒女，何必浪沾巾。"]'),
('6c023895-d9f4-41e4-a9f0-d8502fe38d49','宿太湖口二首  其三','孫覿','宋','宋诗','song-poetry','','["\u592a\u6e56"]','溺灰不辭戎辱，箕踞未易訶。',49,'全唐诗/poet.song.85000.json','["溺灰不辭戎辱，箕踞未易訶。", "僅免遭田甲，誰能讓尉佗。", "輿糧餞吾鬼，分燈遣諸魔。", "酒中有真覺，一夢到無何。"]'),
('c75751be-71d5-48fe-b1b0-88ee873491bd','餘杭聞出師','孫覿','宋','宋诗','song-poetry','','[]','國蹙連羣盜，時危仗老臣。',48,'全唐诗/poet.song.85000.json','["國蹙連羣盜，時危仗老臣。", "分憂當北顧，請幸且東巡。", "肘足儀三晉，創痍又一秦。", "不眠聽野哭，愁殺路傍人。"]'),
('c4a86d9a-855d-4bf2-937e-e3742ba0864a','富陽道中二首  其一','孫覿','宋','宋诗','song-poetry','','[]','渺渺行雲幔，溶溶曳水衣。',48,'全唐诗/poet.song.85000.json','["渺渺行雲幔，溶溶曳水衣。", "雷翻巢墮乳，風落網粘飛。", "獨拄青藜杖，來推白板扉。", "平生邱壑趣，漂泊寸心違。"]'),
('a6d79da5-dfb1-426d-846d-d1d294fce105','富陽道中二首  其二','孫覿','宋','宋诗','song-poetry','','[]','白帽炎州客，青裙酒姥家。',48,'全唐诗/poet.song.85000.json','["白帽炎州客，青裙酒姥家。", "微風搖扇浪，細雨落簷花。", "客舍休占鵩，蠻村欲饌蛇。", "會令醒復醉，高枕送生涯。"]'),
('b6b28029-77a5-49af-88e0-ce9b842ca11a','桐廬連夕大雨溪漲數十丈徙寓白塔山上方閣','孫覿','宋','宋诗','song-poetry','','[]','蒼莽川流會，渾酣海氣嘘。',72,'全唐诗/poet.song.85000.json','["蒼莽川流會，渾酣海氣嘘。", "蛟龍改窟宅，雷電走空虛。", "殷地翻坤軸，黏天浸日車。", "高僧欲杯度，遊客且樓居。", "壯觀真難值，幽懷亦少攄。", "翩翩一鳥去，何必羨知魚。"]'),
('cc73b0cc-3976-4c07-a7c3-f10785f56a3f','水退','孫覿','宋','宋诗','song-poetry','','[]','蕩沃波瀾大，憑陵意氣粗。',72,'全唐诗/poet.song.85000.json','["蕩沃波瀾大，憑陵意氣粗。", "射潮鮫鰐怒，鞭石鬼神驅。", "雲斷千崖立，風行萬壑趨。", "檣烏朝共起，水鳥夜仍呼。", "灧灧紅升曉，霏霏翠撲膚。", "浮楂臥泥滓，狼藉滿街衢。"]'),
('7bc5c6c1-3cac-4ae9-b21f-75764b09c3d7','胥口','孫覿','宋','宋诗','song-poetry','','[]','江闊臥人影，山長送馬蹄。',48,'全唐诗/poet.song.85000.json','["江闊臥人影，山長送馬蹄。", "渚蓮紅尚斂，沙草翠相迷。", "高樹藏雲直，疏篁壓雨低。", "酒醒渾不記，端是武陵谿。"]'),
('1ade2be2-6ee0-466c-9349-6b2117b91243','釣臺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','北塞風塵萬鼓鼙，東京社稷一戎衣。',64,'全唐诗/poet.song.85000.json','["北塞風塵萬鼓鼙，東京社稷一戎衣。", "綠林羣盜驅民去，赤伏真人得帝歸。", "諸老禪聯蒼玉佩，將軍坐鞚紫金鞿。", "先生此日青霞志，一笑凌空拄杖飛。"]'),
('4bb99536-31c3-44af-90ac-179f731339c0','釣臺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','故人遺像丹青落，蓋代榮名日月懸。',64,'全唐诗/poet.song.85000.json','["故人遺像丹青落，蓋代榮名日月懸。", "萬馬羣空冀北野，一蛇獨遊原上田。", "晚浦蒼波涵落日，秋崖老樹立蒼煙。", "直從厭代騎星去，千歲光芒夜斗邊。"]'),
('a37971a8-ba8c-4e4f-9679-d37dc5210187','蘭溪津亭病起二首  其一','孫覿','宋','宋诗','song-poetry','','[]','離亂紛紛醉尉多，將軍獨夜灞亭過。',64,'全唐诗/poet.song.85000.json','["離亂紛紛醉尉多，將軍獨夜灞亭過。", "旅巢對鵩占行役，客爼懸蛇臥宿痾。", "雙鬢盡從愁裏白，衰顔時向酒中酡。", "雲翻雨覆須臾耳，未用區區較唯阿。"]'),
('621d7e53-26d3-42b1-8383-9dc71490c278','蘭溪津亭病起二首  其二','孫覿','宋','宋诗','song-poetry','','[]','風波湧地千漚發，創痏鑽皮百箭攻。',64,'全唐诗/poet.song.85000.json','["風波湧地千漚發，創痏鑽皮百箭攻。", "藥裹關心防二豎，謗書盈篋忤三蟲。", "剖瓜女隸方求巧，結柳奴星也送窮。", "笑我平生持蟹手，未應咄咄左書空。"]'),
('55f9e1a8-3ce0-47cf-af08-debce7ba7f6a','三衢聞都督兵潰常潤間懷舍弟而下','孫覿','宋','宋诗','song-poetry','','[]','紫荆有信欲開花，黄犬無情不到家。',64,'全唐诗/poet.song.85000.json','["紫荆有信欲開花，黄犬無情不到家。", "偶坐厭聞鳥嚄嚄，杯行喜聽鵲查查。", "同看明月人千里，相望孤雲海一涯。", "驥子熊兒無恙否，風雲慘澹鬬龍蛇。"]'),
('9921a193-fc28-4247-b928-c8ae0260236a','月巖寺寺有巖石高數十丈一穴中空如半月狀號半月巖','孫覿','宋','宋诗','song-poetry','','[]','老蟆蝕月缺，破鏡擲道邊。',48,'全唐诗/poet.song.85000.json','["老蟆蝕月缺，破鏡擲道邊。", "金樞壞一夕，玉斧斵千年。", "何人挾寸鐵，插羽飛上天。", "但令蟆磔死，重看十分圓。"]'),
('6e093baa-0f0f-405c-8669-002c3c2c027a','立秋饒陽道中三首  其一','孫覿','宋','宋诗','song-poetry','','[]','殘夜山月吐，蓐食治野裝。',48,'全唐诗/poet.song.85000.json','["殘夜山月吐，蓐食治野裝。", "策策林響變，一葉風隕黄。", "客路感時節，起看雁南翔。", "秋風捩孤影，雲路正茫茫。"]'),
('1d60f249-d233-4b82-b84d-219db2355a85','立秋饒陽道中三首  其二','孫覿','宋','宋诗','song-poetry','','[]','老馬倦長道，解鞍聊緩觴。',48,'全唐诗/poet.song.85000.json','["老馬倦長道，解鞍聊緩觴。", "小雨濯鬢須，欣然愜初涼。", "奇苞照屋角，橘柚垂青黄。", "感之動中懷，弓刀戒秋防。"]'),
('c0a9a617-a3d6-4441-8f12-a0bace12361e','立秋饒陽道中三首  其三','孫覿','宋','宋诗','song-poetry','','[]','竄身楚南極，守隸工遮防。',48,'全唐诗/poet.song.85000.json','["竄身楚南極，守隸工遮防。", "投鞭得小愒，孚席紛在旁。", "虎賁起隅坐，悠然見中郎。", "一醉汩其泥，江湖渺相忘。"]'),
('8452ff49-c248-4779-87d9-4370199db963','弋陽縣古葛陂也縣有古刹臨大溪相傳云佛圖澄浣腸故地','孫覿','宋','宋诗','song-poetry','','[]','古道陰森翠柏行，長鞭搖曳紫游韁。',96,'全唐诗/poet.song.85000.json','["古道陰森翠柏行，長鞭搖曳紫游韁。", "佩鳴蒼玉傾瑤席，地布黄金列寶坊。", "仙客杖飛龍有角，胡僧腸浣水生光。", "兩朝人物空冥寞，百代風流競淼茫。", "松骨倚天増老氣，谿毛著水渡微香。", "鴉啼鵲噪秋風外，千丈藤蘿掛夕陽。"]'),
('d68cc3db-62aa-4adf-9a33-c933e4a9f17b','過安仁縣權令主簿同蔡尉見訪二首  其一','孫覿','宋','宋诗','song-poetry','','[]','莽莽纒兵氣，蓬茅庇一邱。',48,'全唐诗/poet.song.85000.json','["莽莽纒兵氣，蓬茅庇一邱。", "尚看蒙赤幘，不復臥黄紬。", "抱牘杭鳧鶩，徵租聚沐猴。", "黄昏更蕭瑟，風雨嘯鵂鶹。"]'),
('51948524-e568-4810-8254-a245d581b197','過安仁縣權令主簿同蔡尉見訪二首  其二','孫覿','宋','宋诗','song-poetry','','[]','投老一浮萍，長亭復短亭。',48,'全唐诗/poet.song.85000.json','["投老一浮萍，長亭復短亭。", "誰憐仙客去，自有故人經。", "世亂眉多赤，情高眼獨青。", "臨分聽苦語，令我醉時醒。"]'),
('cc01429e-10dc-4d1d-a8c3-6821f71dffe6','宿臨川村舍','孫覿','宋','宋诗','song-poetry','','[]','林壑已秋聲，涼蟬又一鳴。',48,'全唐诗/poet.song.85000.json','["林壑已秋聲，涼蟬又一鳴。", "人間多古意，地僻有微行。", "身老殊方去，愁牽百慮生。", "途人夜相語，豺虎正縱横。"]'),
('28e224fa-0682-4a12-abff-c27758f59b1d','題臨川孝義寺壁二首  其一','孫覿','宋','宋诗','song-poetry','','[]','秋風嫋嫋轉庭梧，客夢初驚一鳥呼。',32,'全唐诗/poet.song.85000.json','["秋風嫋嫋轉庭梧，客夢初驚一鳥呼。", "揀盡寒枝棲不穩，獨行殘夜影同孤。"]'),
('bd879f4c-d51f-4f9a-be63-baceb748aa91','題臨川孝義寺壁二首  其二','孫覿','宋','宋诗','song-poetry','','[]','孤城吹角五更風，笑語團圞一夢中。',32,'全唐诗/poet.song.85000.json','["孤城吹角五更風，笑語團圞一夢中。", "戰格連雲家萬里，書憑黄犬若爲通。"]'),
('0980da75-6948-4fc3-859f-f0831977a49b','疏山寺次白文林韻三首  其一','孫覿','宋','宋诗','song-poetry','','[]','翠幹軒軒迥出林，夜風吹籟紫簫音。',64,'全唐诗/poet.song.85000.json','["翠幹軒軒迥出林，夜風吹籟紫簫音。", "老龍頭角雲霄近，玄豹文章霧雨深。", "末路浮榮炊劍首，半生遺恨寄琴心。", "愁吟獨濺花前淚，故國山河百戰侵。"]'),
('6de3d8c4-198a-46c3-9d0a-0c2992ef2979','疏山寺次白文林韻三首  其二','孫覿','宋','宋诗','song-poetry','','[]','藜杖匆匆集晚林，長廊破壁撼鐘音。',64,'全唐诗/poet.song.85000.json','["藜杖匆匆集晚林，長廊破壁撼鐘音。", "天涯流落相逢地，杯酒殷勤莫厭深。", "萬里功名飛燕頷，千金博飲炙牛心。", "更聞好句驚人倒，一洗蠻煙瘴霧侵。"]'),
('7676ce22-4951-4e19-ba50-4f565fa99497','疏山寺次白文林韻三首  其三','孫覿','宋','宋诗','song-poetry','','[]','黄花翠竹小叢林，臥聽南山白石音。',64,'全唐诗/poet.song.85000.json','["黄花翠竹小叢林，臥聽南山白石音。", "螘鬬已空遺垤在，蝸跧終戀故廬深。", "掀髯一笑追前謬，禮足同參看此心。", "且向疏山結香火，人生莫受二毛侵。"]'),
('d102639f-2443-433c-a910-e8bcf63a6e8b','疏山長老善清日誦楞嚴維摩二經賦小詩二首示之  其一','孫覿','宋','宋诗','song-poetry','','[]','塵漲迷三鹿，桑枯厭八蠶。',48,'全唐诗/poet.song.85000.json','["塵漲迷三鹿，桑枯厭八蠶。", "徵心渾不見，問疾有誰堪。", "坐待成風斵，應須立雪參。", "欽聞第一義，細說後三三。"]'),
('07fd4948-29ff-4457-888d-91c8bec4d819','疏山長老善清日誦楞嚴維摩二經賦小詩二首示之  其二','孫覿','宋','宋诗','song-poetry','','[]','彈指三生過，傷心一念差。',48,'全唐诗/poet.song.85000.json','["彈指三生過，傷心一念差。", "試標天上月，爲種火中花。", "粗識禪爲味，初欣道有牙。", "老師一笑許，千劫誤蒸砂。"]'),
('ae33a388-de26-4ec8-a732-b9ffb27497e9','明水寺五代末危全諷據臨川時所建畫像至今存焉寺旁最高峰有祠屋一區道士居之二首  其一','孫覿','宋','宋诗','song-poetry','','[]','臺殿何年有，千巖紫翠間。',48,'全唐诗/poet.song.85000.json','["臺殿何年有，千巖紫翠間。", "金仙佛世界，羽客道家山。", "骨朽餘三窟，皮存尚一斑。", "傷心千古淚，相見雨潺潺。"]'),
('1a5fb369-7e20-403b-ad68-2af57d907a8a','明水寺五代末危全諷據臨川時所建畫像至今存焉寺旁最高峰有祠屋一區道士居之二首  其二','孫覿','宋','宋诗','song-poetry','','[]','愁坐猿啼裏，行吟度鳥間。',48,'全唐诗/poet.song.85000.json','["愁坐猿啼裏，行吟度鳥間。", "翠凋巾上髮，紅破鏡中顔。", "老去經三折，真游付八還。", "無心自來往，空羨白雲閑。"]'),
('38737d04-3af9-4d07-bc0b-2c17823201a6','崇仁縣','孫覿','宋','宋诗','song-poetry','','[]','萬山攢擁天一笠，北風吹雨兩鬢濕。',128,'全唐诗/poet.song.85000.json','["萬山攢擁天一笠，北風吹雨兩鬢濕。", "饑烏絕叫護巢飛，老蛟怒起拏雲立。", "孤城短日砧杵急，騎驢渺渺衝泥入。", "桑枝倒折機杼空，道旁廢井無人汲。", "遺民到今傳舊邑，擊水華鯨浪三級。", "故物漂流百戰餘，客子起坐萬感集。", "小驛香醪如雪汁，一杯快作長虹吸。", "酒醒寂歷照短檠，幽咽數聲鄰婦泣。"]'),
('f7ff8c25-8c1d-427f-a9f4-a07d8da7a6ff','余南遷次臨川奏廬陵道属聞盜掠高安新淦之間少留仙遊山道祠是時庭下木犀花盛開漫山皆大松一峰蒼然終日遊愒其下各賦詩一篇  其一','孫覿','宋','宋诗','song-poetry','','[]','簷牙啄林杪，華殿浮青紅。',96,'全唐诗/poet.song.85000.json','["簷牙啄林杪，華殿浮青紅。", "天風吹泬寥，萬籟酣笙鏞。", "木犀已著花，濯濯秋雨中。", "赬姿出素面，一洗丹粉空。", "幽香襲巾袂，冷艷棲房櫳。", "迫此芳歲殘，一笑誰當供。", "羣仙立通明，矯矯驂鸞龍。", "相隨歸閬苑，遺恨寄西風。"]'),
('eecaf4cd-fefa-499b-bb99-125918f8c2ab','余南遷次臨川奏廬陵道属聞盜掠高安新淦之間少留仙遊山道祠是時庭下木犀花盛開漫山皆大松一峰蒼然終日遊愒其下各賦詩一篇  其二','孫覿','宋','宋诗','song-poetry','','[]','歷歷水中榆，地遠連玉京。',96,'全唐诗/poet.song.85000.json','["歷歷水中榆，地遠連玉京。", "掄材上華屋，裊裊黄金莖。", "蒼官表獨立，垂胡交縵纓。", "根深崖嶠壯，勢壓山岳傾。", "萬牛挽不回，老氣空峥嶸。", "夜半風雨會，歲晚龍蛇升。", "我來不忍去，繞樹三匝行。", "珍重金石交，待我烹茯苓。"]'),
('d1c456e5-9261-4cf4-acf6-cddf547bdcc4','遣興','孫覿','宋','宋诗','song-poetry','','[]','亂後煎百慮，老去無一欣。',48,'全唐诗/poet.song.85000.json','["亂後煎百慮，老去無一欣。", "故人尺書至，好語中夜聞。", "坐久百蟲絕，開簾月紛紛。", "長歌又一醉，酒醒擊空尊。"]'),
('3de7d991-8368-4f5a-a3b0-081eb00bb110','題華蓋仙亭大松示柳道士','孫覿','宋','宋诗','song-poetry','','[]','繫舟古巴江，曳杖真仙亭。',96,'全唐诗/poet.song.85000.json','["繫舟古巴江，曳杖真仙亭。", "金輿簇畫戟，玉几羅翠屏。", "堂堂十八公，獨立霜中英。", "魁然十圍大，蔭此一蓋青。", "翹翹雲物外，坐閲秋蒂零。", "道人依茅棟，蕙帳淒芳馨。", "苓龜儻可見，長鑱斸青冥。", "一食浣我腸，敗履插修翎。"]'),
('fa99de5c-84c8-4377-a2e1-b0dfdd820c4a','仙遊山九日歎逝二首  其一','孫覿','宋','宋诗','song-poetry','','[]','傷心玉案兩眉齊，永負黄花九日期。',64,'全唐诗/poet.song.85000.json','["傷心玉案兩眉齊，永負黄花九日期。", "萬里炎州嗟我老，百年青淚向君垂。", "俱飛蛺蜨愁看汝，醉把茱萸欲對誰。", "獨立西風搔短髪，一生遺恨一愁悲。"]'),
('19f504d5-05dc-4056-a5f4-0e851c588fe6','仙遊山九日歎逝二首  其二','孫覿','宋','宋诗','song-poetry','','[]','割肉早歸三伏日，傳柑賜飲上元燈。',64,'全唐诗/poet.song.85000.json','["割肉早歸三伏日，傳柑賜飲上元燈。", "那知一慟殊方去，獨向高臺此日登。", "淚溼西風生眼纈，夢回殘夜起衣稜。", "孤鸞别鵠知何處，泉路茫茫喚不應。"]'),
('aa3390db-8629-4de9-b7bf-9ef077223fdc','達臣議承餉石耳','孫覿','宋','宋诗','song-poetry','','[]','窮秋客舍風雨淒，破釜生魚甑有衣。',64,'全唐诗/poet.song.85000.json','["窮秋客舍風雨淒，破釜生魚甑有衣。", "故侯未種東陵瓜，餓夫欲采西山薇。", "歲晚黄精可療饑，故園萬里天一涯。", "未辨登山拾瑤草，且復從公茹石芝。"]'),
('f7eb4b25-1483-4ad6-b2eb-850bf5a9a3db','山行憩田舍老父出迎以黄柑白酒爲餉','孫覿','宋','宋诗','song-poetry','','[]','藜杖扶來雪滿簪，諄諄好語意深深。',64,'全唐诗/poet.song.85000.json','["藜杖扶來雪滿簪，諄諄好語意深深。", "酒傾白墮杯行玉，橘破黄苞坐飣金。", "醉起莫辭田父肘，甘餘須識野人心。", "匆匆不盡遮留意，挽袖丁寧更一臨。"]'),
('4ac6b88a-27dc-4b16-a2a1-864f9ca1c55d','兩日復往次前韻','孫覿','宋','宋诗','song-poetry','','[]','寒蔬離離銀綫亂，凍醴灧灧玉井深。',64,'全唐诗/poet.song.85000.json','["寒蔬離離銀綫亂，凍醴灧灧玉井深。", "坐看庭松翹翠蓋，行穿野菊布黄金。", "犬迎客入喜見尾，鵲隨人語欣會心。", "俗裏淹留怕轑釜，驅兒招喚得重臨。"]'),
('01f80af5-c1e0-4d0a-baad-42df27c19cbd','曹山寺','孫覿','宋','宋诗','song-poetry','','[]','石棧梯空一綫横，路窮臺殿兩崢嶸。',128,'全唐诗/poet.song.85000.json','["石棧梯空一綫横，路窮臺殿兩崢嶸。", "日光澹澹鳥飛沒，雲氣茫茫龍隨行。", "道人西歸餘隻履，結茅宴坐千巖底。", "草根瀝瀝暗泉鳴，樹外騰騰青瘴起。", "翠竹掩冉蒼雲屯，老藤蔽虧白晝昏。", "天低尺五雷雨上，身强丈六祖佛尊。", "我老栖栖厭行旅，逢人欲問前三語。", "不見高僧錫杖飛，山下空留千斛乳。"]'),
('e13a7984-0c85-44d9-bee4-37234ea4e348','贈曹山長老了如','孫覿','宋','宋诗','song-poetry','','[]','一念挂世網，平生誤儒冠。',120,'全唐诗/poet.song.85000.json','["一念挂世網，平生誤儒冠。", "笑看蠅穴紙，坐待鮎緣竿。", "薨薨醯醬瓿，豈識天壤寛。", "老如本逢掖，詩肩尚儒酸。", "久纒冠蓋蔓，忽作泡影觀。", "堂堂人天師，三世一指彈。", "身閑雲月出，骨老霜松寒。", "我生飽憂患，將心覓人安。", "目擊有妙寄，語樂非世歡。", "坐穩且復留，火芋分懶殘。"]'),
('929833cf-5cb6-4687-9582-9077265fae76','送僧妙鑑住廣壽寺','孫覿','宋','宋诗','song-poetry','','[]','明月不可呼，清夜時一出。',72,'全唐诗/poet.song.85000.json','["明月不可呼，清夜時一出。", "孤光掛海涯，皎皎轉空碧。", "道人一茅把，坐睨九年壁。", "磨磚破纒縛，驟若老驥逸。", "匆匆林下逢，悵望不暖席。", "錫杖已凌空，階庭草如積。"]'),
('2352293c-4469-43e5-8d33-c20010980d43','明水逵老以黄甘荔子土芋爲餉小詩答謝','孫覿','宋','宋诗','song-poetry','','[]','客居莽牢落，幽絕無四鄰。',120,'全唐诗/poet.song.85000.json','["客居莽牢落，幽絕無四鄰。", "歲窮有衣結，日晏猶甑塵。", "偪仄戎馬間，敢厭薪水勤。", "故人情義重，采采青泥芹。", "小摘持寄遠，分餘爲情親。", "丹荔擘輕圓，黄柑破芳辛。", "蹲鴟勸加餐，風味亦可人。", "渺渺山澗曲，浩浩水雲晨。", "踞罏有前諾，兩翁對然薪。", "眼纈眩紅綠，共此無邊春。"]'),
('e161e0e3-a802-4747-8e25-869dbea2b6f5','次韻王子欽立春二首  其一','孫覿','宋','宋诗','song-poetry','','[]','玉手傳絲催歲，金刀翦綵伴春回。',63,'全唐诗/poet.song.85000.json','["玉手傳絲催歲，金刀翦綵伴春回。", "兵戈滿眼年年在，花鳥驚心日日來。", "芳意漸還三徑草，暗香猶認兩京梅。", "呼童火急供春事，凍醴生光灧玉醅。"]'),
('ed95535a-72dd-4003-b71e-249211e8e024','次韻王子欽立春二首  其二','孫覿','宋','宋诗','song-poetry','','[]','歲晚驚呼身已老，天涯流落首空回。',64,'全唐诗/poet.song.85000.json','["歲晚驚呼身已老，天涯流落首空回。", "便將酒力推愁去，且放春光入眼來。", "人語嘻嘻爭鬬草，宫花閃閃艷妝梅。", "雪消水暖春江動，綠漲葡萄萬斛醅。"]'),
('e25ca1d8-0ab3-4a26-816b-94aa9794a2f6','東塔六言二首  其一','孫覿','宋','宋诗','song-poetry','','[]','翠竹含風嫋嫋，青山照水重重。',28,'全唐诗/poet.song.85000.json','["翠竹含風嫋嫋，青山照水重重。", "窗户無人半掩，一龕香霧空濛。"]'),
('1ce29dfb-6e9a-45d5-9e4b-fb0d0e2e2f4d','東塔六言二首  其二','孫覿','宋','宋诗','song-poetry','','[]','偶與白雲共出，忽隨倦鳥俱還。',28,'全唐诗/poet.song.85000.json','["偶與白雲共出，忽隨倦鳥俱還。", "明日重尋舊路，桃花流水空山。"]'),
('2537b6d5-d942-498a-a50b-652fa4299af7','遊東塔雨中夜歸二首  其一','孫覿','宋','宋诗','song-poetry','','[]','山氣濛鴻衣自濕，意行曳杖穿雲入。',64,'全唐诗/poet.song.85000.json','["山氣濛鴻衣自濕，意行曳杖穿雲入。", "老翠陰森萬竹蟠，浮蒼瀲灧千峰立。", "邂逅幽尋到蕭寺，拊掌一笑掀百蟄。", "酒醒佛火照黄昏，坐聽北窗風雨集。"]'),
('0d6b15b1-d211-49e6-b187-8d3c479c3ef6','遊東塔雨中夜歸二首  其二','孫覿','宋','宋诗','song-poetry','','[]','山色凌寒春尚瘦，潭影涵空清可漱。',64,'全唐诗/poet.song.85000.json','["山色凌寒春尚瘦，潭影涵空清可漱。", "漠漠雲行紫竹閑，斑斑雨溼黄昏後。", "火炬穿林鳥出巢，人語闐門狗窺竇。", "杖藜有興會重來，更待黄鸝哢晴晝。"]'),
('2aaf4264-ce3d-49a6-b7d5-b00f0b6e5340','次韻王子欽春望二首  其一','孫覿','宋','宋诗','song-poetry','','[]','王孫春望思寥寥，冠蓋當年盛八蕭。',64,'全唐诗/poet.song.85000.json','["王孫春望思寥寥，冠蓋當年盛八蕭。", "花靨重重牆外見，琴心切切酒中招。", "屠龍已破千金産，駟馬重歸萬里橋。", "便解貉裘沽一醉，忍看紅糝綴寒條。"]'),
('577a3c36-2ffa-420f-a3ac-06f324d0c752','次韻王子欽春望二首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬木陰中鎖泬寥，晨門跋馬聽蕭蕭。',64,'全唐诗/poet.song.85000.json','["萬木陰中鎖泬寥，晨門跋馬聽蕭蕭。", "故人自欲分茵去，逐客何妨折簡招。", "共對春風班露草，却隨明月下溪橋。", "擊鮮故有諸郎在，三尺銀刀貫柳條。"]'),
('24168d14-e2de-42a5-82ee-4f479546315d','鄒次魏黄善長攜文見過小詩爲謝','孫覿','宋','宋诗','song-poetry','','[]','鄒郎英妙知名久，筆端自有談天口。',96,'全唐诗/poet.song.85000.json','["鄒郎英妙知名久，筆端自有談天口。", "客舍相逢一尊酒，衆星錯落見箕斗。", "高論欲追牛馬走，長劍忽作蛟龍吼。", "餘子碌碌那得交，江夏無雙亦其偶。", "我觀二妙屠龍手，青紫紛紛何足取。", "他年要作中興碑，大字磨崖繼聱叟。"]'),
('390f7548-eab7-45dc-ad4c-3481db42549b','癸丑寒食曹山飯僧荐章淑人不勝悼往之懷書二詩於方丈屋壁  其一','孫覿','宋','宋诗','song-poetry','','[]','川逝日已遠，蓬漂久未歸。',48,'全唐诗/poet.song.85000.json','["川逝日已遠，蓬漂久未歸。", "異鄉驚歲換，宿草變春暉。", "魂夢差參是，音容想像非。", "遙憐小兒女，慟哭紙錢飛。"]'),
('42684b63-cae5-4303-b9a8-9643029e04eb','癸丑寒食曹山飯僧荐章淑人不勝悼往之懷書二詩於方丈屋壁  其二','孫覿','宋','宋诗','song-poetry','','[]','草草木皮棺，松風生暮寒。',48,'全唐诗/poet.song.85000.json','["草草木皮棺，松風生暮寒。", "鶯啼春寂寂，螢照夜漫漫。", "夢裏號三匝，愁邊薦一簞。", "想思爲君瘦，零落带圍寛。"]'),
('a82f6722-6116-411e-9e68-ef1055ffd077','清明日與范季實諸人過胥澤民别墅小集二首  其一','孫覿','宋','宋诗','song-poetry','','[]','水滿雙飛白鷺，花深百囀黄鸝。',28,'全唐诗/poet.song.85000.json','["水滿雙飛白鷺，花深百囀黄鸝。", "寒食清明過了，一川煙草離離。"]'),
('0f79e63e-e39e-4b4c-a9af-b7c3222a47f7','清明日與范季實諸人過胥澤民别墅小集二首  其二','孫覿','宋','宋诗','song-poetry','','[]','兀兀三杯卬困，昏昏一枕春融。',28,'全唐诗/poet.song.85000.json','["兀兀三杯卬困，昏昏一枕春融。", "酒醒落花風裏，夢回啼鳥聲中。"]'),
('576684c8-3632-42d2-a4b8-c841fb3564d9','曹山春日二首  其一','孫覿','宋','宋诗','song-poetry','','[]','弱柳千絲颺，河横一带圍。',48,'全唐诗/poet.song.85000.json','["弱柳千絲颺，河横一带圍。", "腰支春作瘦，鱗甲雨生肥。", "逐伴魚兒出，爭巢燕子飛。", "匆匆班草地，不覺臥斜暉。"]'),
('09eeb794-efa3-4524-8fd5-0a2f30f1763d','曹山春日二首  其二','孫覿','宋','宋诗','song-poetry','','[]','屏擁山入坐，珠跳水濺裾。',48,'全唐诗/poet.song.85000.json','["屏擁山入坐，珠跳水濺裾。", "香銷塵漠漠，日近竹疏疏。", "身逢百罹後，春殘一夢餘。", "故林千嶂外，孤抱幾時攄。"]'),
('bd7389a4-6b46-4f90-a622-e51089611053','壁上人開軒闢地栽花種橘戲留小詩','孫覿','宋','宋诗','song-poetry','','[]','看雲隨臥起，飲水自敷腴。',48,'全唐诗/poet.song.85000.json','["看雲隨臥起，飲水自敷腴。", "秀色共齋鉢，寒聲落坐隅。", "未開花五葉，且種橘千株。", "幽事相關處，時來近酒壺。"]'),
('17381b42-27dc-4194-84b2-39d66e062ae3','春雨','孫覿','宋','宋诗','song-poetry','','[]','小雨破春昏，清風洗瘴氛。',48,'全唐诗/poet.song.85000.json','["小雨破春昏，清風洗瘴氛。", "霏微花上見，蕭瑟夜深聞。", "獨笑幽閑事，酣歌倚半醺。", "羈懷不堪寫，危坐聽爐芬。"]'),
('cf5438f3-a375-4eac-a874-9fb9a8caf573','春晚二首  其一','孫覿','宋','宋诗','song-poetry','','[]','花落不容惜，猶殘葉底春。',48,'全唐诗/poet.song.85000.json','["花落不容惜，猶殘葉底春。", "稀紅閃餘映，亂綠鬬尖新。", "飛絮高度竹，遊絲遠趁人。", "窺簾聞好語，雙鵲喜津津。"]'),
('84a239e0-758f-4aae-88cf-0404310f4562','春晚二首  其二','孫覿','宋','宋诗','song-poetry','','[]','殘尊斷送春，千里未歸身。',48,'全唐诗/poet.song.85000.json','["殘尊斷送春，千里未歸身。", "鶯老猶聞語，梅酸欲聚顰。", "獨眠愁警夜，起舞聽鳴晨。", "行路難如此，悠悠且傍人。"]'),
('93c4e8da-5c44-4d0a-bb9b-da176ab239a5','曹山三絕句  其一','孫覿','宋','宋诗','song-poetry','','[]','露宿風餐兩鬢華，故園蕪沒舊生涯。',32,'全唐诗/poet.song.85000.json','["露宿風餐兩鬢華，故園蕪沒舊生涯。", "聖恩若許求帷蓋，便向東陵學種瓜。"]'),
('739668b0-200f-429e-ad55-5d80dd4c25c8','曹山三絕句  其二','孫覿','宋','宋诗','song-poetry','','[]','竹杖芒鞋穩稱身，茸茸香草醉中茵。',32,'全唐诗/poet.song.85000.json','["竹杖芒鞋穩稱身，茸茸香草醉中茵。", "舉鞭叱馭何爲者，始信王陽是可人。"]'),
('7be791b9-6346-48ee-8233-c418a42d943c','曹山三絕句  其三','孫覿','宋','宋诗','song-poetry','','[]','毁瓦區區爲食謀，半生炊黍在刀頭。',32,'全唐诗/poet.song.85000.json','["毁瓦區區爲食謀，半生炊黍在刀頭。", "一廛會入扶犁手，不上陳登百尺樓。"]'),
('ccb85098-4846-4b13-8eda-be9a21ef9be7','有客生致兩雉不忍殺開籠縱之二首  其一','孫覿','宋','宋诗','song-poetry','','[]','平地安知禍有機，一跌永負青雲期。',64,'全唐诗/poet.song.85000.json','["平地安知禍有機，一跌永負青雲期。", "舉羣驚雊墮罝網，袞背煥爛光陸離。", "山梁三嗅不忍嘬，如皋一笑吁可悲。", "開籠放汝須遠去，莫遣韓公賦病鴟。"]'),
('0126ab17-b725-4129-8010-cf8fabbeb849','有客生致兩雉不忍殺開籠縱之二首  其二','孫覿','宋','宋诗','song-poetry','','[]','誰令孤鷕遂專埸，翦迭籠中看鳥翔。',64,'全唐诗/poet.song.85000.json','["誰令孤鷕遂專埸，翦迭籠中看鳥翔。", "文章正坐虎毛柄，鎩羽一落千丈强。", "翠翎低摧少顔色，奇禍非汝能遮防。", "匆匆應媒莫浪出，尊拳毒手正交相。"]'),
('78a8d2e0-5894-488e-9295-dd537a8d6fb3','題妙覺寺壁','孫覿','宋','宋诗','song-poetry','','[]','葉底紅稀不見花，枝頭綠暗可藏雅。',32,'全唐诗/poet.song.85000.json','["葉底紅稀不見花，枝頭綠暗可藏雅。", "春歸古殿蒼苔滿，一點籠燈隱絳紗。"]'),
('23ff20fe-bbaa-49ba-855a-d071e24f60aa','再至','孫覿','宋','宋诗','song-poetry','','[]','老眼逢春病有花，淋浪醉墨字如雅。',32,'全唐诗/poet.song.85000.json','["老眼逢春病有花，淋浪醉墨字如雅。", "懸知不是唐王播，慚愧高僧護碧紗。"]'),
('65dc17fe-173b-4f0b-804d-f625a85518b9','宿妙覺竹庵贈静老','孫覿','宋','宋诗','song-poetry','','[]','青山映落日，澹澹煙中明。',156,'全唐诗/poet.song.85000.json','["青山映落日，澹澹煙中明。", "出門無所投，曳杖隨意行。", "破裓僧兩三，喜笑争邀迎。", "曾巢俯修竹，飛星動高甍。", "老人如宿昔，真契同三生。", "遇人無戚疏，出語惡不情。", "寥寥風馬牛，肝胆欲盡傾。", "怪我胸中山，硉兀尚不平。", "邯鄲樂無度，短夢一餉榮。", "蠻觸怒不休，暴骨千里横。", "微言起我病，內愧面汗騂。", "蚤知天宇大，豈有世網嬰。", "舉扇障西風，浣此滄浪纓。"]'),
('6c2f404f-4da3-49b2-998f-c922a9771c50','胥澤民招飲二首  其一','孫覿','宋','宋诗','song-poetry','','[]','蕭晨散幽步，不放一塵驚。',96,'全唐诗/poet.song.85000.json','["蕭晨散幽步，不放一塵驚。", "高崖初日吐，壞道哀湍鳴。", "平生耽田里，見此心眼明。", "危橋屬幽徑，别户延朱甍。", "主人鷄黍約，庖煙起晨烹。", "長須舉案出，銀杯坐中行。", "爛漫寫真意，殷勤愧深情。", "留歡更卜夜，華燭吐長檠。"]'),
('26a28051-e779-4613-8a86-60b7deb85a89','胥澤民招飲二首  其二','孫覿','宋','宋诗','song-poetry','','[]','蒼茫夜氣合，渺渺風露清。',96,'全唐诗/poet.song.85000.json','["蒼茫夜氣合，渺渺風露清。", "籃輿兀醉夢，翩若孤雁征。", "老馬志萬里，絡首喪其生。", "十年飽芻豆，立仗不敢鳴。", "自識酒中趣，承辭身後名。", "皎皎一片心，不受寵辱驚。", "清風悲永夜，萬竅同一聲。", "醉裏有歸路，彷彿遊化城。"]'),
('09ed2370-f5b9-4aab-883b-27ef214fcec0','别如老','孫覿','宋','宋诗','song-poetry','','[]','同舟無胡越，四海皆弟兄。',120,'全唐诗/poet.song.85000.json','["同舟無胡越，四海皆弟兄。", "吾人雖晚接，一笑蓋已傾。", "我老未聞道，意行墮溝坑。", "逢人得推駡，知非愧平生。", "世亂識真態，塗窮見真情。", "曳杖扣禪扃，撞鐘聽靴鳴。", "小窗風雨夜，對此一榻横。", "吾身如木偶，春至不復榮。", "豈無三宿戀，天雨方流行。", "去去得首邱，歸田克殘更。"]'),
('cf1d3266-a706-4acb-8774-d1c8aab6c1d1','徙寓妙覺佛舍胥乂民襆被相過賦夜坐','孫覿','宋','宋诗','song-poetry','','[]','客居厭窮獨，蓬艾翳環堵。',120,'全唐诗/poet.song.85000.json','["客居厭窮獨，蓬艾翳環堵。", "莊舄尚越吟，鍾儀猶楚語。", "吾人有奇操，空洞見城府。", "相逢逆旅中，霧豹初一睹。", "拘囹賦囚山，避謗憎市虎。", "褰裳肯顧我，崖嶠走風雨。", "微吟對清夜，破此五月暑。", "墜露挹金莖，空花堕犀麈。", "孤燈映籠紗，泠灧翳復吐。", "耿耿遂不眠，逢逢聽晨鼓。"]'),
('f8194dc8-9e0b-43aa-9bc4-23d18c438666','招鄒次魏','孫覿','宋','宋诗','song-poetry','','[]','客舍風雨交，庭蕪蔓春草。',120,'全唐诗/poet.song.85000.json','["客舍風雨交，庭蕪蔓春草。", "蓐食悲王孫，戛釜厭邱嫂。", "吾人才傑立，一障狂瀾倒。", "湯湯捍滔天，澟澟塊絕島。", "奇音閑大樸，妙語發天藻。", "壁間見蝎喜，屋上瞻烏好。", "跫然聽足音，自足慰衰老。", "出門泥活活，所向碍行潦。", "懷人心不展，厭亂跡如掃。", "仲子過我廬，肩輿白雲道。"]'),
('c615bdde-3bdb-4840-8a96-6d64b32426c5','贈答淵侍者','孫覿','宋','宋诗','song-poetry','','[]','沐猴著冠天所械，笑唾千金如一芥。',64,'全唐诗/poet.song.85000.json','["沐猴著冠天所械，笑唾千金如一芥。", "時時扣角詠三生，口業未除詩有債。", "薨薨不作秋蟲聲，藹藹欲盡春雲態。", "平旦誰登大將壇，一軍驚呼子光拜。"]'),
('c082a3cd-0fa8-451f-9625-46ee49a38f5c','建昌守朱直伯寄酒小詩爲謝','孫覿','宋','宋诗','song-poetry','','[]','愛酒淵明望白衣，傳聞騎吏款柴扉。',64,'全唐诗/poet.song.85000.json','["愛酒淵明望白衣，傳聞騎吏款柴扉。", "爲憐漁父鳴鞭送，欲便山翁倒載歸。", "泪向琵琶弦上落，心隨蝴蜨夢中飛。", "一杯属我寛愁病，免使黎侯詠式微。"]'),
('480d022f-4bfd-4ae5-851c-487acf3377b1','再用前韻','孫覿','宋','宋诗','song-poetry','','[]','千騎森森響鐵衣，日上銅環四扇扉。',64,'全唐诗/poet.song.85000.json','["千騎森森響鐵衣，日上銅環四扇扉。", "何妨指點銀缾索，直須倒著接籬歸。", "已邀明月三人共，更看紅塵一騎飛。", "何日淵明賦歸去，晨光前路正熹微。"]'),
('db672a8b-8256-4954-b79f-44a2e6a1e5f9','妙覺寺適軒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','古寺秋崖上，清風掩半關。',72,'全唐诗/poet.song.85000.json','["古寺秋崖上，清風掩半關。", "晚花明艷艷，曉溜落潺潺。", "松筍穿階瘦，苔窠蔽石斑。", "翹沙憐鷺静，抱葉看蜂還。", "心以空無累，身從病得閑。", "儀曹獨何事，終日賦囚山。"]'),
('41ff1705-14a0-4af1-a84a-77d9ba9513a5','妙覺寺適軒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','老厭風沙惡，安閑且當禪。',72,'全唐诗/poet.song.85000.json','["老厭風沙惡，安閑且當禪。", "開簾延白月，倚杖立蒼煙。", "鳥散人聲裏，鐘殘客夢邊。", "小蒲風葉偃，薄槿露花鮮。", "句好吟須斷，歡餘醉帽偏。", "人生但如此，何處不翛然。"]'),
('3a9085f8-b415-4a91-8ae7-fd017f49ab83','妙覺書事二首  其一','孫覿','宋','宋诗','song-poetry','','[]','聒聒催酤我，嚶嚶喚友聲。',48,'全唐诗/poet.song.85000.json','["聒聒催酤我，嚶嚶喚友聲。", "一遭青蠅汙，永負白鷗盟。", "睡鴨嘘煙滿，蒼龍噀雨鳴。", "參禪我未暇，一榻對僧横。"]'),
('de7ac2c0-1786-4f9e-a2df-5bc4f28ad55e','妙覺書事二首  其二','孫覿','宋','宋诗','song-poetry','','[]','隱几抛書坐，欹牀聽雨眠。',48,'全唐诗/poet.song.85000.json','["隱几抛書坐，欹牀聽雨眠。", "僧來逢自足，盜去失青氈。", "楚國雖三户，滕氓尚一廛。", "如今更何恨，端用酒爲年。"]'),
('d3134264-bdb7-4fc3-8c32-bcb43ba65d61','次韻王子欽端午','孫覿','宋','宋诗','song-poetry','','[]','飯筒菰黍趁流年，葵扇桃笙尚宛然。',64,'全唐诗/poet.song.85000.json','["飯筒菰黍趁流年，葵扇桃笙尚宛然。", "世味半隨昌歜苦，心旌長與艾人懸。", "鴻飛不到書來少，鵲喜無憑語浪傳。", "兩鬢蕭蕭吹白髮，空餘衰謝故人憐。"]'),
('d6b81e34-14f6-48a7-bf5d-6040a48343cc','吳益先攜文見過以詩爲謝','孫覿','宋','宋诗','song-poetry','','[]','千里之馬初服輈，風騣霧鬛跨九州。',128,'全唐诗/poet.song.85000.json','["千里之馬初服輈，風騣霧鬛跨九州。", "駕鹽挽磨三千秋，俯首尚與駑駘遊。", "吳郎人中第一流，文采絢爛珊瑚鈎。", "陽春白雪和者少，夜光明月暗中投。", "魯人不貴東家邱，吾髯凜凜青兩眸。", "摐金戛玉聲相求，属鏤雙蟠九地幽。", "有氣夜出干斗牛，忽然化作長黄虬。", "睚眦之怨何足讎，一麾立斷樓蘭頭。"]'),
('75f4efee-fa63-4d71-bccf-cfd1d393f696','次韻王子欽','孫覿','宋','宋诗','song-poetry','','[]','北窗風冷冷，西閣夜悄悄。',72,'全唐诗/poet.song.85000.json','["北窗風冷冷，西閣夜悄悄。", "缺月吐半璧，獨與太白曉。", "緱山王郎子，粲若玉樹皎。", "紛紛噲伍中，特立負奇表。", "清談静炎燠，堅臥鎮浮擾。", "呼童高樹栅，赤幘厭凡鳥。"]'),
('cc6373a7-b548-4632-90bc-79b8c6588607','再和','孫覿','宋','宋诗','song-poetry','','[]','二年客塵土，獨夜憂悄悄。',72,'全唐诗/poet.song.85000.json','["二年客塵土，獨夜憂悄悄。", "遇酒一破顔，歌呼醉連曉。", "寸心爲誰明，伴此孤月皎。", "枯柟鬰峥嶸，老幹空自表。", "蟻穿萬孔萃，蛛掛千絲擾。", "白鶴逝不來，豈敢更擇鳥。"]'),
('289253e1-2214-4858-a270-dc22d8f1430b','涂子野九歲子名駒字千里戲作絕句  其一','孫覿','宋','宋诗','song-poetry','','[]','日角珠庭秀兩眉，誰家有此寧馨兒。',32,'全唐诗/poet.song.85000.json','["日角珠庭秀兩眉，誰家有此寧馨兒。", "莫驚墮地駒千里，久見參天桂一枝。"]'),
('10cb61ad-0168-4e4a-b09a-068f34754e9e','涂子野九歲子名駒字千里戲作絕句  其二','孫覿','宋','宋诗','song-poetry','','[]','碌碌爲生笑阿奴，九齡重見此英雛。',32,'全唐诗/poet.song.85000.json','["碌碌爲生笑阿奴，九齡重見此英雛。", "千回健走非黄犢，一洗羣空定白駒。"]'),
('bca04b3d-7c80-4398-9008-d92641974f96','詩贈竹庵静老人','孫覿','宋','宋诗','song-poetry','','[]','争名計身後，逐利了目前。',120,'全唐诗/poet.song.85000.json','["争名計身後，逐利了目前。", "道人一彈指，永斷三生緣。", "起滅水上漚，聚散風中煙。", "紛紛閲凋謝，東海今桑田。", "縞髮茁枯顱，秀眉覆兩顴。", "已超人天上，遂拍佛祖肩。", "茅齋立萬竹，蔭此碧玉椽。", "綠暗雲擾擾，清涵露娟娟。", "我老無家舍，餘地寄一廛。", "不辭供井磑，辛苦送華顛。"]'),
('294cac75-4180-4ab2-a6d1-f4e4efd52c64','置酒','孫覿','宋','宋诗','song-poetry','','[]','離離黍禾暗空村，一點炊煙带雨昏。',96,'全唐诗/poet.song.85000.json','["離離黍禾暗空村，一點炊煙带雨昏。", "山翁過我竹閣寺，未扣爵羅廷尉門。", "老去不辭污詩酒，區區獨醒一何有。", "笑語未辦供主人，久客那能拒鄰叟。", "杜陵白首尚書郎，步屧春風向草堂。", "人生意合無妍醜，共此一夕燈燭光。"]'),
('b11cee14-bf89-4261-ac2e-69d1fd949858','讀李光遠詩卷次韻二首 泗州南山','孫覿','宋','宋诗','song-poetry','','[]','跳波亂清淮，一葉寄真賞。',84,'全唐诗/poet.song.85000.json','["跳波亂清淮，一葉寄真賞。", "南山如高人，標格自矜爽。", "胡塵暗楚甸，絕境墮渺漭。", "空城草木春，户外履誰兩。", "悵望壺公龍，乘雲自來往。", "小詩若圖畫，彷彿見飛槳。", "從今淮上山，不落夢中想。"]'),
('247c0794-4b1a-4c0e-8def-e96dad91a39b','讀李光遠詩卷次韻二首 揚州谷林堂','孫覿','宋','宋诗','song-poetry','','[]','楚山多異材，翠竹滿崖谷。',72,'全唐诗/poet.song.85000.json','["楚山多異材，翠竹滿崖谷。", "蕭蕭斤斧餘，斬伐同一束。", "蕪城带流水，萬畝淇園綠。", "遺苞駮雲錦，老節抱金玉。", "歲晚虎穴鄰，舐掌方擇肉。", "此君亡恙否，應坐白眼俗。"]'),
('cdd80bdf-11f1-4f92-b962-8bb9510e7d89','志新誦近詩次韻二首  其一','孫覿','宋','宋诗','song-poetry','','[]','客舍秋風我欲愁，世途如漆莽悠悠。',64,'全唐诗/poet.song.85000.json','["客舍秋風我欲愁，世途如漆莽悠悠。", "半生小利營錐末，此日危炊上劍頭。", "萬里窮鄉憐我老，一廛小隱待君謀。", "惘然貌赤空相對，扇面令人手不休。"]'),
('b46bff2c-33bc-4d3f-8c99-19114eb2e13d','志新誦近詩次韻二首  其二','孫覿','宋','宋诗','song-poetry','','[]','野鶴昂昂祗自奇，水鳧泛泛强隨時。',64,'全唐诗/poet.song.85000.json','["野鶴昂昂祗自奇，水鳧泛泛强隨時。", "問禪乞我安心法，住世分君大藥資。", "便欲乘桴從魯叟，不須歌鳯歎周衰。", "超然獨嘯千峰上，一吷清風萬竅吹。"]'),
('d47ada40-cf0b-426e-bb0c-5af676a93519','石䂬在宜黄縣之南二十五里義泉寺寺旁有磴道高里許循山而西少北忽有石梁數十丈横絕兩崖之間中空無柱高出雲表神剜鬼刻不可名狀真洞心駭目之觀而僻在一隅遊客無所爲而至乃賦詩一篇以告喜遊而不知者','孫覿','宋','宋诗','song-poetry','','[]','何人手執造化關，投此虹蜺跨兩間。',128,'全唐诗/poet.song.85000.json','["何人手執造化關，投此虹蜺跨兩間。", "烏鵲填成天上路，鬼神鞭出海中山。", "飄飄尻駕凌空舉，側身下瞰千峰雨。", "河漢汹汹聲西流，風雹相躔齊萬弩。", "始信通天有一門，便欲晞髪扶桑根。", "乘槎忽逢支機石，拄杖直到洗頭盆。", "賞俊誇雄兩奇絕，邂逅一聲如電掣。", "冥冥滄海會揚塵，大字磨崖書歲月。"]'),
('069d4e7e-38d5-4efa-ab3b-5b11da7ad8e4','熊夫人遣介欲婿澤民小詩戲之','孫覿','宋','宋诗','song-poetry','','[]','牆頭鄰女三年望，戶外文君一笑窺。',63,'全唐诗/poet.song.85000.json','["牆頭鄰女三年望，戶外文君一笑窺。", "欲得賢夫嫁張耳，此真佳婿是羲之。", "定知不折飛梭齒，似說先齊舉眉。", "不信侯門深似海，水流紅葉謾題詩。"]'),
('63ee2662-33a7-47de-84fb-a07f17b1c2e1','題鄒次魏青藜堂','孫覿','宋','宋诗','song-poetry','','[]','讀書非貴嗜，吾子喜欲迷。',96,'全唐诗/poet.song.85000.json','["讀書非貴嗜，吾子喜欲迷。", "十年費膏火，羣嘲笑書痴。", "磊落載五車，望海無津涯。", "雙瞳如秋月，一出照耀之。", "冥搜理窟邃，妙解鋸屑霏。", "胸中九雲夢，百怪見然犀。", "拊枕出鴻寶，鑄金侔褭蹏。", "神光發中夜，太乙秉青藜。"]'),
('45ddd162-5594-4a51-bd2f-d70754238412','静老容安庵二首  其一','孫覿','宋','宋诗','song-poetry','','[]','離離風中花，深落任所之。',72,'全唐诗/poet.song.85000.json','["離離風中花，深落任所之。", "泛泛水中萍，流轉復在兹。", "静公湖海士，世網那得縻。", "獨有鐵石心，不與燥溼移。", "巢肩統靈鵲，搘牀餘老龜。", "區區了官事，應解笑兒痴。"]'),
('9fa20203-e4ca-4632-982c-451d61cb3cd1','静老容安庵二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雲噓翠撲膚，山擁青入户。',72,'全唐诗/poet.song.85000.json','["雲噓翠撲膚，山擁青入户。", "祗樹給孤園，桃源武陵路。", "一從振履還，不復乘杯渡。", "倚牆捫蝨坐，揮弦送鴻去。", "水涵樓影交，風斂花氣度。", "把茅便有餘，不必黄金布。"]'),
('33935473-0c50-46cd-b6c1-2a6a2c0b4e07','静老通幽軒','孫覿','宋','宋诗','song-poetry','','[]','諸峰倚崔嵬，衆壑隐奔峭。',96,'全唐诗/poet.song.85000.json','["諸峰倚崔嵬，衆壑隐奔峭。", "寓目欣有繫，會心領其要。", "開廬結茅竹，伐翳斬蓬藋。", "此君亦可人，玉立盡娟妙。", "風酣翠相倚，月吐青自照。", "窈眇非世音，鸞鵠中夜嘯。", "煙塵闇北關，烽火被南徼。", "便欲老三閭，終焉隱屠釣。"]'),
('00b5cab1-26f1-44e9-938d-ea80b0f33527','次韻王子欽秋懷二首  其一','孫覿','宋','宋诗','song-poetry','','[]','白汗翻漿浹背流，清飈一掃破除休。',64,'全唐诗/poet.song.85000.json','["白汗翻漿浹背流，清飈一掃破除休。", "楓江湛湛冰壺月，梧井團團玉露秋。", "蟻動巧聞牀下鬬，駒跳首向隙中留。", "南山危坐高稜見，杞國區區豈我憂。"]'),
('54970e70-79e9-409e-9110-3176f6329ce8','次韻王子欽秋懷二首  其二','孫覿','宋','宋诗','song-poetry','','[]','愁邊種種關心事，客裏紛紛見俗情。',64,'全唐诗/poet.song.85000.json','["愁邊種種關心事，客裏紛紛見俗情。", "雁拆西風離思亂，鳥啼殘夜旅魂驚。", "江河風景悲南渡，家室倉皇問北征。", "滄海横流安税駕，一桴從我任平生。"]'),
('857be134-020d-42d9-873c-4e57f51a79a1','秋夜三首  其一','孫覿','宋','宋诗','song-poetry','','[]','山寒藹瞑姿，楓老带漲痕。',60,'全唐诗/poet.song.85000.json','["山寒藹瞑姿，楓老带漲痕。", "蘭摧桂亦折，往往歸其根。", "萬籟各收聲，一氣中自存。", "鼻斤無可斵，尻駕不復奔。", "孤光照獨夜，月落低金盆。"]'),
('32a93c90-f3c8-40de-b51e-72ddf997300b','秋夜三首  其二','孫覿','宋','宋诗','song-poetry','','[]','金氣天與高，燈燼宵正繁。',60,'全唐诗/poet.song.85000.json','["金氣天與高，燈燼宵正繁。", "暗蛩露下績，潛虬浪中翻。", "幽人醉清夜，一笑空罍尊。", "遇勝獨心詣，了了見目存。", "但憂兒輩覺，難與俗人言。"]'),
('cffde6a9-9ca8-46f5-a5cf-a7ada85055a7','秋夜三首  其三','孫覿','宋','宋诗','song-poetry','','[]','寥寥犬吠村，微月耿黄昏。',60,'全唐诗/poet.song.85000.json','["寥寥犬吠村，微月耿黄昏。", "雞豚市井空，虎豹窟宅尊。", "元龍百尺樓，獨臥誰與論。", "酒聖且復中，愁魔自驚奔。", "彈鋏歸去來，稚子候柴門。"]'),
('5e66e6bd-51d4-404e-ba18-7cce25b188e3','秋興  其一','孫覿','宋','宋诗','song-poetry','','[]','雲族正南鶩，日車遂西沈。',48,'全唐诗/poet.song.85000.json','["雲族正南鶩，日車遂西沈。", "倚樓孤客恨，伏枕故園心。", "唧唧蟲造哀，交交鳥遺音。", "危坐百感集，我何念之深。"]'),
('7cf06bd8-8d92-478b-a0b5-dee9c611823c','秋興  其二','孫覿','宋','宋诗','song-poetry','','[]','淺瀨落雲碧，幽花弄秋妍。',48,'全唐诗/poet.song.85000.json','["淺瀨落雲碧，幽花弄秋妍。", "細細回波渡，津津笑靨圓。", "起謀杯中物，行掛杖頭錢。", "阮公任真率，醉臥酒壚邊。"]'),
('5d10c95f-873f-4a12-809c-0bbabb3816d9','妙覺寺三詠 木犀','孫覿','宋','宋诗','song-poetry','','[]','霜葩翳老青，粲粲石壁下。',72,'全唐诗/poet.song.85000.json','["霜葩翳老青，粲粲石壁下。", "瓊樹一時新，肌冰敵姑射。", "光風泛月彩，芳氣襲蘭麝。", "幽人三嗅泣，采玩不盈把。", "芙蓉强争妍，刻畫粉黛假。", "對之若爲容，慚紅面如赬。"]'),
('0b98d59a-9fbd-42b7-919e-6af95d5f51d5','妙覺寺三詠 梧桐','孫覿','宋','宋诗','song-poetry','','[]','高梧傍層樓，隱翳崖寺古。',72,'全唐诗/poet.song.85000.json','["高梧傍層樓，隱翳崖寺古。", "森森露井寒，蔭此六月暑。", "秋風動地至，柯葉遽如許。", "依依别故林，黄落半粘土。", "凉蟬不復號，驚鵲時自語。", "一夜繞空枝，愁絕兩翅羽。"]'),
('fd9719d3-082e-4b32-9c27-8aed48170a38','妙覺寺三詠 芙蓉','孫覿','宋','宋诗','song-poetry','','[]','沙際漾淺碧，竹外欹深紅。',72,'全唐诗/poet.song.85000.json','["沙際漾淺碧，竹外欹深紅。", "晨光發穠麗，醉臉酣春融。", "歡華不滿眼，榮悴一日中。", "娟娟泣朝露，槭槭隕夕風。", "顧我非靈仙，丹砂駐君容。", "舉酒酹其根，明年何處逢。"]'),
('4d537164-5931-4bd7-91ed-d293f2f52021','自崇仁趨新淦凡四夕乃至一寓道觀三止僧舍皆留一夕而去賦小詩記之 奴原寺','孫覿','宋','宋诗','song-poetry','','[]','稚子應門立，老僧迎客入。',48,'全唐诗/poet.song.85000.json','["稚子應門立，老僧迎客入。", "湛湛玉甃寒，唧唧銅瓶泣。", "小軒風雨過，窗户青紅溼。", "晚花發秋妍，黄蜂正衙集。"]'),
('4ad04527-01ae-4633-9965-3126c7d2cfc8','自崇仁趨新淦凡四夕乃至一寓道觀三止僧舍皆留一夕而去賦小詩記之 化度寺','孫覿','宋','宋诗','song-poetry','','[]','失路迷千嶂，投林借一枝。',48,'全唐诗/poet.song.85000.json','["失路迷千嶂，投林借一枝。", "扣門竹西寺，立馬日斜時。", "矍鑠僧窺户，睢盱犬透籬。", "定知嫌不速，明日與君辭。"]'),
('c7beb18c-1eea-46d1-8d21-946968339ad6','自崇仁趨新淦凡四夕乃至一寓道觀三止僧舍皆留一夕而去賦小詩記之 栖霞觀觀在麻嶺下','孫覿','宋','宋诗','song-poetry','','[]','雲表朝飛屐，松蹊晚駐鞍。',48,'全唐诗/poet.song.85000.json','["雲表朝飛屐，松蹊晚駐鞍。", "破扉聯白板，槁項繫黄冠。", "徑雨喧風籜，汀沙立露翰。", "小窗牀坐好，對此百憂寛。"]'),
('66047e5a-a34b-475d-bd1a-d1adc4770a17','自崇仁趨新淦凡四夕乃至一寓道觀三止僧舍皆留一夕而去賦小詩記之 三山寺二首 其一','孫覿','宋','宋诗','song-poetry','','[]','斜日半窗明，無人獨掩扃。',48,'全唐诗/poet.song.85000.json','["斜日半窗明，無人獨掩扃。", "風鈴時自語，雪柏老終青。", "立鵲參差見，微泉斷續聽。", "老僧渾不語，危坐卷殘燈。"]'),
('c1734c49-d689-429e-ac06-e44982906d33','自崇仁趨新淦凡四夕乃至一寓道觀三止僧舍皆留一夕而去賦小詩記之 三山寺二首 其二','孫覿','宋','宋诗','song-poetry','','[]','異縣久爲客，窮途飽所更。',48,'全唐诗/poet.song.85000.json','["異縣久爲客，窮途飽所更。", "對牀雲伴宿，曳杖月同行。", "到處身如寄，看山眼蹔明。", "平生飲中趣，酒賤且頻傾。"]'),
('aeefd6da-d088-45e1-a9d4-4170e95867a2','余大觀中偕何襲明登仕同爲太學諸生别後二十六年余□南遷道清江襲明逆余於新淦之洲上蒼顔白髪大略相似感嘆之餘飲酒賦詩以爲笑樂襲明筆力雄贍操紙立就凡六七反必用前韻余繼和者十二篇云  其一','孫覿','宋','宋诗','song-poetry','','[]','亡弓墮甑一時空，夢斷南柯午枕中。',64,'全唐诗/poet.song.85000.json','["亡弓墮甑一時空，夢斷南柯午枕中。", "便有樽罍追北海，更無塵土汙西風。", "驅牛懶臥山中相，失馬來看塞上翁。", "從此卜鄰成二老，雞豚社酒與君同。"]'),
('e8d53cb9-22aa-4d33-a279-b6118f1d2d3b','余大觀中偕何襲明登仕同爲太學諸生别後二十六年余□南遷道清江襲明逆余於新淦之洲上蒼顔白髪大略相似感嘆之餘飲酒賦詩以爲笑樂襲明筆力雄贍操紙立就凡六七反必用前韻余繼和者十二篇云  其二','孫覿','宋','宋诗','song-poetry','','[]','龍媒去盡馬羣空，一曲陽春在郢中。',64,'全唐诗/poet.song.85000.json','["龍媒去盡馬羣空，一曲陽春在郢中。", "浩浩百川齊赴海，蓬蓬萬竅總號風。", "誰憐楚國沈湘客，獨有商山避世翁。", "閭里應容投緩急，風波千里一舟同。"]'),
('62e68eda-5179-445d-b5bf-4551e1b5b6d5','再和  其一','孫覿','宋','宋诗','song-poetry','','[]','烏啼鵲噪晚庭空，並舍相呼入酒中。',64,'全唐诗/poet.song.85000.json','["烏啼鵲噪晚庭空，並舍相呼入酒中。", "逐影故慚夸父日，披襟聊快楚王風。", "牛衣泣臥悲游子，鳩杖歡迎愧老翁。", "笑我獨醒成底事，一邱之貉古今同。"]'),
('bc17ebce-5ef8-4c25-b91b-f6ace8ad498c','再和  其二','孫覿','宋','宋诗','song-poetry','','[]','沙平雪漫水涵空，路入千巖紫翠中。',64,'全唐诗/poet.song.85000.json','["沙平雪漫水涵空，路入千巖紫翠中。", "村遠微明漁舍火，樓高斜矗酒旗風。", "可憐方外狂司馬，來伴田中一禿翁。", "南北相望三十載，心期不改斷金同。"]'),
('4b37ce86-a613-4832-8d42-3acef0fa2b22','再和  其一','孫覿','宋','宋诗','song-poetry','','[]','瘴雨蠻煙掃地空，衆星環列拱天中。',64,'全唐诗/poet.song.85000.json','["瘴雨蠻煙掃地空，衆星環列拱天中。", "豹章尚隱南山霧，鵬背將摶北海風。", "麟閣似聞登漢將，鹿門猶自臥龐翁。", "低頭莫負平生志，冠蓋風雲萬里同。"]'),
('72c546b9-67ca-4558-b478-1bb48893c6a5','再和  其二','孫覿','宋','宋诗','song-poetry','','[]','夜鶴悲鳴蕙帳空，一身今在百憂中。',64,'全唐诗/poet.song.85000.json','["夜鶴悲鳴蕙帳空，一身今在百憂中。", "驚魂尚喘吳牛月，短翮甘隨宋鷁風。", "且與龜魚爲地主，不將鵝鴨惱鄰翁。", "超然世態誰君似，蘭菊春秋自不同。"]'),
('d9735524-ffc5-4e30-901e-de9725ea119f','何倅利見許出侍兒襲明用前韻賦詩再和  其一','孫覿','宋','宋诗','song-poetry','','[]','平生慣見有司空，腸斷蘇州一盼中。',64,'全唐诗/poet.song.85000.json','["平生慣見有司空，腸斷蘇州一盼中。", "此夜相忘千里月，他年應恨五更風。", "坐中不樂無三粲，客裏相逢祗兩翁。", "急雨催詩更蕭瑟，小窗寒夜一燈同。"]'),
('305d525d-2f05-4e8d-8736-26c1c8440ca5','何倅利見許出侍兒襲明用前韻賦詩再和  其二','孫覿','宋','宋诗','song-poetry','','[]','錦堂蓮燭夜光空，喜笑蟬聯繡户中。',64,'全唐诗/poet.song.85000.json','["錦堂蓮燭夜光空，喜笑蟬聯繡户中。", "塵繞梁飛歌白雪，襪凌波去舞回風。", "投梭且莫驚狂客，却扇何妨眩醉翁。", "青鳥殷勤問消息，留髠滅燭許誰同。"]'),
('7c0746a1-e50b-41c8-ad8b-fe39b1776a1e','何嘉會寺丞遣嫁侍兒襲明有詩次韻  其一','孫覿','宋','宋诗','song-poetry','','[]','魯陽之戈倚半空，誰能一却日再中。',64,'全唐诗/poet.song.85000.json','["魯陽之戈倚半空，誰能一却日再中。", "驚回十二巫山雨，永隔三千弱水風。", "廋語尚傳黄絹婦，多情好在紫髯翁。", "謫仙尚有杯中月，獨舞婆娑醉影同。"]'),
('61c74acd-73b3-4865-aef1-16c1376e12e2','何嘉會寺丞遣嫁侍兒襲明有詩次韻  其二','孫覿','宋','宋诗','song-poetry','','[]','哀蟬已逐夢雲空，錦字參差在眼中。',64,'全唐诗/poet.song.85000.json','["哀蟬已逐夢雲空，錦字參差在眼中。", "應似桃花貪結子，任教柳絮舞隨風。", "留春不住無樊子，隔水遙看有杜翁。", "無那丁寧花鳥使，丁香偷結兩心同。"]'),
('e7f9f295-618e-499b-9b1f-c4cb0e133b71','迎薫堂小集襲明用前韻再和  其一','孫覿','宋','宋诗','song-poetry','','[]','飲痛瓊艘百柁空，參横斗掛月當中。',64,'全唐诗/poet.song.85000.json','["飲痛瓊艘百柁空，參横斗掛月當中。", "不愁馬上衣沾露，且看尊前幘墮風。", "未辦清歌娛醉客，莫將强韻壓衰翁。", "爲歡冷淡君應笑，注瓦傾銀一體同。"]'),
('fe0f1400-5b0b-42a3-a272-f81f16cd6976','迎薫堂小集襲明用前韻再和  其二','孫覿','宋','宋诗','song-poetry','','[]','繪出金盤放筯空，一時酣詠醉鄉中。',64,'全唐诗/poet.song.85000.json','["繪出金盤放筯空，一時酣詠醉鄉中。", "羽觴聚泛蘭亭月，璆佩鏘鳴閬苑風。", "顛倒白綸容老子，淋漓紫綺看仙翁。", "詩成快寫鮫人室，萬顆驪珠訝許同。"]'),
('677f130b-76b5-4ebf-969e-25ce3648f226','何嘉會以侍兒歸彭生小詩戲之','孫覿','宋','宋诗','song-poetry','','[]','浮蒼宛宛兩眉長，瀉碧汪汪一鑑光。',32,'全唐诗/poet.song.85000.json','["浮蒼宛宛兩眉長，瀉碧汪汪一鑑光。", "山海相逢非浪語，小孤明日嫁彭郎。"]'),
('58e71576-7fb7-4759-ac3e-2c7ec49930a5','長樂寺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','層梯倚天碧，細路連草莽。',96,'全唐诗/poet.song.85000.json','["層梯倚天碧，細路連草莽。", "蕭蕭蒼松門，税此林下鞅。", "輪囷老樹姿，偃蹇怪石狀。", "中有蓮花臺，迥出諸天上。", "空堂臥鐘鼓，古佛暗龍象。", "飛泉漱石除，夜半發清響。", "雲低雪浮浮，柳動春盎盎。", "超搖萬里眼，更欲鏟叠嶂。"]'),
('2b8b11d8-41d0-40ff-ab44-56775e7da2a6','長樂寺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','萬瓦冠松壁，千嶂鎖雲莊。',96,'全唐诗/poet.song.85000.json','["萬瓦冠松壁，千嶂鎖雲莊。", "故人置酒地，清夜燈燭張。", "破壁掛月闕，遺笙嘯風廊。", "妖歌傾四座，醉臥錦瑟傍。", "寂寂花絮亂，匆匆鶯燕忙。", "雍門已陳迹，餘音空繞梁。", "我來久徘徊，驚呼首一昂。", "老僧獨依然，對坐柏子香。"]'),
('249cf69d-5224-4642-8cdf-45e63af1eb71','志新遣介致書餽以巴源紙黄甘珠欖大栗鵝鮓枯蝦爲餉戲作長句爲謝','孫覿','宋','宋诗','song-poetry','','[]','巴江新搗萬穀皮，禇生粉面膚凝脂。',128,'全唐诗/poet.song.85000.json','["巴江新搗萬穀皮，禇生粉面膚凝脂。", "故人千里持寄我，落筆宛宛天投霓。", "綈囊丹果十襲包，爆栗飛燼石火敲。", "紅鹽著樹落青子，香霧噀手披黄苞。", "蒼鵝無罪見葅醢，苦酒濯之光五采。", "蝦跧久已成枯腊，咫尺波濤渺江海。", "客舍爭席紛滿前，饋羮不復五漿先。", "殷勤重餉有吾子，兩夫擔荷赬其肩。"]'),
('0be6bcce-e238-4f62-9079-a18d567297a7','蜀婦新寡從何純中讀左氏戲呈純中','孫覿','宋','宋诗','song-poetry','','[]','麟經束高閣，掩卷有三嘆。',72,'全唐诗/poet.song.85000.json','["麟經束高閣，掩卷有三嘆。", "朱弦久零落，鸞膠續其斷。", "英英左阿君，獨唱音節緩。", "故是我輩人，吹簫得幽伴。", "先生擁絳紗，弟子褰素幔。", "一揮斵鼻斤，便舉齊眉案。"]'),
('3ca52a1e-0485-4631-add7-c29375a25386','嘉會飲餞愛姬大慟而別','孫覿','宋','宋诗','song-poetry','','[]','小窗危坐若爲情，曳杖穿雲取次行。',64,'全唐诗/poet.song.85000.json','["小窗危坐若爲情，曳杖穿雲取次行。", "蕭寺試來攜手處，陽關已作斷腸聲。", "歌呼本自追曹相，慟哭那知見賈生。", "坐上誰人最愁絕，江州司馬淚縱横。"]'),
('9950e906-b977-4f6a-8e17-de266a2d05b8','遊鍾石寺問名寺之因緣老僧指門旁石如覆鍾狀賦詩一首邀何襲明登仕同賦','孫覿','宋','宋诗','song-poetry','','[]','月斧琢朣朧，團欒覆石鍾。',216,'全唐诗/poet.song.85000.json','["月斧琢朣朧，團欒覆石鍾。", "連絡青雲根，點注碧蘚封。", "補天記女媧，移山詫愚公。", "當年偶遺漏，墮此草莽中。", "奇礓久淪蟄，化出金仙宫。", "老僧慣見之，笑視瓦礫同。", "礪角戲烏犍，迸火敲青童。", "摩挲問亡恙，千歲今一逢。", "堂堂張茂先，扣以蜀井桐。", "噌吰振林莽，叱吸萬竅風。", "澒洞衆壑滿，吼徹九地通。", "狂奔竄幽魅，驚怒拔老龍。", "豐山霜露零，彭蠡波浪舂。", "一鳴固有待，寸筳那得攻。", "水曹筆五色，東序羅笙鏞。", "辟易四坐傾，蹴蹋萬馬空。", "偉兹抱奇音，伴我窺靈蹤。", "賦詩乃不如，露草號秋蟲。"]'),
('f1cbd8b9-af40-4e15-a8d7-2ca933f6ee90','宜黄尉李集義遺書問安否小詩爲謝','孫覿','宋','宋诗','song-poetry','','[]','三年著南冠，兩見芳歲新。',96,'全唐诗/poet.song.85000.json','["三年著南冠，兩見芳歲新。", "朝爲蟲蛇侶，暮與魑魅鄰。", "行隨木上坐，臥對竹夫人。", "獨有金石交，不廢風雨晨。", "書來一弔屈，我已屢厄陳。", "嘖嘖爨下桐，嗷嗷轍中燐。", "絙以朱絲繩，放之碧海津。", "窮途得重惠，肝胆久輪囷。"]'),
('3397eec2-5789-4049-b353-e3a724d1c038','雪二首  其一','孫覿','宋','宋诗','song-poetry','','[]','嶺雲亂擘絮，簷雨收斷綫。',60,'全唐诗/poet.song.85000.json','["嶺雲亂擘絮，簷雨收斷綫。", "箕神擁前驅，萬瓦集微霰。", "玉峰忽崔嵬，炯若簪出弁。", "衣稜森欲起，眼纈醉復眩。", "属國臥餐氈，含糊不能嚥。"]'),
('5a3236b0-b789-4f2d-9a32-0605a0f5fc67','雪二首  其二','孫覿','宋','宋诗','song-poetry','','[]','喧豗湊六合，澒洞咽羣籟。',60,'全唐诗/poet.song.85000.json','["喧豗湊六合，澒洞咽羣籟。", "俄驚江海懸，坐覺虚空隘。", "包藏失地險，瀰漫見天大。", "嬋娟自一種，巧麗窮百態。", "獨餘古柏青，正色老不壞。"]'),
('a5fd8b16-47c7-4322-9d2d-81073c4b9cea','次韻王子欽上元感事三首  其一','孫覿','宋','宋诗','song-poetry','','[]','寒雨吹黄屋，胡星照紫宸。',48,'全唐诗/poet.song.85000.json','["寒雨吹黄屋，胡星照紫宸。", "龍沙萬里去，燈市七年春。", "感戀丹心折，悲吟白髮新。", "孤臣臥江海，老淚滿衣襟。"]'),
('8a8d9b37-b954-4fb8-aed6-28b30523c3b8','次韻王子欽上元感事三首  其二','孫覿','宋','宋诗','song-poetry','','[]','金地三千界，珠宫十二樓。',48,'全唐诗/poet.song.85000.json','["金地三千界，珠宫十二樓。", "人行仙佛土，春滿帝王州。", "邂逅羣雄擾，消磨百戰休。", "傷心歌舞地，錦纜起汀鷗。"]'),
('b7e04a98-8d3d-4c0e-9b5f-4c87c69dec2f','次韻王子欽上元感事三首  其三','孫覿','宋','宋诗','song-poetry','','[]','冰雪依春盡，雲山發興多。',48,'全唐诗/poet.song.85000.json','["冰雪依春盡，雲山發興多。", "微吟愁獨夜，小立佇斜河。", "社鼓村村急，樵音處處歌。", "呼僮掃月榭，不飲奈明何。"]'),
('62551fba-ae42-41d7-a2f4-20ef1ebd2552','題硤江蕭氏庵二首  其一','孫覿','宋','宋诗','song-poetry','','[]','雪屋清如洗，雲崖翠作堆。',48,'全唐诗/poet.song.85000.json','["雪屋清如洗，雲崖翠作堆。", "破扉風自掩，敗壁雨先頹。", "野色初還柳，林香尚有梅。", "滄江千萬頃，一鳥鏡中回。"]'),
('d9aeb554-2c0e-448a-bda0-cb929d318fb4','題硤江蕭氏庵二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雲逐歸心亂，山隨望眼賖。',48,'全唐诗/poet.song.85000.json','["雲逐歸心亂，山隨望眼賖。", "疏林欹晚照，淺溜咽春沙。", "客路三千過，僧窗一笑譁。", "此生安稅駕，有地即爲家。"]'),
('d64af5de-0ae0-4d48-bade-318534952528','思賢堂蕭君築室江上館李先之先之既沒李伯紀其堂曰思賢云二首  其一','孫覿','宋','宋诗','song-poetry','','[]','扁榜銀鉤勁，褒題袞相尊。',48,'全唐诗/poet.song.85000.json','["扁榜銀鉤勁，褒題袞相尊。", "天邊玉樓去，江上草堂存。", "蠅附俄千里，龍登有一門。", "蕭郎傳舊業，擊水看溟鯤。"]'),
('4289e5b8-f1a9-468b-a816-fe6c6e31a34e','思賢堂蕭君築室江上館李先之先之既沒李伯紀其堂曰思賢云二首  其二','孫覿','宋','宋诗','song-poetry','','[]','相國開藩日，摳衣放鷁時。',48,'全唐诗/poet.song.85000.json','["相國開藩日，摳衣放鷁時。", "碧油來弭節，彩筆坐題詩。", "有客皆如此，知君更不疑。", "相逢一笑喜，空恨十年遲。"]'),
('dcebd1bd-3d00-4364-9429-a90341345fb9','宿善法寺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','野寺知名久，歸鞍試一尋。',48,'全唐诗/poet.song.85000.json','["野寺知名久，歸鞍試一尋。", "亂山迎晚眺，萬木拱春臨。", "逸想超神界，安禪見佛心。", "時參鼻端白，趺坐息深深。"]'),
('54d56db5-4868-4715-9435-d748be36a2b9','宿善法寺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雪漲春光動，雲歸暮塢深。',48,'全唐诗/poet.song.85000.json','["雪漲春光動，雲歸暮塢深。", "巖棲塵不到，禪貌老難侵。", "野虎風生嘯，哀猿月伴吟。", "荒鷄號五點，說盡落星心。"]'),
('e4ea1815-64f7-4e28-989d-883a9599f8ec','再賦二首  其一','孫覿','宋','宋诗','song-poetry','','[]','水繞禪窗浄，香凝古殿深。',48,'全唐诗/poet.song.85000.json','["水繞禪窗浄，香凝古殿深。", "讀書不求解，酬古聊自斟。", "塔鈴已無語，匣琴猶有心。", "獨謠西閣夜，風滿快哉襟。"]'),
('2ec96cef-f544-405d-bea4-22c5d0f8e0f7','再賦二首  其二','孫覿','宋','宋诗','song-poetry','','[]','愛竹門可款，命車壑初尋。',48,'全唐诗/poet.song.85000.json','["愛竹門可款，命車壑初尋。", "烏啼春院静，人語夜堂深。", "鼠迹留僧鉢，蝸涎換佛金。", "鄰翁笑相命，春酌夜沈沈。"]'),
('07a6fad7-0696-4216-b3ed-71fb6f5f7f42','天長寺','孫覿','宋','宋诗','song-poetry','','[]','江行蕭家峽，路入天長寺。',48,'全唐诗/poet.song.85000.json','["江行蕭家峽，路入天長寺。", "眈眈千步廊，植杖聊一愒。", "山對逐客愁，花濺寒食泪。", "提壺苦勸人，何物關汝事。"]'),
('5833b34c-5366-4339-b9d6-fbc5cb810fb3','次韻王子欽雨中','孫覿','宋','宋诗','song-poetry','','[]','夢斷行雲去，詩成急雨催。',48,'全唐诗/poet.song.85000.json','["夢斷行雲去，詩成急雨催。", "霏霏嘘谷滿，閃閃映空來。", "出岫非無意，爲霖信有材。", "故園小桃李，昨夜一時開。"]'),
('a3d61bdf-4611-40c2-a1aa-b639058fcf05','襲明登仕出示尊公家傳留讀數過撫卷太息賦小詩歸之','孫覿','宋','宋诗','song-poetry','','[]','鼻祖有殊相，耳孫信多賢。',48,'全唐诗/poet.song.85000.json','["鼻祖有殊相，耳孫信多賢。", "閲世已黄壤，傳家尚青氈。", "妙語今作者，生氣猶凜然。", "便須勒蒼珉，揭此宰樹邊。"]'),
('67e4da7b-089b-4d7c-ad92-a211e373d48e','再過天長寺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','巖姿露天巧，地勝延隙光。',48,'全唐诗/poet.song.85000.json','["巖姿露天巧，地勝延隙光。", "鯨怒四海鬬，蝸跧一身藏。", "逃空真樂見，憩寂幽夢長。", "燈暗不復續，臥看月侵牀。"]'),
('3a8695d4-a051-4c6e-a072-0d6b3b3ef6c8','再過天長寺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','山立起平案，松偃臥枕岡。',48,'全唐诗/poet.song.85000.json','["山立起平案，松偃臥枕岡。", "尚憐桃靨小，已見麥頭昂。", "檢事關兵氣，逃禪入醉鄉。", "平生江海興，一棹付慈航。"]'),
('227381f5-a569-4012-9335-75c00f57166e','利見置酒燕超軒襲明賦詩次韻二首  其一','孫覿','宋','宋诗','song-poetry','','[]','杯行到手莫留殘，忍聽金鐘吼夜闌。',64,'全唐诗/poet.song.85000.json','["杯行到手莫留殘，忍聽金鐘吼夜闌。", "紅雨亂飄花帽動，碧雲吹斷玉笙寒。", "破除孤悶千痾散，邂逅良圖一笑歡。", "老去便須勤秉燭，對花渾似霧中看。"]'),
('ee82e16f-640e-4823-97ec-e5c3282a864d','利見置酒燕超軒襲明賦詩次韻二首  其二','孫覿','宋','宋诗','song-poetry','','[]','芋火鶉衣對懶殘，銅瓶泣雨又更闌。',64,'全唐诗/poet.song.85000.json','["芋火鶉衣對懶殘，銅瓶泣雨又更闌。", "枕流洗耳真堪笑，映雪看書且耐寒。", "共惜分襟能幾日，直須把酒罄交歡。", "風流喜見佳公子，未信窮途白眼看。"]'),
('df753d0b-61b1-4354-9222-24bac73e7b61','分宜道中','孫覿','宋','宋诗','song-poetry','','[]','老牯挽犁泥沒膝，剡剡青秧鍼水出。',64,'全唐诗/poet.song.85000.json','["老牯挽犁泥沒膝，剡剡青秧鍼水出。", "大麥登場小麥黄，桑柘葉大蠶滿筐。", "猿鳥初呼聚儔侣，繅絲百箔聞好語。", "此時物色不可孤，勸君沽酒提壺盧。"]'),
('e68c7381-f308-4773-a9b4-1985957dedf7','宿袁州城外祥符觀越日徙糾廨舍','孫覿','宋','宋诗','song-poetry','','[]','宜春客舍無一席，古觀獨眠不能夕。',64,'全唐诗/poet.song.85000.json','["宜春客舍無一席，古觀獨眠不能夕。", "破屋颼颼人雨立，空林嘖嘖蛩夜績。", "青袍白馬郡督郵，晨門過我鳴前騶。", "不求五斗彭澤米，且臥百尺陳登樓。"]'),
('9041ec03-da66-4ef8-b3b2-99fa7d7d1764','萍鄉縣','孫覿','宋','宋诗','song-poetry','','[]','雲夢青邱蟠楚藪，萍實江邊大如斗。',96,'全唐诗/poet.song.85000.json','["雲夢青邱蟠楚藪，萍實江邊大如斗。", "故壘摧頹百戰餘，舊事傳流千載後。", "青崖半裂蒼兕吼，空陂突過黄狐走。", "山深日落少人行，寂寥鳴蜩嘒高柳。", "江湖一夢三年久，慰我漂零一杯酒。", "羣盜須降漢赤眉，故侯辦作秦黔首。"]'),
('04e18528-963b-45df-b12f-c81f98b708d2','安仁縣有大第一區官兵縱暴主人谷氏避不敢居三年矣縣尹常館過客於第中賦主人避地二首  其一','孫覿','宋','宋诗','song-poetry','','[]','主人避地臥荒村，道傍故宅今仍存。',64,'全唐诗/poet.song.85000.json','["主人避地臥荒村，道傍故宅今仍存。", "烏鳥呼風白日静，藤蘿掛月蒼煙昏。", "壁立削鐵千步垣，客子不敢窺其門。", "一時勝事那能說，撞鍾擊鼓行金尊。"]'),
('b652a431-fdb4-48f1-bcf3-61df822c9df5','安仁縣有大第一區官兵縱暴主人谷氏避不敢居三年矣縣尹常館過客於第中賦主人避地二首  其二','孫覿','宋','宋诗','song-poetry','','[]','華榱翠桷刻蛟螭，蒿艾不翦與户齊。',64,'全唐诗/poet.song.85000.json','["華榱翠桷刻蛟螭，蒿艾不翦與户齊。", "野鼠羣行晝躡壁，山鬼一腳夜撼扉。", "胡騎掃迹今已非，官兵縱暴來無時。", "千炷眈眈四壁立，主人避地何時歸。"]'),
('611f3b14-3553-4b84-919d-73d47cbc8c1f','衡州靈泉寺觀競渡二首  其一','孫覿','宋','宋诗','song-poetry','','[]','噴雪怒相搏，投虹貫其中。',48,'全唐诗/poet.song.85000.json','["噴雪怒相搏，投虹貫其中。", "張頤嚇北客，拍手笑南公。", "固自輕一死，終然鬭兩雄。", "踟躕倚山閣，得失謾鷄蟲。"]'),
('91b15bcb-b51a-47bc-8c8d-b7896657b12f','衡州靈泉寺觀競渡二首  其二','孫覿','宋','宋诗','song-poetry','','[]','健捷兩首虺，爬沙百足蚿。',48,'全唐诗/poet.song.85000.json','["健捷兩首虺，爬沙百足蚿。", "擊水羣鯨動，追風一鳥翩。", "壯心殊未已，怒臂欲無前。", "亦有旁觀者，跟跗奮兩肩。"]'),
('0527170f-a296-45bf-bb81-a85f2ffff011','即事','孫覿','宋','宋诗','song-poetry','','[]','落日投林去，低雲貼水飛。',48,'全唐诗/poet.song.85000.json','["落日投林去，低雲貼水飛。", "江翻半嶂倒，帆健一風肥。", "酒重傾蠻榼，歌清繞妓衣。", "城南多勝事，何必閬中稀。"]'),
('a0d569e9-a327-451c-9a30-1722a1d3a335','回雁峰','孫覿','宋','宋诗','song-poetry','','[]','三年踐蛇虺，一命抵豺虎。',144,'全唐诗/poet.song.85000.json','["三年踐蛇虺，一命抵豺虎。", "悠悠故園心，萬里崖嶠阻。", "祝融方司南，巨嶽鎮全楚。", "滄波噴石壁，白日灑飛雨。", "寥寥蒼梧帝，髯斷泣二女。", "斕斑竹上泪，濺血今如許。", "沈文弔湘纍，魚葬得死所。", "寂寞千載魂，故物但角黍。", "吾生將安歸，隨此瘴江浦。", "逐臣正南遊，倦鳥已北翥。", "放身秋崖上，萬壑赴一睹。", "干戈浩茫茫，安得兩翅羽。"]'),
('721601ce-d79a-4225-8941-fb4301ca208b','愚溪','孫覿','宋','宋诗','song-poetry','','[]','羣休眩鹿馬，獨覺辨澠淄。',240,'全唐诗/poet.song.85000.json','["羣休眩鹿馬，獨覺辨澠淄。", "蟲鳥豈知道，斷尾畏爲犧。", "草木詎有靈，衛足不如葵。", "智嚢樗里子，痴絕顧愷之。", "成壞繫所遭，何必陋昨非。", "儀曹天下士，失身蹈危機。", "一斥臥江海，南冠繫湘纍。", "不思蛇起陸，便作鳥擇栖。", "匿智以爲愚，更欲名其溪。", "溪山清可厲，溪上碧相圍。", "石底行翠虯，煙中抹修眉。", "一朝纊息定，白日斷履綦。", "叢祠翳篁竹，秋風生網絲。", "凜凜望千載，避世真吾師。", "故物不可尋，山川尚華滋。", "永懷西州動，興言北山移。", "欣然解其會，了了不復疑。", "獨醒亦何事，誓將餔糟醨。", "舉酒酹一觴，宛宛度兩旗。", "蕉黄配丹荔，歌此迎神詩。"]'),
('182cb1c8-71c9-44fd-8e61-9c938f062d8c','礲巖','孫覿','宋','宋诗','song-poetry','','[]','日上千峰亂，風涵萬壑秋。',96,'全唐诗/poet.song.85000.json','["日上千峰亂，風涵萬壑秋。", "兩崖折天罅，一水漲巖幽。", "絕岸飛橋過，尋源秉炬游。", "倚空翹翠葆，漱石走蒼虯。", "老樹攙天立，奔雲接地流。", "壯懷開浩蕩，病骨聳颼飀。", "皓首殊方去，清尊盡日留。", "無人與說似，勝事滿南州。"]'),
('0632b16f-d05f-4058-8a11-356afb3e3a0a','礲巖寺','孫覿','宋','宋诗','song-poetry','','[]','千松夾道直，一水抱村流。',72,'全唐诗/poet.song.85000.json','["千松夾道直，一水抱村流。", "清絕小叢林，繞舍竹修修。", "老僧慣見客，壞衲雪滿頭。", "野果折奇苞，畦蔬翦新柔。", "漂零五管去，邂逅一笑留。", "詩成寫君壁，紀此夢中遊。"]'),
('e0e9ce4b-72a4-4cf4-a550-1478e935d82c','靈泉寺','孫覿','宋','宋诗','song-poetry','','[]','窗户遙開紫翠間，小橋獨立聽潺潺。',64,'全唐诗/poet.song.85000.json','["窗户遙開紫翠間，小橋獨立聽潺潺。", "意諧獨有清風共，興盡聊随落照還。", "但見虚童蒙白帢，且無瀧吏發騂顔。", "風花雨葉元無定，何必區區戀故山。"]'),
('ceb013d5-cf79-48b0-a5a8-fde4b31989b6','次桂州二首  其一','孫覿','宋','宋诗','song-poetry','','[]','過嶺逢人問象州，瘴煙如海蹴天浮。',32,'全唐诗/poet.song.85000.json','["過嶺逢人問象州，瘴煙如海蹴天浮。", "三閭逐客何將到，八桂宜人且少休。"]'),
('ee54b763-fc11-4f0c-a9c9-64e7aa3883c1','次桂州二首  其二','孫覿','宋','宋诗','song-poetry','','[]','江上煙雲翠作堆，倚天青壁雁飛回。',32,'全唐诗/poet.song.85000.json','["江上煙雲翠作堆，倚天青壁雁飛回。", "神州一望三千里，不是南遷肯獨來。"]'),
('e4d7df0a-88cc-4990-b2e9-4d4af5ecb992','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 八桂堂','孫覿','宋','宋诗','song-poetry','','[]','橘中隱商顔，桑下蔭羽葆。',96,'全唐诗/poet.song.85000.json','["橘中隱商顔，桑下蔭羽葆。", "古人日已遠，貴跡今未掃。", "英英八桂堂，屹立表衆草。", "名随五柳傳，壽待三松倒。", "南堂駐金莭，伏劍收蠻獠。", "駪駪立萬馬，獵獵卷千纛。", "元戎領客來，小摘羞澗藻。", "醉纈亂繁花，移來插晴昊。"]'),
('edf9af10-e0c9-40cf-9e96-2d71923feac9','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 七星巖','孫覿','宋','宋诗','song-poetry','','[]','十載汙修門，簪槖侍帝垣。',96,'全唐诗/poet.song.85000.json','["十載汙修門，簪槖侍帝垣。", "五雲深莫窺，衆星拱以繁。", "一坐牘背書，身落海上村。", "山川發餘想，鍾鼓眩昔聞。", "星圖煥斗極，兩兩錯地文。", "今日復何日，乘槎造天閽。", "日月起可挾，參井立能捫。", "誰當揭其柄，爲我酌瀛尊。"]'),
('b0fda03d-31e0-4b97-8e23-c90d909db2af','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 栖霞洞','孫覿','宋','宋诗','song-poetry','','[]','飛仙巢三山，弱水環四溟。',96,'全唐诗/poet.song.85000.json','["飛仙巢三山，弱水環四溟。", "誰知黄茅嶺，自有白玉京。", "獨曳一枝筇，梯空上青冥。", "蟾飛墮八桂，石隕化七星。", "幽幽炬火然，異狀不可名。", "垂天紫雲蓋，插地翠羽屏。", "已無俗士駕，上有遷客經。", "敢言居夷陋，妙絕冠平生。"]'),
('780b0119-994d-4411-b696-56a81bfea4af','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 來風亭風洞在七星巖之下曾公巖之右大暑時有風出穴中泠然如冰雪被體不可久留舊有亭摧壞始撤而新之趙漕少隐置酒落其成名曰來風云','孫覿','宋','宋诗','song-poetry','','[]','萬樹張大傘，千嶂臥獨龍。',96,'全唐诗/poet.song.85000.json','["萬樹張大傘，千嶂臥獨龍。", "彤雲竟天起，火墜九日紅。", "投老落蠻嶠，暍死愁吳儂。", "風流貴公子，一笑林下逢。", "蒼崖折天罅，中有萬里風。", "習習駕兩腋，飄飄落瓊宫。", "草木嘯竽籟，澗谷酣笙鏞。", "披我快哉襟，誰能辨雌雄。"]'),
('4d88158f-ac0f-48df-8197-a69fd5e25b87','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 龍隱巖','孫覿','宋','宋诗','song-poetry','','[]','跳波觸石喧，古木抱崖擁。',96,'全唐诗/poet.song.85000.json','["跳波觸石喧，古木抱崖擁。", "老蛟壓泥蟠，一笑作潭洞。", "孤峰起崷崒，哀壑浩呼汹。", "腥風噤蛙淫，凍雨落毛氄。", "凜凜白晝寒，瘴髪立盡聳。", "旱氣曛日黄，縮爪但陰拱。", "悠然四大海，歛此一毛孔。", "安得化爲霖，蕙葉有光寵。"]'),
('173273b0-6382-46f1-9b5b-aad227bde3d0','桂林山水奇麗妙絕天下柳子厚記訾家洲亭粗見其略余以六月六日度桂林嶺欲更僕詣象属暑甚遂少留日從諸公于巖穴之下穹林巨壑近接闤閽之中遠不過城闉之趾居高望遠夸雄鬭麗殆不可狀擇其尤者以十詩記之名之曰桂林十詠 曾公巖曾子宣丞相元豐中守桂林遊七星山始見此洞芟薙草莽平坦方廣可容數百人悉布磚甓之入洞十餘步有澗水横其前不可涉公梁石爲橋以便遊者號曾公巖','孫覿','宋','宋诗','song-poetry','','[]','羣峰依天立，萬馬屹不動。',96,'全唐诗/poet.song.85000.json','["羣峰依天立，萬馬屹不動。", "風欹紫玉珂，雨暗青絲鞚。", "相君千里目，渺渺孤鴻送。", "披雲覷天巧，鑿翠出巖洞。", "中空貫長虹，側立剖大甕。", "宛宛臥石梁，欲起時地控。", "玉棺已上天，甘棠有遺誦。", "獨餘澗底泉，時與幽人共。"]'),
('66398f01-4b7c-4489-b5b2-8df8fca4e7b3','雉山巖昔有僧結庵此山中誦法華經野雉日一集聽之至終卷乃去率以爲常忽數日不至山下有婦人産子腰脇間餘雉毛數寸寺有石紀其事','孫覿','宋','宋诗','song-poetry','','[]','頑石解首肯，老松聞肘回。',96,'全唐诗/poet.song.85000.json','["頑石解首肯，老松聞肘回。", "野鳥集隅坐，聽法時一來。", "山僧古佛徒，一龕寄巖隈。", "哀此墮卵狀，點礫妙奪胎。", "休去復歇去，呱呱見啼孩。", "獨此腹脇餘，斑斑尚毰毸。", "精通日月貫，義動金石開。", "異事垂千年，仆碑臥蒼苔。"]'),
('48e94835-fa19-4f53-8b16-f439ed934964','雉山巖昔有僧結庵此山中誦法華經野雉日一集聽之至終卷乃去率以爲常忽數日不至山下有婦人産子腰脇間餘雉毛數寸寺有石紀其事 永寧寺佛閣五代末馬氏據有荆廣時其子賨所營也閲二百年壯麗如故有畫像存焉狀貌魁梧稱其閣云','孫覿','宋','宋诗','song-poetry','','[]','一念去來想，萬象起滅境。',96,'全唐诗/poet.song.85000.json','["一念去來想，萬象起滅境。", "方寸有所營，可與天地永。", "五季日尋戈，四海環沸鼎。", "炎方一旅平，烽冷夜徹警。", "梯空出高營，飛閣冠五嶺。", "照耀人天上，變滅彈指頃。", "故物二百年，虎死尚炳炳。", "小立梯層闌，烏鳥聚落景。"]'),
('2ac4ae7e-227e-4bd4-8c79-268a276d155d','雉山巖昔有僧結庵此山中誦法華經野雉日一集聽之至終卷乃去率以爲常忽數日不至山下有婦人産子腰脇間餘雉毛數寸寺有石紀其事 西山超然亭','孫覿','宋','宋诗','song-poetry','','[]','龐區翳榛莽，地瘴藏百怪。',96,'全唐诗/poet.song.85000.json','["龐區翳榛莽，地瘴藏百怪。", "西山何軒軒，拔脚風塵外。", "中縈一綫蟠，側立兩壁對。", "旁連九疑高，遠控三湘大。", "孤亭坐林杪，俯見飛鳥背。", "號弓泣二女，禦魅竄四罪。", "誰去窘拘囚，故自脱天械。", "飄飄思凌雲，萬里風雨會。"]'),
('6186b482-63b3-4950-b7f0-26b51de5c6e5','雉山巖昔有僧結庵此山中誦法華經野雉日一集聽之至終卷乃去率以爲常忽數日不至山下有婦人産子腰脇間餘雉毛數寸寺有石紀其事 虞氏隱居雷守虞沇避地桂林結茅江上萬山環立二水交流遊客過其下皆有忘歸與卜鄰之意','孫覿','宋','宋诗','song-poetry','','[]','山色洗眼青，遙見紫翠重。',96,'全唐诗/poet.song.85000.json','["山色洗眼青，遙見紫翠重。", "江光照肌白，靧作冰雪容。", "問誰三間茅，散我九節筇。", "江聲過席上，山影落杯中。", "主人樂忘歸，臥聽鼓角雄。", "檢點屐齒痕，斕斑尚苔封。", "寂寂春蘿月，蕭蕭秋桂風。", "何日賦歸來，庭柯撫孤松。"]'),
('52f1f82e-500c-492b-85b6-da39c831a284','翠屏洞二首  其一','孫覿','宋','宋诗','song-poetry','','[]','團圞千嶂抱，窈窕一屏開。',48,'全唐诗/poet.song.85000.json','["團圞千嶂抱，窈窕一屏開。", "翠黛愁將斂，烏雲睡作堆。", "倚松真漫爾，藉草亦悠哉。", "更有陽臺雨，朝朝暮暮來。"]'),
('78ee5ae5-9401-4806-9307-545094ac80d7','翠屏洞二首  其二','孫覿','宋','宋诗','song-poetry','','[]','千仞欝嵯峨，纖纖翠錯磨。',48,'全唐诗/poet.song.85000.json','["千仞欝嵯峨，纖纖翠錯磨。", "霧鬟篸碧玉，風幔卷青羅。", "鵲喜窺人語，鶯嬌倚樹歌。", "江花紅濕處，彷像襪凌波。"]'),
('fc9bd71f-1d63-4ed3-bdac-7cb6f5e265f3','飲修仁茶','孫覿','宋','宋诗','song-poetry','','[]','煙雲吐長崖，風雨暗古縣。',72,'全唐诗/poet.song.85000.json','["煙雲吐長崖，風雨暗古縣。", "竹輿赬兩肩，弛擔息微倦。", "茗飲初一嘗，老父有芹獻。", "幽姿絕媚嫵，著齒得瞑眩。", "昏昏嗜睡翁，喚起風灑面。", "亦有不平心，盡從毛孔散。"]'),
('770f2f57-4c63-4985-bacf-62c7602fddc3','九日次獻花鋪','孫覿','宋','宋诗','song-poetry','','[]','古路三叉口，青裙兩髻丫。',48,'全唐诗/poet.song.85000.json','["古路三叉口，青裙兩髻丫。", "更無陶令菊，空想衛公花。", "破屋堆黄葉，清江繚白沙。", "殷勤邀一醉，蜑酒壓梨楂。"]'),
('bba63aa7-a1e9-47a3-b9bf-61c060ffc898','入象州界','孫覿','宋','宋诗','song-poetry','','[]','須賈之罪髮可數，張儀之辨舌空存。',64,'全唐诗/poet.song.85000.json','["須賈之罪髮可數，張儀之辨舌空存。", "以身藏怨今如此，不死投荒感上恩。", "殊俗若爲投緩急，故交何處問寒温。", "多情鳥鵲真幽伴，莫遣張羅翟尉門。"]'),
('17e8fedc-f0d9-49ff-9f2f-21d9c2071172','到象州寓行衙太守陳容德攜酒見過二首  其一','孫覿','宋','宋诗','song-poetry','','[]','萬里南來亦偶然，一杯相属豈非天。',65,'全唐诗/poet.song.85000.json','["萬里南來亦偶然，一杯相属豈非天。", "直從尺五城南社，行盡潮南陽路八千。", "三夜故人應入夢，五漿客舍有誰先。", "使君遙簇花間馬，欲伴愁人到酒邊。"]'),
('443ec8c9-1cd6-4ba4-ae3f-35d4e31cf372','到象州寓行衙太守陳容德攜酒見過二首  其二','孫覿','宋','宋诗','song-poetry','','[]','飣坐黄甘噀手香，堆盤丹荔照人光。',64,'全唐诗/poet.song.85000.json','["飣坐黄甘噀手香，堆盤丹荔照人光。", "莫辭蜑酒一尊赤，會壓瘴茅千里黄。", "未省讒言遭薏苡，直將空腹傲檳榔。", "酒醒夢覺知何處，樹影參差月滿廊。"]'),
('0314f692-e723-484c-8c69-b75fb18e1b2e','南山寺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','千丈雲根蔭此邦，沈沈寒影臥秋江。',64,'全唐诗/poet.song.85000.json','["千丈雲根蔭此邦，沈沈寒影臥秋江。", "潭空映日蒼虬動，煙煖翹沙白鷺雙。", "夢覺灘聲喧客枕，吟餘竹色滿僧窗。", "詩成絕叫層樓上，聽我洪鐘萬石撞。"]'),
('8bca1796-840b-434c-86da-5502e846b345','南山寺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','安心是藥本非禪，遇勝欣隨意所便。',64,'全唐诗/poet.song.85000.json','["安心是藥本非禪，遇勝欣隨意所便。", "嚼蕊拈花身老矣，穿雲涉水思茫然。", "行逢酒伴操觚去，倦憩僧窗借榻眠。", "寄語桃源問津者，人中今是地行仙。"]'),
('707963ac-79ba-4bb3-83cf-12c50ff46955','象州行衙井泉甘冷太守而下皆飲此井','孫覿','宋','宋诗','song-poetry','','[]','雞號更五點，衆星尚煌煌。',72,'全唐诗/poet.song.85000.json','["雞號更五點，衆星尚煌煌。", "殘燭半吞吐，宿酒疑在亡。", "碧井陰修梧，林疏月汪汪。", "嶠南瘴癘地，飲此冰玉光。", "晨瓶出雪乳，一漱病齒涼。", "衆汲欲盡及，匏尊得細嘗。"]'),
('1ea11097-8248-48bc-a334-009e6275122b','題象守坐嘯堂','孫覿','宋','宋诗','song-poetry','','[]','治國如烹鮮，馭民如牧羊。',144,'全唐诗/poet.song.85000.json','["治國如烹鮮，馭民如牧羊。", "薫狐蘆自焚，投鼠器必傷。", "曹侯百世師，獄市寄全齊。", "天下本無事，庸人勿擾之。", "危機蹈潛弩，惡吏冠虓虎。", "飛走豈不高，搖足墮網罟。", "使君古太邱，妙割無全牛。", "班春千騎曉，長嘯萬壑秋。", "棠陰日轉午，風簷翠交舞。", "問道舍蓋公，誦詩選何武。", "渭水占熊羆，萬里笞羌夷。", "試磨南山石，更草中興碑。"]'),
('b0f737f9-f406-4251-984d-7479bb7b0ba0','别象州陳守容德','孫覿','宋','宋诗','song-poetry','','[]','三年客殊方，榮悴不堪說。',120,'全唐诗/poet.song.85000.json','["三年客殊方，榮悴不堪說。", "迢迢家萬里，奄奄命一髮。", "使君古丈夫，興哀在縲絏。", "平生風馬牛，舊職比鶼蹷。", "欣然一笑粲，彼此百憂結。", "皇恩下天扉，淚泣孤臣血。", "行廚洗玉盤，載酒助歡悦。", "庖珍問五鯖，餅字炊十裂。", "徙突今未黔，班草永一訣。", "何須更秉燭，端是夢中别。"]'),
('3d27df3e-06d9-421b-86c9-0f4478e30d11','雉山寺青羅閣','孫覿','宋','宋诗','song-poetry','','[]','蠻村避謗三年過，野寺尋僧半日閑。',64,'全唐诗/poet.song.85000.json','["蠻村避謗三年過，野寺尋僧半日閑。", "小檻吹香花漠漠，斷崖漱碧水潺潺。", "桄榔葉底秋聲滿，柏子煙中午夢還。", "便擬買舟隨釣叟，一蓑煙雨繫滄灣。"]'),
('72f2a805-cd58-41f8-897e-aecbb28ac4a5','蒙亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','小築三間足，雄包萬象并。',48,'全唐诗/poet.song.85000.json','["小築三間足，雄包萬象并。", "遙波通極浦，落日抱孤城。", "小語千巖應，長歌百蟄驚。", "坐看衣屨上，漠漠晚雲生。"]'),
('2a802be3-e938-4549-b5c1-32e10c901f10','蒙亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','落拓詩酒伴，疏慵粥飯僧。',48,'全唐诗/poet.song.85000.json','["落拓詩酒伴，疏慵粥飯僧。", "盪胸閑遠抱，拄頰見高稜。", "鳥倦猶聞語，蛟寒正可罾。", "一區如可卜，吾不愧陳登。"]'),
('b7a3c41a-a4f9-4b9d-bdc1-5c1f6939ec11','七星觀','孫覿','宋','宋诗','song-poetry','','[]','丘壑心猶在，筋骸老可憎。',48,'全唐诗/poet.song.85000.json','["丘壑心猶在，筋骸老可憎。", "倚筇欣小愒，躧履看先登。", "神馬何須駕，尻輿本自興。", "九關通一路，欲躡嶺雲升。"]'),
('2b115307-17e5-43ba-a18a-d08bb66e3660','發桂林劉帥立道同諸司出餞于甘棠渡口二首  其一','孫覿','宋','宋诗','song-poetry','','[]','行盡海北天，笑指湘南路。',72,'全唐诗/poet.song.85000.json','["行盡海北天，笑指湘南路。", "使君載酒醪，擁節東城駐。", "前驅千纛直，縱獵萬人呼。", "塵流翳白日，十里映黄霧。", "何人揖迎我，一葦横江渡。", "渺渺倦鴉翻，相隨歸薄暮。"]'),
('3f96fabb-ad2c-4d0d-a001-4dedbadb516c','發桂林劉帥立道同諸司出餞于甘棠渡口二首  其二','孫覿','宋','宋诗','song-poetry','','[]','洶洶萬號竅，颶風吹海渾。',72,'全唐诗/poet.song.85000.json','["洶洶萬號竅，颶風吹海渾。", "冥冥蔽一天，瘴雲埋日昏。", "南荒底日所，黄葦三家村。", "誰云花解笑，但有鳥能言。", "繆恩解南冠，歸路首北轅。", "酒行可以起，稚子候柴門。"]'),
('4c81c3d2-e10b-41cc-aee0-8e59ef6e3ccb','北歸過永永守趙君宰置酒萬石亭','孫覿','宋','宋诗','song-poetry','','[]','三湘陌上逐臣歸，萬石亭中送客時。',64,'全唐诗/poet.song.85000.json','["三湘陌上逐臣歸，萬石亭中送客時。", "拄杖披榛行莽蒼，汲泉磨蘚看魁奇。", "天傾五色遺媧補，谷變千年出峴碑。", "何似溪邊小桃李，向人膏面出風姿。"]'),
('697c5b01-2362-401c-9a29-968087c6e517','皇妃嶺','孫覿','宋','宋诗','song-poetry','','[]','濯濯漱壑泉，巖巖依天石。',48,'全唐诗/poet.song.85000.json','["濯濯漱壑泉，巖巖依天石。", "扶藜上秋空，一縷挂絕壁。", "胡爲乘此險，登臨風雨夕。", "千金戒垂堂，尊馭且莫叱。"]'),
('e9b39829-c338-4c48-9c19-37318eb5a7b2','過衡州舘于郡齋時太守裴夢貺督役于城上','孫覿','宋','宋诗','song-poetry','','[]','萬鍤風雨集，三令霜雪嚴。',48,'全唐诗/poet.song.85000.json','["萬鍤風雨集，三令霜雪嚴。", "適發半閭左，雅舂亦髠鉗。", "大事難慮始，掇龜寧復占。", "君看執扑者，端是邑中黔。"]'),
('16295e47-e854-4ecc-a49c-753720689cd7','宜春臺呈太守陳次明','孫覿','宋','宋诗','song-poetry','','[]','聞說宜春好，層臺試一登。',48,'全唐诗/poet.song.85000.json','["聞說宜春好，層臺試一登。", "隴泉悲瑟瑟，松雪見層層。", "孤絕煙中寺，微茫樹下僧。", "詩工傳寫妙，不數畫師能。"]'),
('b30bacb7-5f29-4386-ba0a-172dbc845a52','西齋','孫覿','宋','宋诗','song-poetry','','[]','二江戎馬後，宜春獨稱雄。',96,'全唐诗/poet.song.85000.json','["二江戎馬後，宜春獨稱雄。", "重垣抱金柅，巨塹疏玉虹。", "使君師齊相，佳處在酒中。", "百觚倒春醸，洗盡瘡痍空。", "西齋置一榻，時有客子從。", "我來属無事，新脫楚市舂。", "伴值呼浩然，驚座得孟公。", "欹眠看衙集，鼉鼓鳴逢逢。"]'),
('f094e4cb-fde5-464c-9cfb-dc62427b654c','再過曹山示如老','孫覿','宋','宋诗','song-poetry','','[]','不羡鵬飛運，聊隨雁北還。',48,'全唐诗/poet.song.85000.json','["不羡鵬飛運，聊隨雁北還。", "捫天上何嶺，犯雪過曹山。", "偶到萬里去，重來一夢間。", "觀河見如舊，雙鬢自斕斑。"]'),
('4b1f2d5d-5175-4bd6-88a3-da09c2163612','故侍御鄒公抱節亭','孫覿','宋','宋诗','song-poetry','','[]','一邱黄壤臥龍泉，光氣輪囷夜斗邊。',64,'全唐诗/poet.song.85000.json','["一邱黄壤臥龍泉，光氣輪囷夜斗邊。", "長吏青氈無舊物，拾遺華屋有修椽。", "鳯麟毛骨皆如此，水石風流尚宛然。", "亭下不生閑草木，籜龍無數欲參天。"]'),
('7864f760-79a9-4580-bdfe-216476124903','鄒志新追路至甬橋有買田之約三衢道中作詩寄之','孫覿','宋','宋诗','song-poetry','','[]','首路冰雪嚴，過家梅柳動。',144,'全唐诗/poet.song.85000.json','["首路冰雪嚴，過家梅柳動。", "故人一笑隔，千里勞遠夢。", "夫君具眼隻，閲世妙百中。", "嗜好和酸醎，不與俗人共。", "我老臥瘴氛，摧撓讒夫衆。", "敗履誰見收，乘槎子宜從。", "歸袖風中翻，翩若孤雲縱。", "殷勤三日别，折柳天下送。", "那知漢網疏，欲問周鼎重。", "江臯兩牛鳴，塞壘萬絃控。", "終當受一廛，竟欲鄰二仲。", "請師樊遲圃，共抱漢陰甕。"]'),
('a9e34d26-8554-49c3-86ea-6cbefebca40f','送王循道赴省試四首  其一','孫覿','宋','宋诗','song-poetry','','[]','龍擾已可屠，瓠堅今可攻。',48,'全唐诗/poet.song.85000.json','["龍擾已可屠，瓠堅今可攻。", "不辭千金費，莫計五石容。", "藏器古有待，用大難爲工。", "平生不龜手，佇此一戰封。"]'),
('487ad4ad-6287-4fa4-b3ed-90d83f485adb','送王循道赴省試四首  其二','孫覿','宋','宋诗','song-poetry','','[]','千金市駿骨，想像不可逢。',48,'全唐诗/poet.song.85000.json','["千金市駿骨，想像不可逢。", "安知轅軛下，磈礧臥肉騣。", "天廐四十萬，一洗凡馬空。", "葉公莫驚走，始信真有龍。"]'),
('97f5fa75-301c-4a66-bb54-5003cf88a07d','送王循道赴省試四首  其三','孫覿','宋','宋诗','song-poetry','','[]','秦俗自擊缶，齊人善吹竽。',48,'全唐诗/poet.song.85000.json','["秦俗自擊缶，齊人善吹竽。", "寧聞牛角鬬，莫奏鳯將雛。", "獨唱誰能曉，彌天和欲無。", "中郎非俚耳，爲斵爨中枯。"]'),
('b40812aa-81b4-458e-8f7c-08abca35589a','送王循道赴省試四首  其四','孫覿','宋','宋诗','song-poetry','','[]','殖綽拜勇爵，儒冠堪溺中。',48,'全唐诗/poet.song.85000.json','["殖綽拜勇爵，儒冠堪溺中。", "可憐毛錐子，譊譊尚争雄。", "夫君口擊賦，陳言賤雕蟲。", "行以立談間，可折萬里衝。"]'),
('1798957b-da28-4ee3-b36a-039aced4b603','過臻闍黎三首  其一','孫覿','宋','宋诗','song-poetry','','[]','龜肌鶴瘦老臞仙，壞衲穿空雪滿顛。',32,'全唐诗/poet.song.85000.json','["龜肌鶴瘦老臞仙，壞衲穿空雪滿顛。", "無數巖花開自落，青山相對獨依然。"]'),
('e18cd994-0c14-476e-960e-0a15603b035d','過臻闍黎三首  其二','孫覿','宋','宋诗','song-poetry','','[]','髯龍遠舍立疏疏，白甲蒼皮十抱餘。',32,'全唐诗/poet.song.85000.json','["髯龍遠舍立疏疏，白甲蒼皮十抱餘。", "當日青青折釵股，如今老結已傳車。"]'),
('0f392c63-62fa-4b93-b4ec-2ffc333917df','過臻闍黎三首  其三','孫覿','宋','宋诗','song-poetry','','[]','莫便將心到處安，小窗趺坐兩蒲團。',32,'全唐诗/poet.song.85000.json','["莫便將心到處安，小窗趺坐兩蒲團。", "芋魁半熟通紅火，鼻涕垂頤對懶殘。"]'),
('63f0c329-9b4e-4cbf-a997-10539de6e8c5','送智海上人二首  其一','孫覿','宋','宋诗','song-poetry','','[]','大師興趣在江湖，拄杖扶行穩當車。',32,'全唐诗/poet.song.85000.json','["大師興趣在江湖，拄杖扶行穩當車。", "苦要詩翁談生活，穿雲涉水到西徐。"]'),
('ab0d4115-5800-429f-b6b0-69288a8a43f5','送智海上人二首  其二','孫覿','宋','宋诗','song-poetry','','[]','折鼎支磚石半欹，拾薪乞米爲朝饑。',32,'全唐诗/poet.song.85000.json','["折鼎支磚石半欹，拾薪乞米爲朝饑。", "昏昏一點炊煙裏，見我邯鄲夢覺時。"]'),
('729d2ef6-eadc-4d14-848b-a7ee1eda1cd6','馬跡上冢遇大風雨書僧壁二首  其一','孫覿','宋','宋诗','song-poetry','','[]','松竹騷騷繞舍鳴，沙頭一夜連雨明。',32,'全唐诗/poet.song.85000.json','["松竹騷騷繞舍鳴，沙頭一夜連雨明。", "衝泥裹飯澆新冢，野哭干霄共一聲。"]'),
('3fad9daa-e0b5-48ca-b3ae-63c60b589a05','馬跡上冢遇大風雨書僧壁二首  其二','孫覿','宋','宋诗','song-poetry','','[]','白帢排肩上冢歸，饑烏攫肉紙錢飛。',32,'全唐诗/poet.song.85000.json','["白帢排肩上冢歸，饑烏攫肉紙錢飛。", "東家已改清明節，一點炊煙上翠微。"]'),
('3742903d-40c6-4f93-b424-8e6ac7d73c1a','示相者','孫覿','宋','宋诗','song-poetry','','[]','漢嬖寧聞通餓死，舂黥自說布當刑。',32,'全唐诗/poet.song.85000.json','["漢嬖寧聞通餓死，舂黥自說布當刑。", "侯王將相元無種，試向人奴覓衛青。"]'),
('a8439ec1-860c-4ab7-ae44-126b774c4416','某靖國中與時發同寓郡庠潛心之北窗凡三年而别别後三十五年復相遇於荆溪頤山之下蒼顔白髪互相驚歎追數一時同舍生在鬼録者十八九獨兩翁無恙耳方築室山中以老焉將與時發杖屨往來如杜子美所謂兩老者迺賦詩而以爲之先','孫覿','宋','宋诗','song-poetry','','[]','簪盍盡晨夜，裾連講肆朝。',264,'全唐诗/poet.song.85000.json','["簪盍盡晨夜，裾連講肆朝。", "昂霄初一睹，歷塊已先超。", "竟臥鹽輜老，終遺爨鼎焦。", "月分千里共，波折兩萍漂。", "卷地邊塵合，彌天刼火燒。", "途窮歌兕虎，巢燬賦鷦鷯。", "稚子開三徑，先生守一瓢。", "但空囊似腹，莫折磬如腰。", "幘墮樵風過，袍斑釣雪饒。", "蝸盤憐角縮，鼠黠看鬚搖。", "鳧雁吾何筭，松筠子後凋。", "共憐身獨在，相視意俱消。", "負釁投炎海，全生託聖朝。", "那知龜是鼈，已見鵬如雕。", "楚玉號三獻，堯雲煥九霄。", "啼烏占夜喜，歸馬弄風驕。", "便殺雞爲黍，休尋鹿覆蕉。", "並鄰如可卜，半道不須邀。", "汲井澆桑本，攜鉏蒔藥苗。", "千端身外事，一噱醉中囂。", "蟻泛蓮垂葉，魚烹柳貫條。", "往來成二老，隨分各逍遙。"]'),
('fa61e22c-88c7-47a4-bec9-0221da71b09f','次韻王次之龍圖六絕  其一','孫覿','宋','宋诗','song-poetry','','[]','撥雪披雲粥面濃，三盃困臥北窗風。',32,'全唐诗/poet.song.85000.json','["撥雪披雲粥面濃，三盃困臥北窗風。", "悠然一夢南柯去，千騎靴刀帕首紅。"]'),
('f2edd351-acb2-4d28-b429-d5b2d3599599','次韻王次之龍圖六絕  其二','孫覿','宋','宋诗','song-poetry','','[]','蕨芽載土笋牙叢，青子森森褪小紅。',32,'全唐诗/poet.song.85000.json','["蕨芽載土笋牙叢，青子森森褪小紅。", "與物無情吾老矣，如今休恨五更風。"]'),
('ab951a93-f919-49a9-93f9-4d4e1caf8824','次韻王次之龍圖六絕  其三','孫覿','宋','宋诗','song-poetry','','[]','青梅著子欲生仁，始見新紅觸眼新。',32,'全唐诗/poet.song.85000.json','["青梅著子欲生仁，始見新紅觸眼新。", "李徑桃蹊俱掃地，一枝獨自古時春。"]'),
('913e03bc-dc10-4a07-bdb0-d8922ed0ae27','次韻王次之龍圖六絕  其四','孫覿','宋','宋诗','song-poetry','','[]','一種奇葩絕衆芳，朅來當户見鉏傷。',32,'全唐诗/poet.song.85000.json','["一種奇葩絕衆芳，朅來當户見鉏傷。", "猶看紉作幽人佩，獨步修門擅國香。"]'),
('6c264636-9344-48fc-a3e8-a0b0174ee387','次韻王次之龍圖六絕  其五','孫覿','宋','宋诗','song-poetry','','[]','老去傷春只自嗟，追尋陳迹問京華。',32,'全唐诗/poet.song.85000.json','["老去傷春只自嗟，追尋陳迹問京華。", "更搔短髮西南望，病眼昏昏淚渺花。"]'),
('73ec63c3-eebc-4643-8e51-0aa3908c0271','次韻王次之龍圖六絕  其六','孫覿','宋','宋诗','song-poetry','','[]','柔桑采采樹頭稀，蠶婦攜籠陌上歸。',32,'全唐诗/poet.song.85000.json','["柔桑采采樹頭稀，蠶婦攜籠陌上歸。", "縣吏催錢星火急，只將敗壁倚空機。"]'),
('344f6048-fa96-4a65-ad8d-b72caf5730d5','詩示天寧晤老二首  其一','孫覿','宋','宋诗','song-poetry','','[]','錫號延春閣，知名四十年。',48,'全唐诗/poet.song.85000.json','["錫號延春閣，知名四十年。", "向來香一瓣，恭爲佛佗禪。", "霧沐山藏豹，風餐葉翳蟬。", "寥寥千佛後，又見一燈傳。"]'),
('c01c9e57-330c-4664-9db9-8b068432bd58','詩示天寧晤老二首  其二','孫覿','宋','宋诗','song-poetry','','[]','有地逃銅馬，無心待玉魚。',48,'全唐诗/poet.song.85000.json','["有地逃銅馬，無心待玉魚。", "牛眠今可矣，龍耳欲何如。", "荷鍤千巖去，連轆十日餘。", "殷勤古松下，爲剖甕中書。"]'),
('047dc6c7-b4b7-4bee-ae02-e79c01ae1bd2','次韻德發驅虎','孫覿','宋','宋诗','song-poetry','','[]','三窟憎狡兔，兩端忌首鼠。',192,'全唐诗/poet.song.85000.json','["三窟憎狡兔，兩端忌首鼠。", "含糊有前却，遺患在養虎。", "操刀貴能斷，坐見皮寢處。", "應須下車搏，不待探穴取。", "恢恢天漏網，洶洶國破斧。", "驚呼咤萬口，走避空一府。", "長圍起伏虚，尺箠下戛敔。", "迷行出漢圏，送死入鄭圃。", "大彘保尻領，童兒聚儔侣。", "枯顱歸閣束，敗鞟實庭旅。", "寧堪裹馬革，但恐汙牛弩。", "三患古所害，一死誰貰汝。", "綠林嘯亡命，首禍自吕母。", "師行費千金，城壞墮百堵。", "踞鞞體欲消，嚢笏頰誰拄。", "要先羣鯨戮，未快一虎去。"]'),
('93525b1b-577b-40f3-9fd5-8655e4cfbe30','讀沈德潤詩卷','孫覿','宋','宋诗','song-poetry','','[]','繫馬門前柳，投鞭息吾駕。',120,'全唐诗/poet.song.85000.json','["繫馬門前柳，投鞭息吾駕。", "青林合扶疏，木杪抗風榭。", "沈郎天骨清，衆垤立嵩華。", "閉閣臥讀書，一榻過僧夏。", "尤工五字律，句法窺鮑謝。", "無窮真炙輠，有味乃食蔗。", "我老復何爲，齒髪日夜化。", "寅緣葦間見，拊髀起一咤。", "懸知擲地響，自欲補天罅。", "坐令長安楮，頓起千金價。"]'),
('f638bf7b-9a79-4066-b4e1-5abce6737df3','讀王季恭詩卷小詩爲謝二首  其一','孫覿','宋','宋诗','song-poetry','','[]','潛泉不到一周星，膝上郎君得我驚。',64,'全唐诗/poet.song.85000.json','["潛泉不到一周星，膝上郎君得我驚。", "大府潭潭真老相，長淮滚滚舊家聲。", "渥洼隨地須千里，窮髮垂天佇一鳴。", "莫遣畫蛇安兩足，宫袍賜錦待先成。"]'),
('588ae98a-7c9e-4ed3-be9f-f6f108a7707b','讀王季恭詩卷小詩爲謝二首  其二','孫覿','宋','宋诗','song-poetry','','[]','金鍾吼徹曉霜清，瓦釡如雷不敢鳴。',64,'全唐诗/poet.song.85000.json','["金鍾吼徹曉霜清，瓦釡如雷不敢鳴。", "欲識呼盧真彦道，試吟石鼎調彌明。", "牙籖萬軸撐膓滿，金檢千篇唾手成。", "堪笑韓公太多可，浪傳侯喜有詩聲。"]'),
('b8da5f66-75bf-49a8-ae85-0e4b9e01e13c','寄題錢申仲漆堂隱居四首 望雲亭','孫覿','宋','宋诗','song-poetry','','[]','昔年隱君子，共修地下文。',72,'全唐诗/poet.song.85000.json','["昔年隱君子，共修地下文。", "王官竟不返，幸樹十里春。", "哀哉抱長思，慟哭蒼山根。", "腸回日萬周，繫此三尺墳。", "傷心閟黄壤，矯首望白雲。", "雲去無處所，淚濕塚前麟。"]'),
('5f7eb200-3b93-41b3-b2c2-8a74e9e63687','寄題錢申仲漆堂隱居四首 芳美亭','孫覿','宋','宋诗','song-poetry','','[]','離離陌上花，春到錦營中。',72,'全唐诗/poet.song.85000.json','["離離陌上花，春到錦營中。", "上冢千騎出，竟天晚旌紅。", "故園已陳迹，風流餘此翁。", "渺渺山間曲，披披煙雨叢。", "種桃今著花，千巖貯春風。", "錦繡裹山谷，遺民悲故宫。"]'),
('be2ccce7-3697-4647-9842-0f3300260ed3','寄題錢申仲漆堂隱居四首 遂初亭','孫覿','宋','宋诗','song-poetry','','[]','行有叱馭難，坐有垂堂畏。',72,'全唐诗/poet.song.85000.json','["行有叱馭難，坐有垂堂畏。", "莫驅九折險，輕用千金貴。", "爲貧聊爾爾，興盡我輒逝。", "平生慕朱遊，肯汙薛宣吏。", "清曉拄笏坐，西山有佳氣。", "一笑食蛤蜊，寧復知許事。"]'),
('91fe9f49-2d62-44bf-92f4-1a0f736396ac','寄題錢申仲漆堂隱居四首 通慧亭','孫覿','宋','宋诗','song-poetry','','[]','磽磽錫爲骨，瘦脊盤九龍。',72,'全唐诗/poet.song.85000.json','["磽磽錫爲骨，瘦脊盤九龍。", "中涵千斛乳，連絡萬竅通。", "漆堂枕其股，飄飲迺不供。", "詩翁虧天巧，妙契卓錫工。", "青林破蒼玉，碧井臥白虹。", "他年一杯酒，配食桑苧翁。"]'),
('92e0c895-2afa-4fbc-957a-606b19c9c546','寄題胡茂老樞密横山堂','孫覿','宋','宋诗','song-poetry','','[]','古縣水山國，萬室蟠其中。',240,'全唐诗/poet.song.85000.json','["古縣水山國，萬室蟠其中。", "環成千嶂合，並合不泉通。", "我公擅一壑，曾雲生盪胸。", "放神八極外，坐駕兩腋風。", "峨峨十二環，半出簾幕重。", "修眉畫新就，一抹翠掃空。", "欣對愜平生，似爲悦已容。", "百金置酒地，窗户浮青紅。", "高陵拄笏見，採菊籬下逢。", "坡陀逕千丈，横絕垂天雄。", "日麗鶯谷晚，沙喧燕泥融。", "悠然命巾車，往往載客從。", "大句琢天巧，朱絃奏三終。", "溪山久寂寥，高辭擅無窮。", "天王駕羣英，長轡係九戎。", "安知横山下，一榻似老龍。", "功名方鼎來，龜祥兆飛熊。", "勒石誦中興，浯臺兩穹崇。", "西州歸謝傅，東海表太公。", "千年丁令威，騎鶴還故宫。"]'),
('2899cb24-ad9f-4f11-b58d-ae2e64407464','次韻向伯恭侍郎致政歸臨江','孫覿','宋','宋诗','song-poetry','','[]','六龍暴鬛海生塵，霖雨方資命世材。',64,'全唐诗/poet.song.85000.json','["六龍暴鬛海生塵，霖雨方資命世材。", "此去謝公須強起，誰令陶令賦歸來。", "追懷玉筍三年别，指點薌林一笑開。", "大舸横江日千里，憑誰倒曳九牛回。"]'),
('3ec93101-c029-4d25-b14e-afaafe857f43','湖州道中四首 望道場山塔 其一','孫覿','宋','宋诗','song-poetry','','[]','碧玉旋螺插暮煙，遙看桂子落僧前。',32,'全唐诗/poet.song.85000.json','["碧玉旋螺插暮煙，遙看桂子落僧前。", "試尋白水田頭路，一葦横江浪接天。"]'),
('ca3cea71-55bf-45ff-90e5-fb3056feb450','湖州道中四首 望道場山塔 其二','孫覿','宋','宋诗','song-poetry','','[]','蕭寺知名四十年，身投籠檻到無緣。',32,'全唐诗/poet.song.85000.json','["蕭寺知名四十年，身投籠檻到無緣。", "行人指點松間路，正在孤雲落照邊。"]'),
('720aae97-ae6a-490d-a8e0-44af7960da93','湖州道中四首 早發下若','孫覿','宋','宋诗','song-poetry','','[]','宿雨乍收山氣斂，清風欲發曙光寒。',32,'全唐诗/poet.song.85000.json','["宿雨乍收山氣斂，清風欲發曙光寒。", "紛紛鳥動行人起，百尺浮圖水底看。"]'),
('4df96815-e69b-499e-a99c-9c788ee57325','湖州道中四首 東山','孫覿','宋','宋诗','song-poetry','','[]','千章古木翳山根，誰與山僧共寂寥。',32,'全唐诗/poet.song.85000.json','["千章古木翳山根，誰與山僧共寂寥。", "珍重庭松寒不死，蒼皮老幹雪齊腰。"]'),
('b869dcc4-cb55-4bfa-a1ed-561fd229d94a','湖州道中四首 横山堂 其一','孫覿','宋','宋诗','song-poetry','','[]','波間指點見青紅，雪脊嶒棱倚半空。',32,'全唐诗/poet.song.85000.json','["波間指點見青紅，雪脊嶒棱倚半空。", "幻出生綃三萬幅，遊人渾在畫圖中。"]'),
('50840e21-3043-4752-82c1-7b9489a49015','湖州道中四首 横山堂 其二','孫覿','宋','宋诗','song-poetry','','[]','蒼雲千畝蔭平寛，露葉風枝繞舍寒。',32,'全唐诗/poet.song.85000.json','["蒼雲千畝蔭平寛，露葉風枝繞舍寒。", "莫遣先生賦歸去，且令小吏報平安。"]'),
('0bdf33bc-309f-4187-9ff7-6d4b053678c8','湖州道中四首 横山堂 其三','孫覿','宋','宋诗','song-poetry','','[]','溜雨蒼皮四十圍，年來又見子孫枝。',32,'全唐诗/poet.song.85000.json','["溜雨蒼皮四十圍，年來又見子孫枝。", "龍鍾白首門前客，待看成陰合抱時。"]'),
('8f72310d-9cdf-42f8-9f25-520d84b98f36','荆溪道中四言送僧','孫覿','宋','宋诗','song-poetry','','[]','老蠶上薄，倦鳥投林。',80,'全唐诗/poet.song.85000.json','["老蠶上薄，倦鳥投林。", "牛閑人臥，薺麥交陰。", "孤舟縱橫，綠漲一尋。", "好風徐來，清和滿襟。", "舉盃屬影，伴我孤斟。", "老矣鍾儀，尚操楚音。", "高山流水，寓此琴心。", "上人問我，何念之深。"]'),
('73a34a36-3785-4b3f-9e66-2041346ea72f','題谷隱二首  其一','孫覿','宋','宋诗','song-poetry','','[]','碧瘦峨千疊，清深漲一篙。',48,'全唐诗/poet.song.85000.json','["碧瘦峨千疊，清深漲一篙。", "紅輕花似肉，綠細柳如繰。", "句好無强對，神超有獨遨。", "葦間青篛笠，彷彿見秦逃。"]'),
('484e3311-ad9b-4086-b899-243929833ff4','題谷隱二首  其二','孫覿','宋','宋诗','song-poetry','','[]','露濕芙蓉晚，風酣橘柚秋。',48,'全唐诗/poet.song.85000.json','["露濕芙蓉晚，風酣橘柚秋。", "衣巾紅影亂，尊俎翠光流。", "塵暗迷三馬，陽驕喘萬牛。", "五湖煙雨裏，不繫有虛舟。"]'),
('a78d8b0a-0e43-4290-bdce-08626f86d386','送張牧之赴南昌辟','孫覿','宋','宋诗','song-poetry','','[]','青衫觸熟並西州，沒馬黄塵接地流。',64,'全唐诗/poet.song.85000.json','["青衫觸熟並西州，沒馬黄塵接地流。", "庾亮南樓應有待，薛宣東閣可能留。", "官閑端爲三升戀，興盡還從五斗休。", "繪出金盤堆白雪，秋江一葉認歸舟。"]'),
('7362cf54-1986-4938-ad03-e3415713c005','四月十五日牧之赴南昌辟某與季野從周餞于松沛佛舍竟酒步月至垂虹亭久之遂别戲作數句送牧之','孫覿','宋','宋诗','song-poetry','','[]','宛宛白虹貫，曾梯出天半。',120,'全唐诗/poet.song.85000.json','["宛宛白虹貫，曾梯出天半。", "乘雲來帝旁，立侍玉皇案。", "銀河徑千里，水接天漫漫。", "一杯屬明月，俯見人影亂。", "張公江海客，坐嘯白鷗伴。", "寥寥如清風，一嘯亦可喚。", "明朝駕戎軒，插羽流白汗。", "行矣且勿驅，未怪安石緩。", "神光射斗南，絢若金碧爛。", "出門問何祥，銅章付雷煥。"]'),
('c08a3518-ed67-4c4c-a984-51b4f670727a','臞庵','孫覿','宋','宋诗','song-poetry','','[]','落日催行客，馬上振短策。',144,'全唐诗/poet.song.85000.json','["落日催行客，馬上振短策。", "觸途眉見赤，墮俗眼生白。", "安知青林中，有此江上宅。", "决眥破天藏，盪胸納空光。", "一奩注寒晶，表裏洞八窗。", "風水自吐吞，噴雲忽滿江。", "臞翁目如電，坐閲東海變。", "酒酣跨赤鯉，謁帝通明殿。", "霓裳月中聞，羅襪波上見。", "垂老寄漁商，家風在瀟湘。", "虚舟自不繫，倦鳥寧復翔。", "一榻如見容，拄杖挂鉢嚢。"]'),
('d0632619-b665-4ad2-98c0-8f721bfcc4ab','送徑山僧','孫覿','宋','宋诗','song-poetry','','[]','桑棗翳一邱，風雨鳴四壁。',72,'全唐诗/poet.song.85000.json','["桑棗翳一邱，風雨鳴四壁。", "晨門響丁丁，一笑喜折屐。", "臞仙詩作瘦，句有徑山色。", "哀彈發朱弦，妙寄追白石。", "虚名子過聽，愧臥不能夕。", "歸袖挽莫留，凌空看飛錫。"]'),
('65113a2f-525a-489f-9f25-27c607275212','過慧山見舊題二首  其一','孫覿','宋','宋诗','song-poetry','','[]','一别名山十五年，宦情羈思兩茫然。',32,'全唐诗/poet.song.85000.json','["一别名山十五年，宦情羈思兩茫然。", "故人半作累累冢，只有蒼官立道邊。"]'),
('3282a226-0b38-4e45-8640-ad19a77e7785','過慧山見舊題二首  其二','孫覿','宋','宋诗','song-poetry','','[]','髀肉消磨馬上鞍，塵沙滿眼路漫漫。',32,'全唐诗/poet.song.85000.json','["髀肉消磨馬上鞍，塵沙滿眼路漫漫。", "不須更障西風扇，爲酌崖泉一洗看。"]'),
('f2a54360-fefd-4dcf-a5dc-ccccdee7b5d1','王左司致政還鄉二首  其一','孫覿','宋','宋诗','song-poetry','','[]','安眠不蹋鼓蓬蓬，榮路先回鷁退風。',64,'全唐诗/poet.song.85000.json','["安眠不蹋鼓蓬蓬，榮路先回鷁退風。", "獨片角巾東路去，休驚蕙帳北山空。", "畫圖便可追三士，同社誰能作兩翁。", "待拄一筇隨薊叟，摩挲銅狄霸城東。"]'),
('768217f5-a277-43fe-8753-0276bb7b42ba','王左司致政還鄉二首  其二','孫覿','宋','宋诗','song-poetry','','[]','水滿滄浪舊釣磯，春風江上片帆歸。',64,'全唐诗/poet.song.85000.json','["水滿滄浪舊釣磯，春風江上片帆歸。", "繁紅不見桃千樹，老幹空驚柳十圍。", "萬壑煙雲供坐嘯，一龕香火結真依。", "落花細草應堪籍，醉撼長條雪滿衣。"]'),
('be8e4f31-7d65-45fe-855f-27fa83a85aff','過臞庵示王文孺二首  其一','孫覿','宋','宋诗','song-poetry','','[]','黄帽青鞋兩鬢斑，一簔聊寄此身閑。',32,'全唐诗/poet.song.85000.json','["黄帽青鞋兩鬢斑，一簔聊寄此身閑。", "不因誤入桃花去，那得夤緣見幃間。"]'),
('445b3ce6-5188-4f1f-af0e-df713658c947','過臞庵示王文孺二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雞犬無聲白日閑，一筇九節過眉班。',32,'全唐诗/poet.song.85000.json','["雞犬無聲白日閑，一筇九節過眉班。", "會須俎豆三高上，且寄風流二老間。"]'),
('45ea0587-00c4-435b-9301-8b3aa01bebac','華亭朱師實中大燕超堂','孫覿','宋','宋诗','song-poetry','','[]','海禺納萬艘，市區沸百賈。',192,'全唐诗/poet.song.85000.json','["海禺納萬艘，市區沸百賈。", "黄塵翳白日，千騎騰一鼓。", "蛟巢十字路，四顧盡曠土。", "蝸角兩大國，一怒有漂杵。", "角名眩多盧，聚訟攻衆楚。", "昏昏氣成霧，濯濯汗浹雨。", "朱公誤涉世，吏隱寄圭組。", "俗緣墮人境，心大接天宇。", "搴芳採蓮舟，擷秀藝藥圃。", "山寒石稜紫，樹老松鬛古。", "風牽碧羅卷，雨壓翠纛舞。", "寧須鳥催酤，自有花解語。", "觀魚樂洋洋，夢蝶飛栩栩。", "坐令遊俠窟，化作仙佛土。", "高臥水國秋，静憩月庭午。", "不解壺公龍，天上有官府。"]'),
('cca67927-b395-4edb-8c23-ef8027a5d4c5','洞庭沈氏園亭','孫覿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲根瘴滔天，萬疊如連環。',144,'全唐诗/poet.song.85000.json','["雲根瘴滔天，萬疊如連環。", "峨峨一鏡中，綰結十二鬟。", "壇殿歲月古，敝石蒼苔斑。", "毛公已仙去，故物尚人間。", "羣胡射漢月，獵火焮百蠻。", "安知橘中樂，避世真商山。", "英英東陽孫，高情寄人寰。", "誅茅擇地勝，斬崖破天慳。", "開軒疊蒼玉，亂峰刻孱顔。", "循除繞羅带，淺溜鳴潺湲。", "意行雲共出，地坐草可班。", "興至亦乘桴，一簔臥滄灣。"]'),
('65126876-4c36-45a9-9fbc-dbe3f7f9da08','洞庭善慶堂置酒小詩寄之','孫覿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','幽絕小蓬壺，參差見畫圖。',120,'全唐诗/poet.song.85000.json','["幽絕小蓬壺，參差見畫圖。", "亂青山四出，一碧水平鋪。", "洲蕊紅相照，沙茸細欲無。", "蓮房駢百子，橘圃聚千奴。", "布穀休催種，提壺且勸酤。", "楚腰飛燕燕，秦缶和烏烏。", "便旋驚回雪，連娟引貫珠。", "西風催畫鷁，落日詠驪駒。", "浩蕩川原隔，驚呼歲月徂。", "寥寥清夜夢，直擬控摶扶。"]'),
('31335c55-e33f-432d-a51b-2411c0e6c0a9','華山德雲堂','孫覿','宋','宋诗','song-poetry','','[]','昔年曾上德雲堂，木奴千樹新著霜。',64,'全唐诗/poet.song.85000.json','["昔年曾上德雲堂，木奴千樹新著霜。", "白首重來十載後，六華簷蔔薫風香。", "湖上青青只如舊，湖波漲淥濃於酒。", "堂中老宿尚依然，烏鵲巢肩柳生肘。"]'),
('0338cd0e-72d7-46a0-968e-75820b7b56ea','講堂','孫覿','宋','宋诗','song-poetry','','[]','誰令堅白鳴，自作雪雨争。',48,'全唐诗/poet.song.85000.json','["誰令堅白鳴，自作雪雨争。", "莫遣蠅鑽楮，便恐鼠污羮。", "遵師表衆惑，自逐鞭影行。", "拊几無一言，大千作雷鳴。"]'),
('97b7e340-c0ce-42c0-8ac2-2542a13c3e3f','折玉崖','孫覿','宋','宋诗','song-poetry','','[]','巉巉兩崖青，漫漫一奩白。',60,'全唐诗/poet.song.85000.json','["巉巉兩崖青，漫漫一奩白。", "抵沙射月影，窗户栖珠璧。", "定心如止水，逝將老空寂。", "手弄一掬寒，面傃千仞碧。", "須防童子喜，往往犯瓦礫。"]'),
('ef1e5819-6271-41f3-a8c1-0b1e5f0a7ff4','興化朱公大卿沒于庚申歲既除喪矣其子彦寔過余于晉陵留十日而别賦二小詩以餞之  其一','孫覿','宋','宋诗','song-poetry','','[]','百感關心老淚潸，一抔埋玉臥空山。',64,'全唐诗/poet.song.85000.json','["百感關心老淚潸，一抔埋玉臥空山。", "著鞭竟看駒千里，闚管初驚豹一斑。", "貧病故侯今白髪，風流公子尚青綸。", "不須優孟追諧笑，已見遺珠合浦還。"]'),
('109a9973-0259-4254-b11e-5456f7e92786','興化朱公大卿沒于庚申歲既除喪矣其子彦寔過余于晉陵留十日而别賦二小詩以餞之  其二','孫覿','宋','宋诗','song-poetry','','[]','柴扉忽枉故人車，躧履歡迎一笑初。',64,'全唐诗/poet.song.85000.json','["柴扉忽枉故人車，躧履歡迎一笑初。", "夢裏覆蕉疑有鹿，食前彈鋏歎無魚。", "匆匆注瓦澆村醸，草草供盤折野蔬。", "他日死生君一訪，上林鴻雁有書無。"]'),
('2bd530eb-51b1-478e-90f3-70cbcb146b70','讀張彥明飲酒賦詩唱酬次韻歸之','孫覿','宋','宋诗','song-poetry','','[]','滿酌黄壚萬户春，倒披紫綺八仙人。',64,'全唐诗/poet.song.85000.json','["滿酌黄壚萬户春，倒披紫綺八仙人。", "句中得妙陶元亮，酒裏知名賀季真。", "九醖調成花上露，一丸爊出鼎中銀。", "老來不辦追强對，分我餘光幸借鄰。"]'),
('9a84286f-dde7-490a-a1ea-98d3b74343ee','青氈堂','孫覿','宋','宋诗','song-poetry','','[]','晉馬已老矣，楚弓今得之。',96,'全唐诗/poet.song.85000.json','["晉馬已老矣，楚弓今得之。", "懷璧萬里至，化鶴千歲歸。", "主人有故巢，鳩居不復栖。", "俄驚桑田換，已見城郭非。", "偶尋蕉中覆，忽得爨下遺。", "平生手所種，老大今十圍。", "故壁初見蝎，空牀尚支龜。", "塞翁一笑喜，共賦青氈詩。"]'),
('5cfa0b41-c615-4d58-a340-091b662d8bcb','别雲闍黎','孫覿','宋','宋诗','song-poetry','','[]','邂逅不煖席，躊蹰空復情。',48,'全唐诗/poet.song.85000.json','["邂逅不煖席，躊蹰空復情。", "偶隨孤月出，又作片雲征。", "已振空中錫，聊班地上荆。", "他年葛洪井，更欲問三生。"]'),
('cddb7d34-beaf-4532-8a8d-303bdc1b724e','送僧慧徹','孫覿','宋','宋诗','song-poetry','','[]','千燈佛祖後，五字島阿間。',48,'全唐诗/poet.song.85000.json','["千燈佛祖後，五字島阿間。", "危坐肘生柳，獨謠肩聳山。", "浮杯更東渡，振履又西還。", "爲我覓釣舟，一簔伴子閑。"]'),
('f6f0f8fe-333a-4de2-8899-630e1ef6f94b','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 澹臺書堂','孫覿','宋','宋诗','song-poetry','','[]','松根絡斷崖，石脚泫細泉。',72,'全唐诗/poet.song.85000.json','["松根絡斷崖，石脚泫細泉。", "書堂何代育，故物尚依然。", "右丞今摩詰，尚友千載前。", "神交夢仙舟，地勝真輞川。", "散策塵外躅，脱屣區中緣。", "杯尊酌花鳥，一醉藉草眠。"]'),
('533e2efe-6527-4567-b4dc-398cd8fd38c2','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 泊湖潭','孫覿','宋','宋诗','song-poetry','','[]','藹藹竹樹交，一潭蔭寒青。',72,'全唐诗/poet.song.85000.json','["藹藹竹樹交，一潭蔭寒青。", "已無蛙黽汙，尚有蛟龍腥。", "林疏泛月彩，艷艷一鏡平。", "我心一如此，炯炯珠夜明。", "意行魚共樂，坐穩鷗不驚。", "更欲漱吾齒，不掛功與名。"]'),
('091fd6e5-4d95-4a54-807c-52d8249f5166','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 蝦蟆石','孫覿','宋','宋诗','song-poetry','','[]','天公磔蛙死，墮地化爲石。',72,'全唐诗/poet.song.85000.json','["天公磔蛙死，墮地化爲石。", "魁然此江郊，面滯蒼煙色。", "葱蘢一拳青，凝湛半蒿碧。", "猶疑老蟾窟，尚吐月中液。", "我來蹈其背，坐睨倚天壁。", "鼓吹不復鳴，煙雨空寂歷。"]'),
('522a9c97-e937-497b-8f43-86d71cb9d5f5','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 多寶院','孫覿','宋','宋诗','song-poetry','','[]','穿雲訪幽伴，倚枝蒼崖根。',72,'全唐诗/poet.song.85000.json','["穿雲訪幽伴，倚枝蒼崖根。", "冥冥篁竹中，古寺松爲門。", "野僧營一飽，乞食山下村。", "擁鼻且獨謠，未覺釣石温。", "世事風雨過，歲陰波浪奔。", "飄然得遠遊，寄此五石尊。"]'),
('4b0b1926-bc15-49e1-ae4d-1f6216773c71','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 梅仙潭','孫覿','宋','宋诗','song-poetry','','[]','潭潭雲幕垂，杪樹秋磬發。',72,'全唐诗/poet.song.85000.json','["潭潭雲幕垂，杪樹秋磬發。", "飛仙駕青鸞，通籍在金闕。", "遙見切雲冠，尚想凌波襪。", "殷勤小梅花，獨照黄昏月。", "生綃濕香霧，翠袖卷煙雪。", "忽然東風惡，一夜吹石裂。"]'),
('0c5cc8c0-c843-4036-8c22-4f8f71537919','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 金石臺','孫覿','宋','宋诗','song-poetry','','[]','曾臺接叢霄，東西鬱相望。',72,'全唐诗/poet.song.85000.json','["曾臺接叢霄，東西鬱相望。", "地靈鍾神秀，人物擅一方。", "相居踐台斗，争雄兩巍卬。", "倚薄雲雨近，蔽虧星月光。", "陳迹恍如接，尊名綴前芳。", "獨有真男子，平生盛孝章。"]'),
('05ca1a7f-67af-42fe-820c-21e5b940bc48','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 懷賢庵','孫覿','宋','宋诗','song-poetry','','[]','佳人去何之，歲月忽已逝。',72,'全唐诗/poet.song.85000.json','["佳人去何之，歲月忽已逝。", "懷人昔孟光，問道今法喜。", "百年草頭露，一夢月中螘。", "見此兩足尊，感動淚如洗。", "區區記刻舟，兒嬉亦漫爾。", "永斷三生緣，付此一彈指。"]'),
('92de5045-d8a8-4e40-8560-cca579fabf28','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 翠積樓','孫覿','宋','宋诗','song-poetry','','[]','曾稜倚高寒，突兀擅空闊。',72,'全唐诗/poet.song.85000.json','["曾稜倚高寒，突兀擅空闊。", "江横碧羅带，山斷青玉玦。", "湛湛清不搖，霏霏翠如潑。", "松蹊奮蒼鬛，苔石換綠髪。", "陰森揉肌粟，蒨絢亂眼纈。", "憑欄送落景，一鳥煙中沒。"]'),
('623f252a-c91c-4c20-904d-66ec362a49b2','右丞相張公達明營别墅于汝川記可遊者九處繪而爲圖貽書屬晉陵孫某賦之 甘陂莊院','孫覿','宋','宋诗','song-poetry','','[]','張公臥江海，戢羽如鵬蹲。',72,'全唐诗/poet.song.85000.json','["張公臥江海，戢羽如鵬蹲。", "平生廊廟具，投老三家村。", "一壑身所寄，萬里心自存。", "買花紅間坐，種竹青滿門。", "似聞橘生奴，漸見桐有孫。", "提壺時見廣，一笑空罍尊。"]'),
('e100f495-a3c8-4b31-aa29-9d0df469bcbd','題宜興閭邱令巢鳯亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','老仙躡兩鳧，自歌于蒍于。',96,'全唐诗/poet.song.85000.json','["老仙躡兩鳧，自歌于蒍于。", "千岑對隱几，萬竹繞直廬。", "上有丹鳯穴，巢居插脩梧。", "奇毛間五采，斕斑此英雛。", "啾啾黄雀羣，百陋見一姝。", "追風嚇六鷁，逐日墜九烏。", "芝田有遺啄，握粟未可呼。", "天池九萬里，一飛試南圖。"]'),
('fb761b60-a715-49c5-b936-adb280e82834','題宜興閭邱令巢鳯亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','少年有殊相，瓠白非臞儒。',96,'全唐诗/poet.song.85000.json','["少年有殊相，瓠白非臞儒。", "三吳山水窟，見此紫鳯雛。", "家無儋石儲，腹有萬卷書。", "陳編踐芻狗，博具抵牧猪。", "手持半段槍，伎癢始一呼。", "倒海探龍頷，據地捋虎須。", "有客持鈞樞，大書表其閭。", "盛事傳不朽，畫入荆溪圖。"]'),
('54fb305e-a34d-41ef-8c32-2e78c0e7b51c','和張正民通守','孫覿','宋','宋诗','song-poetry','','[]','零落衣冠汙塵土，戴盆望天那得睹。',64,'全唐诗/poet.song.85000.json','["零落衣冠汙塵土，戴盆望天那得睹。", "青黄不著爨下焚，糟粕空傳紙上語。", "判花視草迹已陳，十年閉口不論文。", "君詩藹藹春雲似，來弔湘江九死魂。"]'),
('40f2de80-fdd4-4911-99c1-9d52695e90ec','張全真大資四老堂','孫覿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','真人東方行，攜幼坐小輦。',288,'全唐诗/poet.song.85000.json','["真人東方行，攜幼坐小輦。", "五星聚光炯，八龍臥偃蹇。", "張公世忠孝，七葉冠蟬冕。", "翹翹麟一角，濯濯蕙九畹。", "聲名大小馮，門巷南北阮。", "壎篪自鳴和，滿耳聽睍睆。", "舂粟悲漢謠，然萁笑魏褊。", "詎聞華亭鶴，空憶上蔡犬。", "堂堂鼎軸老，秉道迪天顯。", "寧投千金璧，不踐九折坂。", "飛飛鴻雁行，戀戀桑榆暖。", "草木商山村，煙波洞庭晚。", "芝老正堪茹，橘熟行可搴。", "連床話團欒，共此一笑莞。", "當年伯仲氏，衫鬢綠婉婉。", "彩衣戲翁側，玉立盡瑚璉。", "峥嶸六門闕，突兀今在眼。", "歲月知幾何，華皓森雪巘。", "扶顛屬匠石，起死待和扁。", "富貴挽不來，拄頰但手板。", "談間鋸屑霏，酒伴金荷卷。", "舞茵翔兩鸞，歌板曳猶繭。", "冰壺明月吐，琪樹清風滿。", "起尋赤松遊，仙籍標閬苑。"]'),
('c7963da7-d2d6-4d41-a75e-e90efa1bfe1f','少逸登第還里中喜而賦詩少逸過余出示和篇次韻爲賀','孫覿','宋','宋诗','song-poetry','','[]','帳底諸生擁鼻謠，詩書滿腹似邊韶。',64,'全唐诗/poet.song.85000.json','["帳底諸生擁鼻謠，詩書滿腹似邊韶。", "禹門擊水高三級，堯殿披雲煥九霄。", "駿馬看花春寂寂，長檠燒燭夜寥寥。", "一飛更上金鑾去，滿袖香煙散早朝。"]'),
('508b2fb2-31ab-4ede-be35-7e241e3854be','三衢教授陳德召寵貺新篇兼辱寄惠古史賦三小詩爲謝  其一','孫覿','宋','宋诗','song-poetry','','[]','伐樹已掃迹，種花今問津。',60,'全唐诗/poet.song.85000.json','["伐樹已掃迹，種花今問津。", "一筇隨臥起，四壁空無鄰。", "有懷平生遊，老手妙斵輪。", "去搴柯山秀，盡作泮水芹。", "裁詩問無恙，寄此嶺頭雲。"]'),
('f95a70fe-b7b4-4c86-bcd5-2193fcd6bc70','三衢教授陳德召寵貺新篇兼辱寄惠古史賦三小詩爲謝  其二','孫覿','宋','宋诗','song-poetry','','[]','世人識真少，耳剽得驚坐。',60,'全唐诗/poet.song.85000.json','["世人識真少，耳剽得驚坐。", "安知百尺樓，上有元龍臥。", "儒官爲官曹，學子書吏課。", "長謠振商音，麗藻發楚些。", "獨有白雪章，妙絕無人和。"]'),
('8219ce29-c198-4d89-ad76-ef2de352167d','三衢教授陳德召寵貺新篇兼辱寄惠古史賦三小詩爲謝  其三','孫覿','宋','宋诗','song-poetry','','[]','太史命世豪，始作表傳記。',60,'全唐诗/poet.song.85000.json','["太史命世豪，始作表傳記。", "著書自一家，亦足見奇偉。", "寥寥千載向，筆削號古史。", "排斥已甚哉，不學而見詆。", "孰云争名者，區區在朝市。"]'),
('39108f39-4032-4a10-895c-7def99febf7b','題靈巖五至堂','孫覿','宋','宋诗','song-poetry','','[]','老人昔記觀何處，白髪蒼顔只如故。',96,'全唐诗/poet.song.85000.json','["老人昔記觀何處，白髪蒼顔只如故。", "湛然不與生滅期，始信真心有常住。", "公今忘物兼忘我，坎止留行無不可。", "桑下了無三宿戀，壁間一坐九年過。", "振履忽逐秋鴻往，浮杯又趁春潮上。", "一片孤雲自在飛，不落人中去來想。"]'),
('17903849-2bb4-450e-80f5-78bf9febb1c6','鄭惇老謙老寄示四賦小詩爲謝','孫覿','宋','宋诗','song-poetry','','[]','三椽容膝地，一枕曲肱眠。',120,'全唐诗/poet.song.85000.json','["三椽容膝地，一枕曲肱眠。", "手把故人畫，起行夢相牽。", "明河天上落，一派墮我前。", "溶溶注銀海，浩浩瀉玉川。", "老眼眩欲迷，今在第幾天。", "堂堂通德門，種德今百年。", "齋房九莖芝，岳井十丈蓮。", "連枝挺奇秀，見此兩謫仙。", "詩成粲珠玉，紙落生雲煙。", "一飛看昂霄，雲中雁行連。"]'),
('13b4e7ad-922a-4c02-abcd-5dca2ec9a24e','章席祖巢雲閣','孫覿','宋','宋诗','song-poetry','','[]','翳翳林影交，小閤俯江郊。',96,'全唐诗/poet.song.85000.json','["翳翳林影交，小閤俯江郊。", "千崖障錦綉，萬壑鳴弦匏。", "翛然一枝筇，寄此三重茅。", "久知風可御，更取雲爲巢。", "抱石舒翠縷，綉色纔可睹。", "霏霏擘春絮，欻見白鶴舞。", "凝矑一瞬間，忽展垂天羽。", "起從潭中龍，去作山下雨。"]'),
('dabfa31c-b305-4473-a1d0-222688d2a028','題李營邱畫','孫覿','宋','宋诗','song-poetry','','[]','酒膽乘酣思如湧，戲括枯筆爲此弄。',64,'全唐诗/poet.song.85000.json','["酒膽乘酣思如湧，戲括枯筆爲此弄。", "誰令堂上生楓樹，自是胸中有雲夢。", "前山歷歷粲可數，淺瀨鱗鱗森欲動。", "一嘯參差是故林，歸心已逐孤雲縱。"]'),
('923a10d5-ce93-40c8-9234-7979ed253886','寄題莫謙仲山居西樓二首 山居','孫覿','宋','宋诗','song-poetry','','[]','魚鹽市井富，冠蓋車馬路。',96,'全唐诗/poet.song.85000.json','["魚鹽市井富，冠蓋車馬路。", "生息自相吹，晨門黕如霧。", "超然塵外躅，硉兀見砥柱。", "湯湯海横流，自有安立處。", "幻泡水上漚，空華草頭露。", "一峰獨蒼然，歲寒但如故。", "醉搴庭下花，吟繞池邊樹。", "便有山中臞，來隨白雲屨。"]'),
('779519b5-006f-4ffc-9710-c20ca291ae06','寄題莫謙仲山居西樓二首 西樓','孫覿','宋','宋诗','song-poetry','','[]','曾梯倚半空，百尺臥元龍。',96,'全唐诗/poet.song.85000.json','["曾梯倚半空，百尺臥元龍。", "偃蹇一榻上，峥嶸兩争雄。", "暮卷珠簾雨，夜鎮犀帷風。", "吾公安在哉，雲間指青紅。", "俯視大千界，一器蚋滿中。", "巢蚊幸有餘，國蝸遂相攻。", "湛湛天一碧，萬里磨青銅。", "不落牛背上，悠然送飛鴻。"]'),
('bd889243-1888-4e21-b63b-f71e5a434e12','過慧山方丈皥老酌泉試茶賦兩詩遺之  其一','孫覿','宋','宋诗','song-poetry','','[]','蕭蕭阿蘭若，桑苧有故家。',96,'全唐诗/poet.song.85000.json','["蕭蕭阿蘭若，桑苧有故家。", "佛屋倚高寒，僧蹊抱攲斜。", "殷勤泉上客，流落瘴海涯。", "蜑酒壓梨樝，蠻烹啗蛙蛇。", "光潔鏡一奩，照影空自嗟。", "老僧薦茗粥，芳鮮凝露華。", "驅除鼻中雷，掃盡眼界花。", "飄飄思凌雲，攝身上蒼霞。"]'),
('c85d70d1-ce2d-4693-9b2b-e4cbd1797301','過慧山方丈皥老酌泉試茶賦兩詩遺之  其二','孫覿','宋','宋诗','song-poetry','','[]','戰塵霾漢天，獵火焮胡地。',96,'全唐诗/poet.song.85000.json','["戰塵霾漢天，獵火焮胡地。", "一筇道垢氣，步入青蓮寺。", "眈眈九龍盤，一壑埋老翠。", "倚天松骨大，粘壁苔髪細。", "道人本臞儒，得法妙出世。", "胸中萬斛泉，洗盡蔬筍氣。", "大風吹泠泠，助我鳴鼓吹。", "名爲不二門，聲音作佛事。"]'),
('3cb39390-ffa2-4504-a970-4aa740b3dcf4','過楓橋寺示遷老三首  其一','孫覿','宋','宋诗','song-poetry','','[]','白首重來一夢中，青山不改舊時容。',32,'全唐诗/poet.song.85000.json','["白首重來一夢中，青山不改舊時容。", "烏啼月落橋西寺，攲枕猶聞半夜鍾。"]'),
('8101f6b8-1162-4f0d-a5b8-509b2776b2e2','過楓橋寺示遷老三首  其二','孫覿','宋','宋诗','song-poetry','','[]','三年瘴海臥炎霄，夢隔青風一水遙。',32,'全唐诗/poet.song.85000.json','["三年瘴海臥炎霄，夢隔青風一水遙。", "萬里歸來悲故物，銅駝埋沒草齊腰。"]'),
('ed89bc29-e2b8-48ad-a98e-12cbb5ebbb50','過楓橋寺示遷老三首  其三','孫覿','宋','宋诗','song-poetry','','[]','翠木蒼藤一兩家，門依古柳抱谿斜。',32,'全唐诗/poet.song.85000.json','["翠木蒼藤一兩家，門依古柳抱谿斜。", "古城流水參差是，不見玄都舊日花。"]'),
('8ce841c6-98f7-4d78-a74a-d97812dab6dc','題虎邱劍池二首  其一','孫覿','宋','宋诗','song-poetry','','[]','猘子齗齗老更狂，潭空百尺臥干將。',32,'全唐诗/poet.song.85000.json','["猘子齗齗老更狂，潭空百尺臥干將。", "但令雷煥占牛斗，不用朱雲請尚方。"]'),
('02ac65fd-cb2d-4bd5-bb4c-ad860805e528','題虎邱劍池二首  其二','孫覿','宋','宋诗','song-poetry','','[]','神兵一躍幾千年，石底乖龍抱寶眠。',32,'全唐诗/poet.song.85000.json','["神兵一躍幾千年，石底乖龍抱寶眠。", "尚有玉川懷寸鐵，裁詩救月淚潺湲。"]'),
('3b65fd4f-a233-41bf-a8d8-36c93f6e41d6','吳門道中二首  其一','孫覿','宋','宋诗','song-poetry','','[]','數間茅屋水邊村，楊柳依依綠映門。',32,'全唐诗/poet.song.85000.json','["數間茅屋水邊村，楊柳依依綠映門。", "渡口喚船人獨立，一簔煙雨濕黄昏。"]'),
('b42cecce-2d58-4b8d-986a-a60bf8061343','吳門道中二首  其二','孫覿','宋','宋诗','song-poetry','','[]','一點炊煙竹裏村，人家深閉雨中門。',32,'全唐诗/poet.song.85000.json','["一點炊煙竹裏村，人家深閉雨中門。", "數聲好鳥不如處，千丈藤蘿古木昏。"]'),
('a3b6bb3a-4d9f-4650-885f-1750de3b8567','龜潭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','真源閟仙扃，一綫下佛龕。',72,'全唐诗/poet.song.85000.json','["真源閟仙扃，一綫下佛龕。", "來從白馬洞，聚作烏龜潭。", "觸石細瑟瑟，循除走涵涵。", "漱齒類齧雪，湔衣真佩藍。", "醉紅灑面醒，衰白照影慚。", "延緣遂清景，拄策縱幽探。"]'),
('3e612602-529a-4b07-84e6-e0e63e50e2cd','龜潭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','心空閑有味，境寂澹無營。',72,'全唐诗/poet.song.85000.json','["心空閑有味，境寂澹無營。", "石鼎脹豕腹，幽幽暗泉鳴。", "銅盤印鳥迹，漠漠微雲行。", "起挽枝上紅，細傾榼中清。", "提壺亦勸飲，布穀仍催耕。", "悠然獨往願，一笑愜平生。"]'),
('06d76025-b04a-49a3-8a52-fe4d75898f7d','罨畫谿行四首  其一','孫覿','宋','宋诗','song-poetry','','[]','老牯浮鼻水中歸，綵雉應媒桑下飛。',64,'全唐诗/poet.song.85000.json','["老牯浮鼻水中歸，綵雉應媒桑下飛。", "蘿蔦冥冥山四起，數家雞犬煙樹裏。", "一支新綠漲晴溝，楊柳中間擊小舟。", "罨畫谿頭烏鳥樂，呼雨喚風不能休。"]'),
('95e0b948-382b-4561-8450-3e0d55e5f5a9','罨畫谿行四首  其二','孫覿','宋','宋诗','song-poetry','','[]','蜨趁花飛争入坐，倚空百尺遊絲墮。',64,'全唐诗/poet.song.85000.json','["蜨趁花飛争入坐，倚空百尺遊絲墮。", "亂山銜日半船明，斷雲載雨前村過。", "蕨芽戴土小兒拳，漁市人歸柳貫鮮。", "罨畫溪頭人語好，烹魚煮蕨餉春田。"]'),
('b283dc19-94af-42a9-bdf6-f4ea411c6610','罨畫谿行四首  其三','孫覿','宋','宋诗','song-poetry','','[]','沙頭綠暗已藏鴉，竹裏猶殘一兩花。',64,'全唐诗/poet.song.85000.json','["沙頭綠暗已藏鴉，竹裏猶殘一兩花。", "蝸廬抱柳開新國，燕語窺簾憶舊家。", "春風有信自年年，罨畫溪邊柳繫船。", "陶情滿滿酒如泉，醉與長缾藉草眠。"]'),
('cdbb80ba-e3be-4f05-8806-ecc6134cd593','罨畫谿行四首  其四','孫覿','宋','宋诗','song-poetry','','[]','翠木蒼藤繚白沙，槿籬茅店野人家。',64,'全唐诗/poet.song.85000.json','["翠木蒼藤繚白沙，槿籬茅店野人家。", "了無狡兔營三窟，只有黄蜂趁兩衙。", "樹頭獵獵酒旗風，罨畫溪邉賣酒翁。", "銀缾快瀉清若空，令君一笑面生紅。"]'),
('0a7ee688-f758-48a6-a5e2-d097d4679ef2','龜潭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','稚竹緣崖瘦，蒼藤翳樹昏。',48,'全唐诗/poet.song.85000.json','["稚竹緣崖瘦，蒼藤翳樹昏。", "野花渾少態，谷鳥自能言。", "獨曳煙中策，來傾月下尊。", "樂哉無與共，幽興在桑門。"]'),
('d09d9020-4463-44e1-b1df-9b433b497a22','龜潭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','蝸舍三間小，龜泉一勺甘。',48,'全唐诗/poet.song.85000.json','["蝸舍三間小，龜泉一勺甘。", "楞嚴渾不看，彌勒久同龕。", "潭影千峰倒，雲梢萬木參。", "巖花自無主，紅雨落毿毿。"]'),
('a8b29921-e4ea-4853-ac88-4b93c87f9e7e','題董令升待制朋谿','孫覿','宋','宋诗','song-poetry','','[]','先生谿上宅，華榜有殊稱。',96,'全唐诗/poet.song.85000.json','["先生谿上宅，華榜有殊稱。", "已爲山作主，更與谿爲朋。", "高甍俯流水，坐見南山稜。", "濯髪雲破碎，湔衣雪崩騰。", "老蟾駕月來，瀲灧一鏡升。", "舉櫂擊空明，玉壺響春冰。", "夜久羣動息，一嘯清風興。", "手持修月斧，自控赤鯉乘。"]'),
('0d999b1e-c058-4759-8d0a-f46931f8e46c','題莫壽朋內翰所藏東坡畫枯木','孫覿','宋','宋诗','song-poetry','','[]','龍筋鶴骨老催頽，百尺脩圍折巨雷。',32,'全唐诗/poet.song.85000.json','["龍筋鶴骨老催頽，百尺脩圍折巨雷。", "倦鵲飛來空百繞，踏枝不着又驚回。"]'),
('7b594e08-f218-4986-a57d-4daa7c660773','李茂嘉寄茶  其一','孫覿','宋','宋诗','song-poetry','','[]','蠻珍分到謫仙家，斷壁殘璋裹絳紗。',32,'全唐诗/poet.song.85000.json','["蠻珍分到謫仙家，斷壁殘璋裹絳紗。", "擬把金釵候湯眼，不將白玉伴脂麻。"]'),
('5db10edf-c499-4db1-92fe-73007a8d47b5','李茂嘉寄茶  其二','孫覿','宋','宋诗','song-poetry','','[]','大瓢貯月瀉銀瓶，瑟瑟松風入坐鳴。',32,'全唐诗/poet.song.85000.json','["大瓢貯月瀉銀瓶，瑟瑟松風入坐鳴。", "擬把金釵候湯眼，睡魔先已樹降旌。"]'),
('45b3d2f1-47be-4038-8e60-5c16f72e51d5','園中草木二首  其一','孫覿','宋','宋诗','song-poetry','','[]','葵花臥雨金杯覆，蕉葉欹風羽扇低。',32,'全唐诗/poet.song.85000.json','["葵花臥雨金杯覆，蕉葉欹風羽扇低。", "若信空華俱足幻，何妨伯厚載雞栖。"]'),
('df0b20b9-d4c2-4e0b-9663-ebd780cfbab4','園中草木二首  其二','孫覿','宋','宋诗','song-poetry','','[]','翠衿獨倚秋風立，絳幘猶含宿雨偏。',32,'全唐诗/poet.song.85000.json','["翠衿獨倚秋風立，絳幘猶含宿雨偏。", "已見異雞無應者，若爲矯首尚昂然。"]'),
('26f3fe76-3517-4f54-856d-cd7f8a255954','題德清縣舍松筠堂菊','孫覿','宋','宋诗','song-poetry','','[]','籬脚金花玉露團，枕叢寒蜨冷相看。',32,'全唐诗/poet.song.85000.json','["籬脚金花玉露團，枕叢寒蜨冷相看。", "不隨桃李供春事，且伴松筠到歲寒。"]'),
('cae0e21d-1ac4-46e9-aa35-420eff1a36dd','餘杭道中觀何人家竹','孫覿','宋','宋诗','song-poetry','','[]','平生不省問寒温，見竹欣然便扣門。',32,'全唐诗/poet.song.85000.json','["平生不省問寒温，見竹欣然便扣門。", "我是此君風月主，不應便與俗人言。"]'),
('ca715ab5-ade6-4750-a21c-a3daf5e997a4','送雪峰化主','孫覿','宋','宋诗','song-poetry','','[]','行盡千山與萬山，青鞋布襪水雲間。',32,'全唐诗/poet.song.85000.json','["行盡千山與萬山，青鞋布襪水雲間。", "龍天正繞毗那室，乞取凋胡一缽還。"]'),
('b6a02507-15d2-4b3b-8fcd-b02f429fa2c3','山長老寄茶','孫覿','宋','宋诗','song-poetry','','[]','睡魔迎我入華胥，夢境倏然一蜨如。',32,'全唐诗/poet.song.85000.json','["睡魔迎我入華胥，夢境倏然一蜨如。", "不用分燈遣將去，山翁茗盌爲驅除。"]'),
('63e89460-c4d2-4b5e-bcf2-a5e4ef375608','吳江教院首坐索詩賦一首','孫覿','宋','宋诗','song-poetry','','[]','石火光中客此身，只鑽故紙敝精神。',32,'全唐诗/poet.song.85000.json','["石火光中客此身，只鑽故紙敝精神。", "如今衰老渾無用，猶有虚名語世人。"]'),
('0471baa7-55c5-4e54-a3c1-3900107c2fed','送僧慧卓','孫覿','宋','宋诗','song-poetry','','[]','瓦盂錫杖布行纒，風意泠泠意欲仙。',32,'全唐诗/poet.song.85000.json','["瓦盂錫杖布行纒，風意泠泠意欲仙。", "一片閑雲無倚著，悠然吹墮野人邊。"]'),
('f852c376-c9f4-4746-a87f-6bb378360714','送可珪化主','孫覿','宋','宋诗','song-poetry','','[]','龍天萬德擁天堂，中有維摩六尺牀。',32,'全唐诗/poet.song.85000.json','["龍天萬德擁天堂，中有維摩六尺牀。", "但遣文殊來問疾，毗耶一鉢滿城香。"]'),
('c8b2449a-4100-418b-8ff4-0e27a67d7b52','復闍黎寄示龍興舉老唱酬書一偈還之','孫覿','宋','宋诗','song-poetry','','[]','無臺無鏡亦無塵，云何去現句文身。',32,'全唐诗/poet.song.85000.json','["無臺無鏡亦無塵，云何去現句文身。", "只有華嚴八千偈，酬對毘那彼上人。"]'),
('1a1ea161-d3cb-4a93-9488-8af6b8b1a89e','題刪定姪畫卷次其韻','孫覿','宋','宋诗','song-poetry','','[]','青尖簇簇兩春山，翠壘峨峨十二鬟。',32,'全唐诗/poet.song.85000.json','["青尖簇簇兩春山，翠壘峨峨十二鬟。", "彷彿陽臺夢中見，試憑畫手駐君顔。"]'),
('647e8029-2d10-463e-82d1-b5df9468666e','修上人以楞嚴圓覺二經見寄書六言一偈','孫覿','宋','宋诗','song-poetry','','[]','月標指上自見，珠繫衣中可尋。',28,'全唐诗/poet.song.85000.json','["月標指上自見，珠繫衣中可尋。", "卷去與人遮眼，却來問佛徴心。"]'),
('0918812d-2385-4c80-88cb-217de1c2dbed','鄭惇老謙老出示三賦','孫覿','宋','宋诗','song-poetry','','[]','妙絕窺三賦，雄才想二豪。',48,'全唐诗/poet.song.85000.json','["妙絕窺三賦，雄才想二豪。", "望驚河伯歎，却走季咸逃。", "句挾青邱大，吟翻白雪高。", "定知空驥北，猶待九方臯。"]'),
('4d72a4f5-e269-4ddb-9c78-03152c3cb547','題隆上人墨梅花','孫覿','宋','宋诗','song-poetry','','[]','一枝插向釵頭見，千樹開時雪裏看。',32,'全唐诗/poet.song.85000.json','["一枝插向釵頭見，千樹開時雪裏看。", "慚愧道人三昧手，盡將春色寄豪端。"]'),
('4e3e9098-a25d-402e-a4b1-2d22cc0b3c14','送五侄歸南安','孫覿','宋','宋诗','song-poetry','','[]','綠髪青衫美少年，追風一抹紫鸞鞭。',32,'全唐诗/poet.song.85000.json','["綠髪青衫美少年，追風一抹紫鸞鞭。", "十年竹馬兒童舊，洗眼來看立道邊。"]'),
('3e338fe5-5311-4289-b023-49083e2f4966','題因闍黎静節軒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','露葉纖纖翦綠瓊，三椽瀟灑竹間亭。',64,'全唐诗/poet.song.85000.json','["露葉纖纖翦綠瓊，三椽瀟灑竹間亭。", "青蓮池上狻猊坐，碧玉壺中翡翠屏。", "曉幌日移光破碎，夜窗風過響瓏玲。", "何人暫脱紅塵履，一枕昏昏醉鼾醒。"]'),
('645acf5b-3b9a-46cc-9e7d-f6dba84ac825','題因闍黎静節軒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','蒼雲十畝護禪扃，中有金仙不死庭。',64,'全唐诗/poet.song.85000.json','["蒼雲十畝護禪扃，中有金仙不死庭。", "邂逅種桃規作伴，蕭條對鶴兩忘形。", "空華閃閃風中絮，浪蕊悠悠水上萍。", "珍重此君真石友，歲寒不改自青青。"]'),
('6fdda7ae-7be9-415d-a2b2-dfe8569b480d','龜潭三首  其一','孫覿','宋','宋诗','song-poetry','','[]','埋没榛蕪不記年，穿雲絡石自濺濺。',32,'全唐诗/poet.song.85000.json','["埋没榛蕪不記年，穿雲絡石自濺濺。", "柳州莫作愚谿對，乞與佳名到處傳。"]'),
('96f31010-f833-4e80-86ac-757163f91d03','龜潭三首  其二','孫覿','宋','宋诗','song-poetry','','[]','蒔竹流泉占一邱，倚筇盡日看游鯈。',32,'全唐诗/poet.song.85000.json','["蒔竹流泉占一邱，倚筇盡日看游鯈。", "崎嶇好事無人共，獨飲泉旁自獻酬。"]'),
('c398e246-7167-44a2-82c8-8e5533f00a3b','龜潭三首  其三','孫覿','宋','宋诗','song-poetry','','[]','山空水浄竹娟娟，玉礫金沙自炯然。',32,'全唐诗/poet.song.85000.json','["山空水浄竹娟娟，玉礫金沙自炯然。", "宿鷺驚窺潭底日，潛魚翻動水中天。"]'),
('ab357356-6856-4526-a622-385313ec10ce','春事三首  其一','孫覿','宋','宋诗','song-poetry','','[]','茆棟依林出，松扉傍水斜。',48,'全唐诗/poet.song.85000.json','["茆棟依林出，松扉傍水斜。", "浮蒼圍百叠，亂綠翳三叉。", "屋破蝸書壁，庭蕪鶴印沙。", "小桃供一笑，已著兩三花。"]'),
('8e37d2ef-3318-4558-bac7-ad5eec599e29','春事三首  其二','孫覿','宋','宋诗','song-poetry','','[]','閑隨白雲行，倦倚青松立。',48,'全唐诗/poet.song.85000.json','["閑隨白雲行，倦倚青松立。", "嚼葉須鬛香，藉草衣巾濕。", "風從月下生，月向杯中吸。", "戴星莫匆匆，秉燭要汲汲。"]'),
('528e23a3-99e5-4f8d-bb18-2e90e5bb3e39','春事三首  其三','孫覿','宋','宋诗','song-poetry','','[]','黄鸝遺好音，碧草縈别恨。',48,'全唐诗/poet.song.85000.json','["黄鸝遺好音，碧草縈别恨。", "雨擢翠千尋，風斂紅一寸。", "持醪散百憂，琢句破孤悶。", "呼童數擊鮮，無久諸郎溷。"]'),
('4a580b7a-09d2-484b-a129-92f3137b0c24','龜潭守冢僧伐去大芭蕉種二松其上賦小詩記之二首  其一','孫覿','宋','宋诗','song-poetry','','[]','粲粲豐肌猶外好，便便大腹已中空。',32,'全唐诗/poet.song.85000.json','["粲粲豐肌猶外好，便便大腹已中空。", "故衣狼藉三秋雨，破扇飄搖一夜風。"]'),
('67c836ec-88a7-4123-8cc9-9129d4b94f9e','龜潭守冢僧伐去大芭蕉種二松其上賦小詩記之二首  其二','孫覿','宋','宋诗','song-poetry','','[]','草亡木卒太匆匆，獨有髯龍在眼中。',32,'全唐诗/poet.song.85000.json','["草亡木卒太匆匆，獨有髯龍在眼中。", "雨折風吹終不死，霜根雪節貫青銅。"]'),
('4eb15f04-51d2-4378-9fa7-3f0982a7b590','遊金沙寺寺有陸希聲侍郎讀書堂在頤山上二首  其一','孫覿','宋','宋诗','song-poetry','','[]','一龕明滅佛前燈，破裓猶殘一兩僧。',32,'全唐诗/poet.song.85000.json','["一龕明滅佛前燈，破裓猶殘一兩僧。", "說似鴻盤讀書處，試尋幽伴拄烏藤。"]'),
('2191d837-a700-4270-bf41-8d11c3f2342c','遊金沙寺寺有陸希聲侍郎讀書堂在頤山上二首  其二','孫覿','宋','宋诗','song-poetry','','[]','綠笋遺苞半出籬，清溪一曲翠相迷。',32,'全唐诗/poet.song.85000.json','["綠笋遺苞半出籬，清溪一曲翠相迷。", "古苔稱意壞牆滿，好鳥盡情深樹啼。"]'),
('8bbd164f-78cb-4141-a41c-d8e21f164bbe','金沙寺端老營大藏殿小詩示之','孫覿','宋','宋诗','song-poetry','','[]','平生不讀一行經，解說如來最上乘。',32,'全唐诗/poet.song.85000.json','["平生不讀一行經，解說如來最上乘。", "但繞禪床行一帀，免教鑽紙似癡蠅。"]'),
('b3e520fb-5576-47e6-adf0-6dbae7dbd2a6','秋日二首  其一','孫覿','宋','宋诗','song-poetry','','[]','豆熟連村雨葉黄，秔肥蘸水露華香。',32,'全唐诗/poet.song.85000.json','["豆熟連村雨葉黄，秔肥蘸水露華香。", "凉蟬已抱寒莖槁，凍蜨猶穿晚菊忙。"]'),
('e04afff0-876a-4765-9b01-03d0cc9d0397','秋日二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雲巘曾稜路遠蒼，井梧蕭瑟隕疏黄。',32,'全唐诗/poet.song.85000.json','["雲巘曾稜路遠蒼，井梧蕭瑟隕疏黄。", "浪浪一枕芭蕉雨，端爲幽人滴夜長。"]'),
('54c84bcd-37e1-4b5b-ae22-89eb7ddb5652','歲暮郊行','孫覿','宋','宋诗','song-poetry','','[]','殘雪溶溶水披凍，山空翠濕衣巾重。',64,'全唐诗/poet.song.85000.json','["殘雪溶溶水披凍，山空翠濕衣巾重。", "東家西家酒初熟，南枝北枝春欲動。", "班坐偶隨鷗鷺集，意行適與牛羊共。", "直將萬事付狙公，莫浪歡喜蹋破甕。"]'),
('a43c620c-b8fa-4e59-a33f-061f6279634f','臞庵浮天閣','孫覿','宋','宋诗','song-poetry','','[]','黄蘆吹雪滿汀洲，萬里煙波接素秋。',64,'全唐诗/poet.song.85000.json','["黄蘆吹雪滿汀洲，萬里煙波接素秋。", "數點征帆天上落，一輪斜日水中流。", "長橋蹋月隨君伴，小閣浮天賦遠遊。", "便買一舟爲泛宅，此生何必老莵裘。"]'),
('fa69b3f3-57ed-4b95-ab13-d79d3fd82a64','向伯恭侍郎致政薌林築一堂名之曰企疏晉陵孫某聞而賦詩二首  其一','孫覿','宋','宋诗','song-poetry','','[]','銅臭應作幺，夢屍當得官。',96,'全唐诗/poet.song.85000.json','["銅臭應作幺，夢屍當得官。", "喁喁魚聚沫，戢戢蚋集酸。", "高人有遠抱，一笑視鼠肝。", "水將洗耳用，山作拄頰看。", "種芳茹秋菊，搴秀紉春蘭。", "披披芰荷衣，采采苜蓿盤。", "三徑偭真境，一瓢非世歡。", "富貴挽不來，爲我歌考槃。"]'),
('c237dda1-74c2-400f-9c49-8ba17e64b094','向伯恭侍郎致政薌林築一堂名之曰企疏晉陵孫某聞而賦詩二首  其二','孫覿','宋','宋诗','song-poetry','','[]','且學方回痴，莫羨董公健。',96,'全唐诗/poet.song.85000.json','["且學方回痴，莫羨董公健。", "誰令軀七尺，浪作青紫楦。", "更搖乞憐尾，仍出弔喪面。", "薌林有老仙，蚤具佛眼見。", "國恩倘粗酬，已債遂焚劵。", "驅除竹馬棄，狼藉芻狗踐。", "寥寥漢二傅，千歲一關楗。", "竟日飲無何，更補離騷傳。"]'),
('c0df6042-1498-4275-a4f2-08781b567657','再至龜潭','孫覿','宋','宋诗','song-poetry','','[]','歲歲來尋罨畫春，看山弄水意長新。',32,'全唐诗/poet.song.85000.json','["歲歲來尋罨畫春，看山弄水意長新。", "不知流水今何處，只有青山是故人。"]'),
('fd0d2308-aa14-47d4-b30d-74268497e663','湖洑上冢繫舟丁山田舍小憩','孫覿','宋','宋诗','song-poetry','','[]','清谿三百曲，一片春風綠。',72,'全唐诗/poet.song.85000.json','["清谿三百曲，一片春風綠。", "茅屋有人家，窈窕閉深竹。", "老去耽田里，寓目快親矚。", "風漪卷翠綃，雲巘鏤蒼玉。", "尋盟喚白鷗，解佩贖黄犢。", "獨嘯無一人，傳聲滿空谷。"]'),
('67f8ea43-a1a9-4572-9def-4f0092e3fc73','舟次蜀山遇大風雨','孫覿','宋','宋诗','song-poetry','','[]','阿香推雷車，躡雲捕黄蛇。',72,'全唐诗/poet.song.85000.json','["阿香推雷車，躡雲捕黄蛇。", "打頭風似箭，注面雨如麻。", "篙師不改色，移舟並蒼霞。", "結纜繫桑本，小定起復挐。", "畏途失九折，迷津悟三叉。", "誰知一笑中，平地有褒斜。"]'),
('ba426ee1-a63f-43b0-a7f5-54dd41c8b8be','讀史','孫覿','宋','宋诗','song-poetry','','[]','莫羨馬革裹，猶堪柳車囚。',72,'全唐诗/poet.song.85000.json','["莫羨馬革裹，猶堪柳車囚。", "誰令骨作鯁，且慕舌爲柔。", "自笑丹心折，人言老語偷。", "直將輪覆井，仍取带維舟。", "唾面我勿拭，溺灰汝何尤。", "君看簀中屍，起斷魏齊頭。"]'),
('1ebe14b4-83dc-4383-955b-790d27030cdb','臨安道中二首  其一','孫覿','宋','宋诗','song-poetry','','[]','莽莽原野迥，練練沙水清。',48,'全唐诗/poet.song.85000.json','["莽莽原野迥，練練沙水清。", "逕封面苔滑，樹隕風籜鳴。", "小立聽鳥語，深尋見魚行。", "夕陽紅未斂，彷彿見參横。"]'),
('7e98b16a-a937-4b47-adf0-acb80343800d','臨安道中二首  其二','孫覿','宋','宋诗','song-poetry','','[]','微流隱復見，一曲宛秋蛇。',48,'全唐诗/poet.song.85000.json','["微流隱復見，一曲宛秋蛇。", "柳老蟲巢葉，潮平鳥篆沙。", "青鞋踏雨滑，烏帽倚風斜。", "何處堪攜手，宜城賣酒家。"]'),
('5329237c-5233-4ef0-a729-cb5edef79c70','將軍樹','孫覿','宋','宋诗','song-poetry','','[]','當年樹下遂兒嬉，直到將軍衣錦時。',32,'全唐诗/poet.song.85000.json','["當年樹下遂兒嬉，直到將軍衣錦時。", "老幹千年龍化後，如今空有寄生枝。"]'),
('4a092371-e261-48f0-b592-146f4f8f1a82','廣教寺種玉軒','孫覿','宋','宋诗','song-poetry','','[]','道人餘浄業，種竹把雲根。',48,'全唐诗/poet.song.85000.json','["道人餘浄業，種竹把雲根。", "野色禪窗迅，秋聲客枕喧。", "持鉏掀鼠壤，插棘護龍孫。", "不放纖塵立，清風自滿門。"]'),
('93099b69-b86d-4b4f-9559-cf918891a345','廣教寺湧翠閣','孫覿','宋','宋诗','song-poetry','','[]','高甍縹渺冠曾巔，一握孤雲尺五天。',32,'全唐诗/poet.song.85000.json','["高甍縹渺冠曾巔，一握孤雲尺五天。", "試向堂前參翠柏，要看地底出青蓮。"]'),
('8fb89449-20d3-440e-8ea6-65365696cac6','某送妻母章碩人之葬道過紫藤省拜妻祖莊敏公及妻伯叔諸公之墓題勝因寺壁','孫覿','宋','宋诗','song-poetry','','[]','宰樹連山淚葉春，纍纍高冢臥麒麟。',32,'全唐诗/poet.song.85000.json','["宰樹連山淚葉春，纍纍高冢臥麒麟。", "羊曇一慟西州去，華屋生存有幾人。"]'),
('c8bf15e8-c52a-4e43-81a8-55a154682e69','臨安羅氏占春軒','孫覿','宋','宋诗','song-poetry','','[]','扶疏繞屋樹葱蘢，一笑歡迎得此翁。',32,'全唐诗/poet.song.85000.json','["扶疏繞屋樹葱蘢，一笑歡迎得此翁。", "燕麥兔葵俱掃地，只栽桃李占春風。"]'),
('ec2fb555-b6b4-4fd5-a739-a8a6b34e1fdf','寄題虞陽山周氏隱居五詠 妙光庵','孫覿','宋','宋诗','song-poetry','','[]','孤煙抱水村，落日滿雲樹。',72,'全唐诗/poet.song.85000.json','["孤煙抱水村，落日滿雲樹。", "亂山如連環，楊柳是門處。", "青繚竹谿灣，翠點苔石路。", "鐘魚寂無聲，白日掩僧户。", "茗碗酌雲腴，香篆擢煙縷。", "坐穩不知夕，炯炯山月吐。"]'),
('1545b379-c519-4bdd-965b-e9b0c3f00aeb','寄題虞陽山周氏隱居五詠 佚老堂','孫覿','宋','宋诗','song-poetry','','[]','浮生知幾何，聞道苦不早。',96,'全唐诗/poet.song.85000.json','["浮生知幾何，聞道苦不早。", "過眼電掣雲，轉看露晞草。", "怱怱已解鑣，馬鬛翳蓬葆。", "夫君悟無生，不待須髪皓。", "朝行清谿曲，暮宿白雲道。", "柴門鳥跡絕，槁葉風自掃。", "竹間雨泠泠，花上日杲杲。", "坐對五大夫，自足休吾老。"]'),
('74766d31-bee2-45f6-93a2-74b3e18c7894','寄題虞陽山周氏隱居五詠 柳堂漁舍','孫覿','宋','宋诗','song-poetry','','[]','老來厭朝市，静占五百弓。',96,'全唐诗/poet.song.85000.json','["老來厭朝市，静占五百弓。", "山稜瘦如削，水面清若空。", "行穿萬蓋青，臥戴一葉紅。", "黄柑千頭奴，白鳧五尺童。", "銀刀貫翠縷，象鼻卷碧筩。", "一醉百不知，漁父真家風。", "幽尋屬無事，散此九節筇。", "空濛水雲裏，端生畫屏中。"]'),
('a56e5626-1431-477c-8bc4-43dd64c8a700','寄題虞陽山周氏隱居五詠 環翠亭','孫覿','宋','宋诗','song-poetry','','[]','樵磴盤蒼巘，漁磯俯碧潭。',48,'全唐诗/poet.song.85000.json','["樵磴盤蒼巘，漁磯俯碧潭。", "羣尖清染黛，一曲翠挼藍。", "冉冉松雲細，娟娟竹露涵。", "春風萬楊柳，綠影亂毿毿。"]'),
('3ce10eb6-2a55-4695-9f12-656363d72363','寄題虞陽山周氏隱居五詠 五秀堂','孫覿','宋','宋诗','song-poetry','','[]','一幹中柴立，交柯擁四垂。',48,'全唐诗/poet.song.85000.json','["一幹中柴立，交柯擁四垂。", "定知三世種，已長五孫枝。", "端是神明力，非關雨露私。", "躊躇三匝繞，爲賦角弓詩。"]'),
('2e0d47ed-1702-4b1a-90cb-fde3677f6c26','卓持者手持筇竹見遺書六言一偈','孫覿','宋','宋诗','song-poetry','','[]','滇池赤藤使者，太乙青藜老仙。',28,'全唐诗/poet.song.85000.json','["滇池赤藤使者，太乙青藜老仙。", "如何一筇九節，拄到玉女盆邊。"]'),
('3acba6ee-b841-4b5a-a369-c3412b3ff8f9','喜陳紹曾至','孫覿','宋','宋诗','song-poetry','','[]','雨苔荒逕石，風葉擁門衡。',48,'全唐诗/poet.song.85000.json','["雨苔荒逕石，風葉擁門衡。", "破甑渠能顧，虚舟任自横。", "燭殘無共影，谷應有同聲。", "試問門前轍，多應是友生。"]'),
('8189d5de-05be-4e3d-b375-76f2d54fd86e','重陽前数日微暑小雨遂凉二首  其一','孫覿','宋','宋诗','song-poetry','','[]','小雨送殘暑，新凉入郊墟。',48,'全唐诗/poet.song.85000.json','["小雨送殘暑，新凉入郊墟。", "丹葉互明滅，玄雲時卷舒。", "行螘尚移垤，盤蝸已伏廬。", "翛翛風響變，零落扇思疏。"]'),
('362fed6c-8bdd-46d7-a079-f6ee61a0ff4a','重陽前数日微暑小雨遂凉二首  其二','孫覿','宋','宋诗','song-poetry','','[]','披衣趁雞晨，耿耿殘月曙。',48,'全唐诗/poet.song.85000.json','["披衣趁雞晨，耿耿殘月曙。", "林表霽霞升，青紅滿雲樹。", "凉蟬猶抱葉，寒蟲欲壞户。", "行行繞黄菊，狼藉衣上露。"]'),
('41631be1-68ad-4b4d-9295-4839a5ae7cc6','崑山道中二首  其一','孫覿','宋','宋诗','song-poetry','','[]','歸鳥破煙沒，飛泉隔隴分。',48,'全唐诗/poet.song.85000.json','["歸鳥破煙沒，飛泉隔隴分。", "松門挂疏雨，樵路蹋行雲。", "獨往隨漫興，高談遺世紛。", "悠然一杯酒，可以傲人羣。"]'),
('09015114-9dbd-429e-aa33-7b5b0aea985a','崑山道中二首  其二','孫覿','宋','宋诗','song-poetry','','[]','日脚銜半璧，江面横匹素。',48,'全唐诗/poet.song.85000.json','["日脚銜半璧，江面横匹素。", "一片黄蘆秋，摵摵風景暮。", "閑枕曲肱眠，自琢撚須句。", "稍稍山月吐，已復草多露。"]'),
('4a7e0543-42ab-46f3-8dda-cbbc85fa1c6f','次韻葉首善龍圖見寄','孫覿','宋','宋诗','song-poetry','','[]','十年流落臥漳濱，種秫畦蔬手自親。',64,'全唐诗/poet.song.85000.json','["十年流落臥漳濱，種秫畦蔬手自親。", "心似疲牛猶喘月，身如病木豈知春。", "試彈長鋏撩公子，忽解綈袍值故人。", "健筆縱横驚老眼，恍疑帝所夢韶鈞。"]'),
('3dd610d2-8783-4b18-a8c7-2149cc7af832','吳漢逸家荆谿蓄古書奇器甚富余欲造觀而未果賦小詩先之','孫覿','宋','宋诗','song-poetry','','[]','高人臥江海，煙雨三家村。',120,'全唐诗/poet.song.85000.json','["高人臥江海，煙雨三家村。", "白眼憎俗徒，青山自當門。", "披圖望千載，耿耿尚自存。", "金鑄騕褭蹏，漆書科斗文。", "虬螭盤六印，犧象刻四尊。", "劍包虎皮斑，琴漫蛇腹紋。", "猶吐星芒寒，尚带雷斧痕。", "我亦望古者，昂昂真戴盆。", "儻未倚門揮，應許置榻論。", "從公問奇字，載酒過子雲。"]'),
('ff8c3331-978e-476b-b38a-0a858732ca51','題删定姪畫卷二首  其一','孫覿','宋','宋诗','song-poetry','','[]','筆下鑿開混沌，眼中見此崔嵬。',28,'全唐诗/poet.song.85000.json','["筆下鑿開混沌，眼中見此崔嵬。", "海上神鼇負出，天邊靈鷲飛來。"]'),
('f0569159-4919-4126-8fcf-8963cc2235be','題删定姪畫卷二首  其二','孫覿','宋','宋诗','song-poetry','','[]','水邊兩鵠語時，山下一牛鳴地。',28,'全唐诗/poet.song.85000.json','["水邊兩鵠語時，山下一牛鳴地。", "蒼梧翠竹森然，長與閑雲臥起。"]'),
('03067dc3-8e57-43f9-95a3-a4b49ba3475e','寄題四明吳勰拙軒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','分寸躋攀曳九牛，一錐無地拙於鳩。',32,'全唐诗/poet.song.85000.json','["分寸躋攀曳九牛，一錐無地拙於鳩。", "穿鍼結縷非吾事，不上天孫乞巧樓。"]'),
('6dce9519-29ce-4629-93a5-630530be433d','寄題四明吳勰拙軒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','老罷誰當問喘牛，羈栖具作寄巢鳩。',32,'全唐诗/poet.song.85000.json','["老罷誰當問喘牛，羈栖具作寄巢鳩。", "蓋茆一把藏吾拙，便是元龍百尺樓。"]'),
('02be64f6-fc9e-4fd8-9fa4-950d905eb5c5','寄題臨安王氏通幽軒','孫覿','宋','宋诗','song-poetry','','[]','翠樾兩檐交復，紫苔一徑微通。',28,'全唐诗/poet.song.85000.json','["翠樾兩檐交復，紫苔一徑微通。", "雨籜猶含夏綠，風苞已褪春紅。"]'),
('72e1577e-f0d6-4b61-958a-c3ce03c023e5','柳','孫覿','宋','宋诗','song-poetry','','[]','修纖似束楚腰支，楊柳春風二月時。',32,'全唐诗/poet.song.85000.json','["修纖似束楚腰支，楊柳春風二月時。", "金地化身千佛眼，錦江新様十宮眉。"]'),
('48773f8d-60ce-4041-aaee-f451e209e3c2','雨二首  其一','孫覿','宋','宋诗','song-poetry','','[]','山空發清響，樓迥落餘霏。',48,'全唐诗/poet.song.85000.json','["山空發清響，樓迥落餘霏。", "掩冉花頭重，渾酣水面肥。", "喧豗沉地鏡，飄灑浄垣衣。", "數點蒼茫裏，饑烏接翅歸。"]'),
('ce46ab6e-f8a4-408b-89ab-3d7de515d6ca','雨二首  其二','孫覿','宋','宋诗','song-poetry','','[]','淅瀝珠跳瓦，淋浪綆縋簷。',48,'全唐诗/poet.song.85000.json','["淅瀝珠跳瓦，淋浪綆縋簷。", "林園春寂寂，燈火夜厭厭。", "寒著衣稜起，愁牽酒户添。", "詩翁獨無事，危坐撚衰髯。"]'),
('5930c6d7-cb7a-4841-a1d4-a68a283301e0','送僧德最','孫覿','宋','宋诗','song-poetry','','[]','剝啄動柴荆，相看兩眼青。',48,'全唐诗/poet.song.85000.json','["剝啄動柴荆，相看兩眼青。", "詩如雲態度，人似鶴儀形。", "妙斵窺天巧，哀彈感夢靈。", "定知花雨裏，亂石點頭聽。"]'),
('d84c034a-74b3-48fe-9c2a-f0fd7da5f328','朱彦直穹石堂','孫覿','宋','宋诗','song-poetry','','[]','擬把高天補，曾將巨海填。',72,'全唐诗/poet.song.85000.json','["擬把高天補，曾將巨海填。", "猶殘如蝸練，尚带祖龍鞭。", "勢重坤輿壯，根深粤嶠連。", "孤騫摶鷲羽，突立冠鼇顛。", "錫號俄三品，論材但一拳。", "誰令此奇偉，偃臥獨魁然。"]'),
('682ad4ea-1030-46c2-a90c-5ed4378c577a','小園春事二首  其一','孫覿','宋','宋诗','song-poetry','','[]','屋頭喚雨泥滑滑，萬瓦紛披土囊發。',64,'全唐诗/poet.song.85000.json','["屋頭喚雨泥滑滑，萬瓦紛披土囊發。", "西園春事一時休，繁紅浸亂煙脂雪。", "綠蘿高張翠羽蓋，蒼巘中斷青玉玦。", "不見枝上一點紅，千頃桑麻光似潑。"]'),
('11c8178d-67e1-431d-aa8a-25db47ee9795','小園春事二首  其二','孫覿','宋','宋诗','song-poetry','','[]','小園花柳爭春發，風雨顛狂二三月。',64,'全唐诗/poet.song.85000.json','["小園花柳爭春發，風雨顛狂二三月。", "斷梗梢空轉若迷，細紅糝逕繁如纈。", "叵堪繞屋溜潺潺，可厭觸途泥活活。", "不妨暫柅故人車，大似陳公井中轄。"]'),
('7385c728-d37b-47e3-947c-fab806e36572','夏日田舍二首  其一','孫覿','宋','宋诗','song-poetry','','[]','斷塹疏新碧，長林驚遠揚。',48,'全唐诗/poet.song.85000.json','["斷塹疏新碧，長林驚遠揚。", "魚跳蒲葉偃，鵲起樹頭昂。", "覓句投詩社，逃禪入醉鄉。", "夢回殘酒裏，月可一庭方。"]'),
('91ec5e19-2b3b-46de-ac8b-04ee9cd521c8','夏日田舍二首  其二','孫覿','宋','宋诗','song-poetry','','[]','麥臥黄雲壠，秧分綠錦畦。',48,'全唐诗/poet.song.85000.json','["麥臥黄雲壠，秧分綠錦畦。", "犬來迎客路，鳥去背人啼。", "虺虺饑雷吼，昏昏醉纈迷。", "只疑塵土涴，獨自照清谿。"]'),
('f21020b8-1db7-430f-a9cf-88b89ee90518','夏日京口道中二首  其一','孫覿','宋','宋诗','song-poetry','','[]','冉冉征途去，眈眈畏日長。',48,'全唐诗/poet.song.85000.json','["冉冉征途去，眈眈畏日長。", "枕流浣清泚，倚樹憩蒼凉。", "蟬抱風枝響，螢升露草光。", "不眠愁獨夜，臥看月侵床。"]'),
('0ce447c6-fbbc-4c8a-983d-af44914d2c5a','夏日京口道中二首  其二','孫覿','宋','宋诗','song-poetry','','[]','亭臯一雨過，清飈吹面凉。',48,'全唐诗/poet.song.85000.json','["亭臯一雨過，清飈吹面凉。", "雲綻微月吐，引杯吸空光。", "獨詣敞神界，冥搜破天荒。", "扣舷歌小海，幽意滿滄浪。"]'),
('0c522266-d011-45a0-83af-7d2212b0a66b','京口普照寺','孫覿','宋','宋诗','song-poetry','','[]','敗屋茨生草，崩崖蔓老藤。',48,'全唐诗/poet.song.85000.json','["敗屋茨生草，崩崖蔓老藤。", "布金無長者，持鉢有殘僧。", "撥刺魚跳釡，睢盱鼠瞰燈。", "炎炎三伏暑，岑絕冷如冰。"]'),
('e250f016-3566-41ac-8c79-28f77dd771d9','都統劉侯築新第不居供佛其中號布金庵遣騎入泉南迎山老主之','孫覿','宋','宋诗','song-poetry','','[]','羣魔起爲祟，百堵掀作灰。',72,'全唐诗/poet.song.85000.json','["羣魔起爲祟，百堵掀作灰。", "那聞五花葉，但見一莓苔。", "將軍道南宅，萬礎蟠金堆。", "天瑞黄鶴下，地湧青蓮開。", "老仙逃僧去，大士問疾來。", "龍天擁猊坐，百蠻奮春雷。"]'),
('a741cf14-c2f4-45af-b0e2-4b8517bc0d3d','吳門道中','孫覿','宋','宋诗','song-poetry','','[]','小橋分路各西東，寂寂松窗半掩同。',32,'全唐诗/poet.song.85000.json','["小橋分路各西東，寂寂松窗半掩同。", "客夢悠揚殘酒裏，一池荷葉雨聲中。"]'),
('0df92049-bf91-49c5-b588-0f07cfb3c010','魏江道上得小庵解裝小愒','孫覿','宋','宋诗','song-poetry','','[]','老柳當門翠十尋，桑麻一曲窈然深。',32,'全唐诗/poet.song.85000.json','["老柳當門翠十尋，桑麻一曲窈然深。", "蒼苔滿地無人掃，只有酴醿一架陰。"]'),
('f759a307-6973-4023-9c64-23138d550470','示鶴林山老二首  其一','孫覿','宋','宋诗','song-poetry','','[]','應化來江右，乘流出嶠南。',48,'全唐诗/poet.song.85000.json','["應化來江右，乘流出嶠南。", "後身逢七七，前話續三三。", "坐見諸天繞，來聽二士談。", "更無木上坐，只有佛同龕。"]'),
('fbb5fce6-fc54-48d8-aee5-1997ddc332c0','示鶴林山老二首  其二','孫覿','宋','宋诗','song-poetry','','[]','一别三千里，重臨二十年。',48,'全唐诗/poet.song.85000.json','["一别三千里，重臨二十年。", "霜蒹空老矣，雪柏自依然。", "習氣詩情在，真心佛果圓。", "相看無一語，趺坐炷爐煙。"]'),
('0af22aff-1c4f-4049-b9c5-65e8090bb495','宜興林尉山父巢仙亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','半篙淥漲狎鷗邊，萬點青尖拄笏前。',32,'全唐诗/poet.song.85000.json','["半篙淥漲狎鷗邊，萬點青尖拄笏前。", "水色山容鬭清好，吳中關市有巢仙。"]'),
('97cc2b11-a652-4cdb-a76a-cc0b7c657c94','宜興林尉山父巢仙亭二首  其二','孫覿','宋','宋诗','song-poetry','','[]','且可浮沉隨俗裏，更將強健鬭尊前。',32,'全唐诗/poet.song.85000.json','["且可浮沉隨俗裏，更將強健鬭尊前。", "懸知天上多官府，盍向人中作地仙。"]'),
('4a3cd768-94b3-4513-a182-eb316023adf3','浮遠堂','孫覿','宋','宋诗','song-poetry','','[]','月堕山城小，沙寒水國秋。',144,'全唐诗/poet.song.85000.json','["月堕山城小，沙寒水國秋。", "雲根拔地起，冰柱蹴天浮。", "紫翠分鼇嶺，青紅雜蜃樓。", "舟航通萬里，城郭數三州。", "刺史馮熊貴，仙翁控鯉遊。", "八龍追後駿，五馬駐前騶。", "露舄迎門鵲，風簾壓海牛。", "地偏餘勝迹，山好對冥收。", "雨爲催詩至，雲應度曲留。", "歡呼領百罰，跌宕散千憂。", "顛倒青霞帔，淋漓紫綺裘。", "誰鑱峴山石，千載記風流。"]'),
('b1fc38fd-312b-4ee7-9f68-e9bac53aafaf','連雪苦寒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','霜氣森森背有芒，風稜槭槭面疑創。',32,'全唐诗/poet.song.85000.json','["霜氣森森背有芒，風稜槭槭面疑創。", "破衾且作龜頭縮，短褐愁牽鶴脛長。"]'),
('fb15bc5d-383e-41f9-b7ee-92f304abe876','連雪苦寒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','怪底騎驢詠雪詩，東風有信在南枝。',32,'全唐诗/poet.song.85000.json','["怪底騎驢詠雪詩，東風有信在南枝。", "來麰已報豐年瑞，屬國餐氈且耐饑。"]'),
('413c1e1a-a598-4928-a4ed-ab5b8f01e430','大雪後喜晴二首  其一','孫覿','宋','宋诗','song-poetry','','[]','嶺雪班班在，崖泉咽咽鳴。',48,'全唐诗/poet.song.85000.json','["嶺雪班班在，崖泉咽咽鳴。", "一州明曉霽，萬壑貯春聲。", "蹬滑藤枝健，沙晴屐齒輕。", "小兒修浄供，酌茗慰孤清。"]'),
('c7f3344f-3691-4578-8b54-2e250d26787a','大雪後喜晴二首  其二','孫覿','宋','宋诗','song-poetry','','[]','雪浄山容改，風回野意新。',48,'全唐诗/poet.song.85000.json','["雪浄山容改，風回野意新。", "草根清漠漠，沙尾碧鱗鱗。", "有客推門版，呼童整角巾。", "風流楊柳似，一噱散千顰。"]'),
('252e5d7d-4e38-4803-be80-47b15ab55f58','送鄒次賈歸臨川二首  其一','孫覿','宋','宋诗','song-poetry','','[]','不負丹雞約，來尋白馬盟。',48,'全唐诗/poet.song.85000.json','["不負丹雞約，來尋白馬盟。", "龍鍾著帽進，爵躍倒衣迎。", "感慨追平昔，驚呼問死生。", "殷勤一樽酒，閑健且同傾。"]'),
('369bf53c-4a73-48a4-aabb-6417b5ee9d2a','送鄒次賈歸臨川二首  其二','孫覿','宋','宋诗','song-poetry','','[]','徒步輕千里，重臨賁一邱。',48,'全唐诗/poet.song.85000.json','["徒步輕千里，重臨賁一邱。", "留歡不暖席，索去忽扁舟。", "惜别猶班草，傳聲可置郵。", "躊躇搔白首，獨上仲宣樓。"]'),
('3d6cfc43-49c0-4843-a5ca-1f83ab56a9f1','南唐門道上見桃二首  其一','孫覿','宋','宋诗','song-poetry','','[]','一逕青苔短短籬，小桃竹外兩三枝。',32,'全唐诗/poet.song.85000.json','["一逕青苔短短籬，小桃竹外兩三枝。", "殷勤待得黄昏月，正見斜紅臥酒卮。"]'),
('9dca918a-43ff-4a46-83e5-05f3c505d5c3','南唐門道上見桃二首  其二','孫覿','宋','宋诗','song-poetry','','[]','細紅如糝未全匀，洗雨梳風日日新。',32,'全唐诗/poet.song.85000.json','["細紅如糝未全匀，洗雨梳風日日新。", "前度劉郎在何處，故林空鎖一枝春。"]'),
('d039b558-2d63-4c21-a808-00b388bd5c59','惠楙吉水軒二首  其一','孫覿','宋','宋诗','song-poetry','','[]','演漾浮清樾，千凝漫綠莎。',48,'全唐诗/poet.song.85000.json','["演漾浮清樾，千凝漫綠莎。", "更無野鳥渡，自有窟蟾過。", "短綆飛蒼雪，長纓卷素波。", "會須號一噫，霹靂起龍梭。"]'),
('002d534d-5761-43ee-90ff-e692757b7ab0','惠楙吉水軒二首  其二','孫覿','宋','宋诗','song-poetry','','[]','練練迎朝霽，漻漻卷夜氛。',48,'全唐诗/poet.song.85000.json','["練練迎朝霽，漻漻卷夜氛。", "挽河半天落，貯月一瓢分。", "盪胸飽新授，洗耳浣昔聞。", "誰知望梅者，肺渴已如焚。"]'),
('b60b2d44-c120-4933-b4ac-d4e11893dce5','送刪定姪赴高安郡丞','孫覿','宋','宋诗','song-poetry','','[]','紛紛戲事擾真情，夢入槐宮一餉榮。',64,'全唐诗/poet.song.85000.json','["紛紛戲事擾真情，夢入槐宮一餉榮。", "莫向蝸廬分兩國，只將螘垤當専城。", "遨頭定自污三顧，紙尾何妨署一名。", "南望崆峒堪拄笏，白雲飛處眼偏明。"]'),
('179aebf7-1b47-41d8-b06b-6a954bed77dc','寄題楊元光黄巖清畏軒','孫覿','宋','宋诗','song-poetry','','[]','楊公相大曆，獨擅德爵尊。',96,'全唐诗/poet.song.85000.json','["楊公相大曆，獨擅德爵尊。", "清渭貫涇濁，寸膠定河渾。", "高名冠朝倫，流風被仍昆。", "悠然向千載，凜凜尚目存。", "官閑擁黄紬，臥聽衙集喧。", "蕭蕭鳧鷖行，重糈不到門。", "蝗虎不待驅，聞風自驚奔。", "所貴知我希，已及魚與豚。"]'),
('0acfbcfd-9e49-42cb-b75e-b5b33083f076','題致思庵二首  其一','孫覿','宋','宋诗','song-poetry','','[]','草逕衝泥滑，松門隱霧深。',48,'全唐诗/poet.song.85000.json','["草逕衝泥滑，松門隱霧深。", "潛魚寒上窟，宿鳥暝投林。", "風樹搖青冢，雲蘿倚碧潯。", "禪翁蒙一衲，寂寞海潮音。"]'),
('4a824c3b-e5fb-4e0d-b086-c1c83214e4eb','題致思庵二首  其二','孫覿','宋','宋诗','song-poetry','','[]','宿雨連村暗，春流隔隴分。',48,'全唐诗/poet.song.85000.json','["宿雨連村暗，春流隔隴分。", "檣烏吟外見，城角定中聞。", "石鼎涵蒼潤，銅爐湧翠芬。", "明朝南北路，相望兩孤雲。"]'),
('8e6da78c-fbf0-487c-90f2-aa02096b8252','焦山吸江亭二首  其一','孫覿','宋','宋诗','song-poetry','','[]','昔年攜客寄僧龕，敗屋疏籬一草庵。',32,'全唐诗/poet.song.85000.json','["昔年攜客寄僧龕，敗屋疏籬一草庵。", "白首重來看修竹，連山樓觀亦眈眈。"]'),
('2e7e2fe1-c379-4470-a366-54f0daef8010','焦山吸江亭二首  其二','孫覿','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬頃蒼茫一島孤，潭潭雲海現毘盧。',32,'全唐诗/poet.song.85000.json','["萬頃蒼茫一島孤，潭潭雲海現毘盧。", "問君吸盡西江水，中有曹谿一滴無。"]'),
('a33f427c-92e6-4008-8b32-49203ee6efde','再賦五至堂二首  其一','孫覿','宋','宋诗','song-poetry','','[]','猊坐諸天繞，龍龕百鬼神。',72,'全唐诗/poet.song.85000.json','["猊坐諸天繞，龍龕百鬼神。", "捫蘿穿窈窕，拄策上峥嶸。", "雨送秋聲入，風迎夜氣生。", "降肛壹鼉吼，撇烈兩島驚。", "獨詣超神界，真游夢化城。", "微吟更有味，琢雪鬭僧清。"]');
